fn main() {
    // Example data: jagged vector of vectors
    let data: Vec<Vec<usize>> = vec![
        vec![1, 2, 3],
        vec![4, 5],
        vec![6, 7, 8, 9],
        vec![10],
    ];

    println!("Original: {:?}", data);

    // Method 1: Nested parallel iterators (most elegant for coarse-grained parallelism)
    // This preserves structure naturally by mapping over each inner vector in parallel
    let result1: Vec<Vec<String>> = data
        .clone()
        .into_par_iter()
        .map(|inner| {
            inner
                .into_par_iter()
                .map(|x| format!("processed_{}", x))
                .collect()
        })
        .collect();

    println!("Method 1 (nested par_iter): {:?}", result1);

    // Method 2: Flatten -> Process -> Reshape (most efficient for fine-grained work)
    // Better when individual elements are expensive to process
    let result2 = process_flatten_reshape(data.clone());
    println!("Method 2 (flatten/reshape): {:?}", result2);

    // Method 3: In-place mutation (if you don't need to change the type)
    let mut data_mut = data.clone();
    data_mut
        .par_iter_mut()
        .for_each(|inner| {
            inner.par_iter_mut().for_each(|x| {
                *x = x.wrapping_mul(2); // example: double each value
            });
        });
    println!("Method 3 (in-place mutation): {:?}", data_mut);
}

/// Efficiently processes elements in parallel while preserving nested structure
/// Steps:
/// 1. Remember the sizes of inner vectors
/// 2. Flatten into one contiguous Vec
/// 3. Process in parallel with fine-grained parallelism
/// 4. Reshape back using the saved sizes
fn process_flatten_reshape(input: Vec<Vec<usize>>) -> Vec<Vec<String>> {
    // Save the structure (lengths of inner vectors)
    let lengths: Vec<usize> = input.iter().map(|v| v.len()).collect();

    // Flatten the nested vector into a single Vec
    // This is sequential but O(n) and cache-friendly
    let flat: Vec<usize> = input.into_iter().flatten().collect();

    // Process all elements in parallel with optimal load balancing
    let processed: Vec<String> = flat
        .into_par_iter()
        .map(|x| format!("processed_{}", x))
        .collect();

    // Reshape the flat vector back to the original nested structure
    reshape(processed, &lengths)
}

/// Reshapes a flat vector into a nested structure based on target lengths
fn reshape<T>(flat: Vec<T>, lengths: &[usize]) -> Vec<Vec<T>> {
    let mut result = Vec::with_capacity(lengths.len());
    let mut iter = flat.into_iter();

    for &len in lengths {
        let chunk: Vec<T> = iter.by_ref().take(len).collect();
        result.push(chunk);
    }

    result
}

