use std::fs;
use std::io;
use std::path::Path;

const FILE_PATH: &str = "output.json";

#[derive(Debug, Serialize, Deserialize)]
struct TodoItem {
    task: String,
    completed: bool,
}

/// Load existing items or return empty vec if file doesn't exist yet.
/// Handles empty files and missing files gracefully.
fn load_items() -> io::Result<Vec<TodoItem>> {
    if !Path::new(FILE_PATH).exists() {
        return Ok(Vec::new());
    }

    let content = fs::read_to_string(FILE_PATH)?;

    // Handle empty file case
    if content.trim().is_empty() {
        return Ok(Vec::new());
    }

    serde_json::from_str(&content)
        .map_err(|e| io::Error::new(io::ErrorKind::InvalidData, e))
}

/// Save the entire vector back to file.
/// This overwrites the file with the updated JSON array.
fn save_items(items: &[TodoItem]) -> io::Result<()> {
    let json = serde_json::to_string_pretty(items)
        .map_err(|e| io::Error::new(io::ErrorKind::InvalidData, e))?;
    fs::write(FILE_PATH, json)
}

/// Append a new item to the JSON file.
/// Works whether the file exists or not.
fn append_item(task: String) -> io::Result<()> {
    let mut items = load_items()?;
    items.push(TodoItem {
        task,
        completed: false,
    });
    save_items(&items)
}

fn main() -> io::Result<()> {
    // Display current items
    println!("Current todos:");
    let items = load_items()?;

    if items.is_empty() {
        println!("  (No items yet)");
    } else {
        for (i, item) in items.iter().enumerate() {
            let status = if item.completed { "[x]" } else { "[ ]" };
            println!("  {} {}: {}", status, i + 1, item.task);
        }
    }

    // Append a new item
    let new_task = format!("Task created at {:?}", std::time::SystemTime::now());
    println!("\nAppending: {}", new_task);
    append_item(new_task)?;

    println!("Successfully saved to {}", FILE_PATH);
    println!("Total items: {}", items.len() + 1);

    Ok(())
}"
}
