fn main() {
    // Define a custom operator: sqrt(x + 1)
    // Op::new takes: name, arity (number of arguments), and the function to execute
    let sqrt_plus_one = Op::new(
        "sqrt_plus_one",
        1, // This operator takes 1 argument
        Box::new(|args: &[f64]| {
            (args[0] + 1.0).sqrt()
        })
    );

    // Define another custom operator: x^2 + x (quadratic)
    let quadratic = Op::new(
        "quadratic",
        1,
        Box::new(|args: &[f64]| {
            let x = args[0];
            x * x + x
        })
    );

    // Set up the operation store with custom and built-in operators
    let store = vec![
        (NodeType::Vertex, vec![
            Op::add(), 
            Op::sub(), 
            Op::mul(),
            Op::div(),
            sqrt_plus_one,  // Our first custom operator
            quadratic,      // Our second custom operator
        ]),
        (NodeType::Leaf, vec![
            Op::var(0),         // Variable x (index 0)
            Op::const_val(1.0), // Constant 1.0
            Op::const_val(2.0), // Constant 2.0
        ]),
    ];

    // Generate sample data: target is sqrt(x + 1) * 2
    // We want the GP to discover this relationship
    let training_data: Vec<(Vec<f64>, f64)> = (0..20)
        .map(|i| {
            let x = i as f64 * 0.5;
            let y = (x + 1.0).sqrt() * 2.0; // target function
            (vec![x], y)
        })
        .collect();

    // Create the codex for tree-based GP
    // Parameters: operation store, min depth, max depth
    let codex = TreeCodex::new(store, 2, 5);

    // Create the evolutionary engine
    let mut engine = Engine::new(codex, Objective::minimize())
        .selector(TournamentSelector::new(4))
        .population_size(500)
        .fitness_fn(move |tree: &Tree| {
            // Calculate mean squared error
            let mut total_error = 0.0;
            for (inputs, expected) in &training_data {
                let output = tree.evaluate(inputs);
                let error = output - expected;
                total_error += error * error;
            }
            total_error / training_data.len() as f64
        });

    println!("Starting evolution with custom operators...");

    // Run evolution for 150 generations
    let result = engine.run(150);

    println!("\nEvolution complete!");
    println!("Best fitness (MSE): {:.6}", result.best_fitness());
    println!("Best solution (Lisp notation): {:?}", result.best());

    // Test the best solution on some values
    println!("\nTesting discovered equation:");
    let best_tree = result.best();
    for x in [0.0, 1.0, 4.0, 9.0] {
        let predicted = best_tree.evaluate(&[x]);
        let actual = (x + 1.0).sqrt() * 2.0;
        println!("  x={:.1}: predicted={:.4}, actual={:.4}, diff={:.4}", 
                 x, predicted, actual, (predicted - actual).abs());
    }
}
