use std::path::PathBuf;

fn deserialize_path_list<'de, D>(deserializer: D) -> Result<Vec<PathBuf>, D::Error>
where
    D: Deserializer<'de>,
{
    #[derive(Deserialize)]
    #[serde(untagged)]
    enum PathListInput {
        Direct(Vec<PathBuf>),
        Ref {
            #[serde(rename = "$ref")]
            reference: String,
        },
    }

    match PathListInput::deserialize(deserializer)? {
        PathListInput::Direct(paths) => Ok(paths),
        PathListInput::Ref { reference } => {
            // Parse reference format: "./a.json#/p_list"
            let (file_path, pointer) = reference
                .split_once('#')
                .ok_or_else(|| serde::de::Error::custom("Reference must contain '#' separator"))?;

            // Read the referenced file
            let content = std::fs::read_to_string(file_path)
                .map_err(|e| serde::de::Error::custom(format!("Failed to read '{}': {}", file_path, e)))?;

            // Parse as generic JSON value
            let value: serde_json::Value = serde_json::from_str(&content)
                .map_err(|e| serde::de::Error::custom(format!("Failed to parse '{}': {}", file_path, e)))?;

            // Navigate using JSON pointer (e.g., "/p_list")
            let target = value
                .pointer(pointer)
                .ok_or_else(|| serde::de::Error::custom(format!("JSON pointer '{}' not found in '{}'", pointer, file_path)))?;

            // Deserialize the target value into Vec<PathBuf>
            Vec::deserialize(target)
                .map_err(|e| serde::de::Error::custom(format!("Failed to deserialize referenced data: {}", e)))
        }
    }
}

