{
  "Cargo.toml": "[package]
name = "atomic-fetch-add-replacement"
version = "0.1.0"
edition = "2021"

[dependencies]
# For hosted testing with `cargo run`:
critical-section = { version = "1.2", features = ["std"] }

# For actual thumbv6m-none-eabi target (e.g., RP2040), use:
# [dependencies]
# critical-section = "1.2"
# 
# And add a critical section implementation, e.g.:
# cortex-m = { version = "0.7", features = ["critical-section-single-core"] }
# or for RP2040 dual-core:
# rp2040-hal = { version = "0.10", features = ["critical-section-impl"] }",
  "main.rs": "use std::sync::atomic::{AtomicUsize, Ordering};

struct ChannelManager {
    // On thumbv6m-none-eabi: use core::sync::atomic::AtomicUsize
    // (load/store available, but fetch_add is not)
    channel_index: AtomicUsize,
}

impl ChannelManager {
    fn new() -> Self {
        Self {
            channel_index: AtomicUsize::new(0),
        }
    }

    /// Replacement for atomic-polyfill::AtomicUsize::fetch_add(1, Ordering::Relaxed)
    fn fetch_add_channel(&self) -> usize {
        critical_section::with(|_| {
            // The correct Ordering is **Relaxed** (as used here).
            //
            // Why: critical_section::with() provides mutual exclusion by disabling 
            // interrupts (on single-core thumbv6m) or acquiring a spinlock (on 
            // RP2040's dual-core Cortex-M0+). This ensures the load-modify-store 
            // sequence executes atomically with respect to interrupts and other cores.
            //
            // Since no concurrent thread can observe the intermediate state between
            // load and store, and the critical section acts as a compiler fence/memory 
            // barrier on entry and exit, Ordering::Relaxed is both correct and optimal 
            // inside the closure. Using Acquire/Release/SeqCst would work but provides 
            // no additional safety and may generate unnecessary barrier instructions.
            let old_val = self.channel_index.load(Ordering::Relaxed);
            self.channel_index.store(old_val.wrapping_add(1), Ordering::Relaxed);
            old_val
        })
    }
}

fn main() {
    let manager = ChannelManager::new();

    // Test the atomic increment behavior
    let idx1 = manager.fetch_add_channel();
    let idx2 = manager.fetch_add_channel();
    let idx3 = manager.fetch_add_channel();

    println!("Channel indices: {}, {}, {}", idx1, idx2, idx3);
    assert_eq!(idx1, 0);
    assert_eq!(idx2, 1);
    assert_eq!(idx3, 2);

    println!("\nSuccess! Ordering::Relaxed is correct.");
    println!("The critical_section provides synchronization,");
    println!("making stronger orderings unnecessary inside.");
}"
}
