  "main.rs": "/// Tokenize a shell command string respecting single quotes.
/// 
/// Rules:
/// - Whitespace outside quotes separates tokens
/// - Characters inside single quotes (including whitespace) are preserved
/// - Quoted and unquoted sections can concatenate into a single token
/// - Empty quoted strings produce empty tokens
fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current = String::new();
    let mut in_single_quote = false;
    let mut in_word = false; // Tracks if we're currently building a token

    for c in input.chars() {
        match c {
            '\'' => {
                // Toggle quote state
                in_single_quote = !in_single_quote;
                // Quotes mark the beginning or continuation of a word,
                // even if the content inside is empty
                in_word = true;
            }
            c if c.is_whitespace() && !in_single_quote => {
                // Whitespace outside quotes ends the current token
                if in_word {
                    tokens.push(std::mem::take(&mut current));
                    in_word = false;
                }
            }
            _ => {
                // Regular character (or whitespace inside quotes)
                current.push(c);
                in_word = true;
            }
        }
    }

    // Push the final token if there is one
    if in_word {
        tokens.push(current);
    }

    tokens
}

fn main() {
    let test_cases = vec![
        " one  ' two  'three    four",
        "echo 'hello world'",
        "echo 'hello''world'",
        "echo '' empty",
        "  multiple   spaces  ",
    ];

    for input in test_cases {
        let tokens = tokenize(input);
        println!("Input: {:?}", input);
        println!("Tokens ({}):", tokens.len());
        for token in &tokens {
            println!("  `<{}>`", token);
        }
        println!();
