use serde::ser::{Serialize, SerializeStruct, Serializer};
use std::fmt;

// Data structures
struct A {
    x: usize,
    b: Vec<B>,
}

enum B {
    Integer(i64),
    Text(String),
}

// ========== Serialization ==========

impl Serialize for B {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        match self {
            B::Integer(n) => serializer.serialize_i64(*n),
            B::Text(s) => serializer.serialize_str(s),
        }
    }
}

impl Serialize for A {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        let mut state = serializer.serialize_struct("A", 2)?;
        state.serialize_field("x", &self.x)?;
        state.serialize_field("b", &self.b)?;
        state.end()
    }
}

// ========== Deserialization ==========

impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct BVisitor;

        impl<'de> Visitor<'de> for BVisitor {
            type Value = B;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("integer or string")
            }

            fn visit_i64<E>(self, value: i64) -> Result<Self::Value, E>
            where
                E: de::Error,
            {
                Ok(B::Integer(value))
            }

            fn visit_str<E>(self, value: &str) -> Result<Self::Value, E>
            where
                E: de::Error,
            {
                Ok(B::Text(value.to_owned()))
            }

            fn visit_string<E>(self, value: String) -> Result<Self::Value, E>
            where
                E: de::Error,
            {
                Ok(B::Text(value))
            }
        }

        deserializer.deserialize_any(BVisitor)
    }
}

impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct AVisitor;

        impl<'de> Visitor<'de> for AVisitor {
            type Value = A;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("struct A with fields x and b")
            }

            fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut x: Option<usize> = None;
                let mut b: Option<Vec<B>> = None;

                // Use String for keys to avoid lifetime issues with &str
                while let Some(key) = map.next_key::<String>()? {
                    match key.as_str() {
                        "x" => {
                            if x.is_some() {
                                return Err(de::Error::duplicate_field("x"));
                            }
                            x = Some(map.next_value()?);
                        }
                        "b" => {
                            if b.is_some() {
                                return Err(de::Error::duplicate_field("b"));
                            }
                            // Delegate to Vec<B>'s deserializer.
                            // This automatically uses B's custom deserializer for each element.
                            b = Some(map.next_value::<Vec<B>>()?);
                        }
                        _ => {
                            // Ignore unknown fields
                            map.next_value::<de::IgnoredAny>()?;
                        }
                    }
                }

                let x = x.ok_or_else(|| de::Error::missing_field("x"))?;
                let b = b.ok_or_else(|| de::Error::missing_field("b"))?;

                Ok(A { x, b })
            }
        }

        deserializer.deserialize_struct("A", &["x", "b"], AVisitor)
    }
}

