    /// 
    /// Phase 1: Read-only pass to identify all pairs satisfying criterion
    /// Phase 2: Mutable pass to update neighbor lists
    /// 
    /// This avoids unsafe pointers and allows modifying both elements of a pair.
    pub fn build_lists_safe(&mut self) {
        let n = self.get_nelems();
        if n == 0 {
            return;
        }

        // Phase 1: Compute pairs (i, j) where criterion is met
        // We exploit symmetry: only check i < j, then add both directions
        let mut pairs = Vec::new();
        for i in 0..n {
            for j in (i + 1)..n {
                if self.elems[i].criterion(&self.elems[j]) < self.cutoff {
                    pairs.push((i, j));
                }
