    /// 
    /// Uses temporary Mutex-wrapped neighbor lists to allow parallel updates
    /// without collecting pairs first. This avoids the O(edges) temporary storage
    /// but adds synchronization overhead per edge.
    pub fn build_lists_parallel_mutex(&mut self) {
        use std::sync::Mutex;

        let n = self.get_nelems();
        if n == 0 {
            return;
        }

        let cutoff = self.cutoff;

        // Create temporary thread-safe containers for neighbor lists
        let nb_lists: Vec<Mutex<Vec<usize>>> = (0..n).map(|_| Mutex::new(Vec::new())).collect();

