type Type = LocalBoxedObservableClone<'static, bool, Infallible>;

/// Builds an RS flip-flop feedback loop.
/// 
/// The circular dependency (Q depends on Q', Q' depends on Q) is handled
/// using `scan` to maintain state, avoiding the RefCell reentrancy panic
/// that occurs with direct circular subscriptions.
fn flipflop(s: Type, r: Type) -> (Type, Type) {
    // Combine S and R inputs into a stream of (S, R) tuples
    let state = s
        .combine_latest(r, |s, r| (s, r))
        // Scan maintains the flip-flop state (Q, Q_bar).
        // The closure receives the previous state and computes the next state,
        // effectively closing the feedback loop within the state function.
        // Seed with (false, true) representing the Reset state (Q=0, Q'=1).
        .scan((false, true), |(q, q_bar), (s, r)| {
            // NAND logic: !(a && b)
            // Q = NAND(S, Q')
            // Q' = NAND(R, Q)
            let new_q = !(s && *q_bar);
            let new_q_bar = !(r && *q);

