const FPS: u64 = 60;
const FRAME_TIME: Duration = Duration::from_nanos(1_000_000_000 / FPS);
const BUFFER_COUNT: usize = 3; // Triple buffer to avoid tearing

struct SharedBuffer {
    name: String,
    _file: File,
    mmap: memmap2::MmapMut,
}

impl SharedBuffer {
    fn new(index: usize, size: usize) -> Result<Self> {
        // Shared memory names must start with / and contain no other slashes
        let name = format!("/kitty_anim_{}_{}", std::process::id(), index);

        // Create shared memory object
        let fd = shm_open(
            &name,
            OFlag::O_CREAT | OFlag::O_RDWR,
            Mode::S_IRUSR | Mode::S_IWUSR,
        )?;

        // Set size
        ftruncate(&fd, size as i64)?;

        // Convert to File for memmap2
        let file = unsafe { File::from_raw_fd(fd.into_raw_fd()) };

        // Memory map it for fast access
        let mmap = unsafe {
            MmapOptions::new()
                .len(size)
                .map_mut(&file)?
        };

        Ok(Self {
            name,
            _file: file,
            mmap,
        })
    }

    fn as_mut_slice(&mut self) -> &mut [u8] {
        &mut self.mmap
    }
}

impl Drop for SharedBuffer {
    fn drop(&mut self) {
        // Remove the shared memory object from the system
        let _ = shm_unlink(&self.name);
    }
}

struct BufferPool {
    buffers: Vec<SharedBuffer>,
    current: usize,
}

impl BufferPool {
    fn new(size: usize) -> Result<Self> {
        let mut buffers = Vec::with_capacity(BUFFER_COUNT);
        for i in 0..BUFFER_COUNT {
            buffers.push(SharedBuffer::new(i, size)?);
        }
        Ok(Self {
            buffers,
            current: 0,
        })
    }

    // Returns the next buffer in the rotation (0 -> 1 -> 2 -> 0)
    fn get_next(&mut self) -> &mut SharedBuffer {
        let buf = &mut self.buffers[self.current];
        self.current = (self.current + 1) % BUFFER_COUNT;
        buf
    }
}

fn main() -> Result<()> {
    // Setup Ctrl+C handler for clean exit
    let running = Arc::new(AtomicBool::new(true));
    let r = running.clone();
    ctrlc::set_handler(move || {
        r.store(false, Ordering::SeqCst);
