    let (width, height) = terminal_size_pixels().unwrap_or((800, 600));
    let (width, height) = (width as usize, height as usize);
    let buffer_size = width * height * 3; // RGB24 = 3 bytes per pixel

    if buffer_size == 0 {
        anyhow::bail!("Terminal size is zero");
    }

    // Setup terminal - raw mode to prevent input interference
    let mut stdout = stdout().into_raw_mode()?;

    // Clear screen, hide cursor, move to home position
    write!(stdout, "\x1b[2J\x1b[H\x1b[?25l")?;
    stdout.flush()?;

    // Initialize triple buffer pool
    let mut pool = BufferPool::new(buffer_size)?;
    let mut frame_count: u64 = 0;
    let pi = std::f32::consts::PI;

    while running.load(Ordering::SeqCst) {
        let frame_start = Instant::now();

        // Get the next buffer (rotates through 3 buffers)
        let buffer = pool.get_next();
        let data = buffer.as_mut_slice();

