/// In a Tauri app, you would store `Arc<Agent>` in your `AppState`.
pub struct Agent {
    /// Write-end of the PTY. Protected by Mutex because File::write takes &mut self.
    /// Contention here is minimal (only during active writes), never blocked by reads.
