#[async_trait]
impl ProxyLifecycle for ProxyCtx {
    async fn request_filter(&self) -> Result<(), ()> {
        // REHYDRATION PATTERN:
        // Use .instrument(span) to enter the parent span context for this async block.
        // This makes `request_span` the current span, so any new spans created 
        // inside will automatically have it as their parent.
        async {
            // Now we're inside the request span context
            let stage_span = info_span!("stage_request_filter");
            let _enter = stage_span.enter();

            info!("Executing request filter logic");
            sleep(Duration::from_millis(50)).await;
            info!("Request filter complete");

            Ok(())
        }
        .instrument(self.request_span.clone()) // <-- Rehydrate the parent span here
        .await
    }

    async fn upstream_peer(&self) -> Result<(), ()> {
        // Alternative pattern: store span, then instrument
        let parent = self.request_span.clone();

        async move {
            let stage_span = info_span!("stage_upstream");
            let _enter = stage_span.enter();

            info!("Connecting to upstream");
            sleep(Duration::from_millis(100)).await;
            info!("Upstream connection established");

            Ok(())
        }
        .instrument(parent) // <-- Span moves into the instrumented future
        .await
    }

    async fn response_filter(&self) -> Result<(), ()> {
        async {
            let stage_span = info_span!("stage_response");
            let _enter = stage_span.enter();

            info!("Processing response");
            Ok(())
        }
        .instrument(self.request_span.clone())
        .await
    }
