/// Custom asset reader that lazily loads individual files from ZIP archives.
/// Supports paths like "archive.zip/internal/path.txt" - only the specific
/// entry is decompressed and returned, not the entire archive.
pub struct LazyZipAssetReader {
    /// Root directory for resolving relative archive paths (typically "assets")
    asset_root: PathBuf,
}

impl LazyZipAssetReader {
    pub fn new(asset_root: PathBuf) -> Self {
        Self { asset_root }
    }

    /// Splits a path like "textures.zip/level1/wall.png" into:
    /// ("assets/textures.zip", "level1/wall.png")
    fn split_path(&self, path: &Path) -> Option<(PathBuf, String)> {
        let path_str = path.to_string_lossy();

        // Support both .zip and .wad extensions (case insensitive)
        let lower = path_str.to_lowercase();
        let ext_idx = lower.find(".zip/").or_else(|| lower.find(".wad/"))?;

        let archive_name = &path_str[..ext_idx + 4];
        let internal_path = path_str[ext_idx + 5..].to_string();

        let archive_path = self.asset_root.join(archive_name);
        Some((archive_path, internal_path))
    }
}

impl AssetReader for LazyZipAssetReader {
    async fn read<'a>(&'a self, path: &'a Path) -> Result<impl Reader + 'a, AssetReaderError> {
        if let Some((archive_path, internal_path)) = self.split_path(path) {
            // Open the archive fresh each time. This avoids Sync issues with ZipArchive
            // and ensures we don't keep file handles open longer than necessary.
            let file = std::fs::File::open(&archive_path)
                .map_err(|e| AssetReaderError::Io(Arc::new(e)))?;

            let mut archive = ZipArchive::new(file)
                .map_err(|e| AssetReaderError::Io(Arc::new(std::io::Error::new(
                    std::io::ErrorKind::InvalidData,
                    format!("Failed to open archive: {}", e)
                ))))?;

            // Read only the specific entry requested (lazy loading)
            let mut entry = archive.by_name(&internal_path)
                .map_err(|e| AssetReaderError::Io(Arc::new(std::io::Error::new(
                    std::io::ErrorKind::NotFound,
                    format!("Entry '{}' not found in archive: {}", internal_path, e)
                ))))?;

            let mut bytes = Vec::new();
            entry.read_to_end(&mut bytes)
                .map_err(|e| AssetReaderError::Io(Arc::new(e)))?;

            // VecReader implements AsyncReadSeek and owns the bytes via Cow
            Ok(VecReader::new(bytes))
        } else {
            Err(AssetReaderError::NotFound(path.to_path_buf()))
        }
    }

    async fn read_meta<'a>(&'a self, path: &'a Path) -> Result<impl Reader + 'a, AssetReaderError> {
        // Metadata files inside zips are not supported in this simple example
        Err(AssetReaderError::NotFound(path.to_path_buf()))
    }

