    pub struct Boo(pub i32);

    impl Rest for Foo {
        fn method1(&self) -> String { format!("Foo:{}", self.0) }
        fn method2(&self) -> i32 { self.0.len() as i32 }
        fn method3(&self) -> bool { true }
    }

    impl Rest for Boo {
        fn method1(&self) -> String { format!("Boo:{}", self.0) }
        fn method2(&self) -> i32 { self.0 * 2 }
        fn method3(&self) -> bool { false }
    }
