                        Item::Boo(inner) => inner.method1(),
                    }
                }

                fn method2(&self) -> i32 {
                    match self {
                        Item::Foo(inner) => inner.method2(),
                        Item::Boo(inner) => inner.method2(),
                    }
                }

                fn method3(&self) -> bool {
                    match self {
                        Item::Foo(inner) => inner.method3(),
                        Item::Boo(inner) => inner.method3(),
