/// Create a Use item from a UseTree by parsing
fn make_use_item(tree: &UseTree) -> Use {
    let text = format!("use {};", tree);
    let file = SourceFile::parse(&text).ok().unwrap();
    file.syntax().descendants().find_map(Use::cast).unwrap()
