/// Transform a UseTree and its children, returning one or more new UseTrees.
/// The `prefix` argument tracks the accumulated path from parent nodes.
fn transform_use_tree(tree: &UseTree, prefix: &str) -> Vec<UseTree> {
    let path_str = tree.path().map(|p| p.to_string()).unwrap_or_default();

    // Compute the full path up to this node
    let full_path = if prefix.is_empty() {
        path_str.clone()
    } else if path_str.is_empty() {
        prefix.to_string()
    } else {
        format!("{}::{}", prefix, path_str)
    };

    // Check if this path starts with vexide::devices
    if full_path.starts_with("vexide::devices") {
        let new_prefix = full_path.replacen("vexide::devices", "vexide", 1);

        // Handle glob imports: vexide::devices::* -> vexide::*
        if tree.star_token().is_some() {
            let new_path = make::path_from_str(&new_prefix).expect("valid path");
            return vec![make::use_tree(new_path, None, true)];
        }

        // Handle nested lists: vexide::devices::{smart, adi} -> vexide::{smart, adi}
        if let Some(list) = tree.use_tree_list() {
            let mut new_children = Vec::new();
            for child in list.use_trees() {
                // Recursively process children with the new prefix
                let transformed = transform_use_tree(&child, &new_prefix);
                new_children.extend(transformed);
            }

            if new_children.is_empty() {
                return vec![];
            }

            let new_path = make::path_from_str(&new_prefix).expect("valid path");
            let new_list = make::use_tree_list(new_children);
            return vec![make::use_tree(new_path, Some(new_list), false)];
        }

        // Handle simple paths: vexide::devices or vexide::devices::Motor
        // If we're importing the parent module itself (new_prefix == prefix), 
        // use `self` keyword (e.g., vexide::devices inside vexide::{devices, fs})
        if new_prefix == prefix && !prefix.is_empty() {
            let self_path = make::path_from_str("self").expect("valid path");
            return vec![make::use_tree(self_path, None, false)];
        }

        let new_path = make::path_from_str(&new_prefix).expect("valid path");
        return vec![make::use_tree(new_path, None, false)];
    }

    // Not our target path, but recurse into children to check for nested targets
    if let Some(list) = tree.use_tree_list() {
        let mut new_children = Vec::new();
        let mut changed = false;

        for child in list.use_trees() {
            let transformed = transform_use_tree(&child, &full_path);

            // Check if transformation actually changed the child
            if transformed.len() != 1 || transformed[0].to_string() != child.to_string() {
                changed = true;
            }

            new_children.extend(transformed);
        }

        // If no changes, return original tree
        if !changed {
            return vec![tree.clone()];
        }

        // If all children were removed, return empty
        if new_children.is_empty() {
            return vec![];
        }

        // Rebuild the tree with transformed children
        // If the current node has no path (e.g., root of `use {a, b}`), 
        // we just return the children (hoist them)
        if tree.path().is_none() {
            return new_children;
        }

        let path = tree.path().expect("path exists");
        let new_list = make::use_tree_list(new_children);
        return vec![make::use_tree(path, Some(new_list), false)];
    }

    // Leaf node, no changes needed
    vec![tree.clone()]
}
