fn manual_parse_inspection(bytes: &[u8]) {
    use der::{Any, Header, Length};

    println!("\n=== Manual ASN.1 Inspection ===");

    // Parse the outer SEQUENCE header
    let mut pos = 0usize;

    // Check for SEQUENCE tag (0x30)
    if bytes.is_empty() || bytes[0] != 0x30 {
        println!("Expected SEQUENCE (0x30) at start, found 0x{:02x}", bytes[0]);
        return;
