    pos += 1;

    // Parse length
    let (length, bytes_consumed) = parse_length(&bytes[pos..]);
    pos += bytes_consumed;

    println!("SignedData SEQUENCE length: {} bytes (consumed {} header bytes)", length, pos);

    // Try to locate version field (should be INTEGER 1)
    if pos < bytes.len() && bytes[pos] == 0x02 {
        let version_len = bytes[pos + 1] as usize;
        println!("Version field at offset {}: INTEGER length {}", pos, version_len);
        pos += 2 + version_len;
    }

    // Next should be SET of digest algorithms
    if pos < bytes.len() {
        println!("Next byte at offset {}: 0x{:02x} (expected SET 0x31)", pos, bytes[pos]);
        if bytes[pos] == 0x31 {
            let (set_len, consumed) = parse_length(&bytes[pos+1..]);
            println!("  SET length: {} bytes", set_len);
            pos += 1 + consumed + set_len;
        }
    }

    // Next should be SEQUENCE for EncapsulatedContentInfo
    if pos < bytes.len() {
        println!("Next byte at offset {}: 0x{:02x} (expected SEQUENCE 0x30)", pos, bytes[pos]);
        if bytes[pos] == 0x30 {
            let (seq_len, consumed) = parse_length(&bytes[pos+1..]);
            println!("  SEQUENCE length: {} bytes (EncapContentInfo)", seq_len);

            // Check if position 129 falls within this area
            if pos <= 129 && 129 < pos + 1 + consumed + seq_len {
                println!("  *** Position 129 is within this EncapContentInfo ***");
            }
        }
    }
