fn parse_length(bytes: &[u8]) -> (usize, usize) {
    if bytes.is_empty() {
        return (0, 0);
    }

    let first = bytes[0];
    if first & 0x80 == 0 {
        // Short form
        (first as usize, 1)
    } else {
        // Long form
        let num_bytes = (first & 0x7F) as usize;
        let mut len = 0usize;
        for i in 0..num_bytes {
            if i + 1 < bytes.len() {
                len = (len << 8) | (bytes[i + 1] as usize);
            }
        }
        (len, 1 + num_bytes)
    }
}

