  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll, RawWaker, RawWakerVTable, Waker};

/// Result of trying to poll a future synchronously
pub enum TryPollResult<X> {
    /// The future completed immediately with this value
    Ready(X),
    /// The future is pending and has been spawned as a Tokio task
    Pending(tokio::task::JoinHandle<X>),
}

/// Attempts to poll a future once synchronously.
/// 
/// If the future is ready, returns the value immediately.
/// If the future is pending, spawns it as a Tokio task and returns the join handle.
/// 
/// # Requirements
/// 
/// The future must be `Send + 'static` to be spawnable on the Tokio runtime.
pub fn try_poll<X, F>(future: F) -> TryPollResult<X>
where
    F: Future<Output = X> + Send + 'static,
    X: Send + 'static,
{
    // Create a no-op waker since we're only polling once synchronously
    let waker = noop_waker();
    let mut context = Context::from_waker(&waker);

    // Pin the future so we can poll it
    let mut future = Box::pin(future);

    // Attempt to poll the future
    match future.as_mut().poll(&mut context) {
        Poll::Ready(value) => TryPollResult::Ready(value),
        Poll::Pending => {
            // Future is not ready, spawn it on the Tokio runtime
            let handle = tokio::spawn(future);
            TryPollResult::Pending(handle)
        }
    }
}

/// Creates a no-op waker for synchronous polling.
/// 
/// This waker does nothing when woken, which is fine for our use case
