            Severity::LOG_EMERG => self.logger.emerg(message),
            Severity::LOG_ALERT => self.logger.alert(message),
            Severity::LOG_CRIT => self.logger.crit(message),
            Severity::LOG_ERR => self.logger.err(message),
            Severity::LOG_WARNING => self.logger.warning(message),
            Severity::LOG_NOTICE => self.logger.notice(message),
            Severity::LOG_INFO => self.logger.info(message),
            Severity::LOG_DEBUG => self.logger.debug(message),
        };

        // Centralized error handling - no need to repeat .expect() everywhere
        if let Err(e) = result {
            eprintln!("Syslog error: {}", e);
        }
    }

    pub fn info(&mut self, msg: &str) {
        self.log(Severity::LOG_INFO, msg);
    }

    pub fn warning(&mut self, msg: &str) {
        self.log(Severity::LOG_WARNING, msg);
    }

    pub fn err(&mut self, msg: &str) {
        self.log(Severity::LOG_ERR, msg);
    }
}

/// Log info with automatic file and line number (like C++ __FILE__ and __LINE__)
#[macro_export]
macro_rules! log_info {
    ($logger:expr, $($arg:tt)*) => {{
        let logger = &mut $logger;
        let file = file!();
        let line = line!();
        let msg = format!($($arg)*);
        logger.info(&format!("[{}:{}] {}", file, line, msg))
    }};
}

#[macro_export]
macro_rules! log_warning {
    ($logger:expr, $($arg:tt)*) => {{
        let logger = &mut $logger;
        let file = file!();
        let line = line!();
        let msg = format!($($arg)*);
        logger.warning(&format!("[{}:{}] {}", file, line, msg))
    }};
}

#[macro_export]
macro_rules! log_error {
    ($logger:expr, $($arg:tt)*) => {{
        let logger = &mut $logger;
        let file = file!();
        let line = line!();
        let msg = format!($($arg)*);
        logger.err(&format!("[{}:{}] {}", file, line, msg))
    }};
}

fn main() {
    let mut logger = SyslogClient::new("syslog_test")
        .expect("Could not connect to syslog");

    // Using macros: no .expect() repetition, automatic file:line info
    let sum1 = 2 + 3;
    log_info!(logger, "Sum 1: 2 + 3 = {}", sum1);

    let sum2 = 10 - 4;
    log_warning!(logger, "Sum 2: 10 - 4 = {}", sum2);

    let sum3 = 6 * 7;
    log_error!(logger, "Sum 3: 6 * 7 = {}", sum3);

    // Direct method calls: still no .expect() needed
    logger.info("Direct info without file/line info");
    logger.warning("Direct warning");
    logger.err("Direct error");
}
