    let coordinator = tokio::spawn(async move {
        let mut count = 0;

        while let Some(raw_json) = rx.recv().await {
            // Wrap in Arc for shared ownership (cheap, just ref counting)
            let arc_storage = Arc::new(raw_json);

            // Build self-referential struct: deserialization happens ONCE here
            let bundle = DataBundleBuilder {
                storage: arc_storage,
                parsed_builder: |s: &String| {
                    // This deserializes into &str slices pointing into the Arc<String>
                    serde_json::from_str(s).expect("valid json")
                },
            }.build();

            // Pass across tokio::spawn without cloning the deserialized content
            // The bundle is 'static because it owns all its data via Arc
            tokio::spawn(async move {
                // Access the borrowed data safely through the generated accessor
                bundle.with_parsed(|my_data| {
                    println!(
                        "Worker task processing: data='{}', more_data='{}' (thread: {:?})",
                        my_data.data,
                        my_data.more_data,
                        std::thread::current().id()
