  "main.rs": "use std::collections::HashMap;
use serde::{Serialize, Deserialize};
use serde_json::Value;

// ============================================================================
// Notion API Types
// ============================================================================

#[derive(Debug, Clone)]
enum PropertyValue {
    Title(Vec<RichTextObject>),
    Url(String),
    MultiSelect(Vec<SelectObject>),
}

#[derive(Debug, Clone)]
struct RichTextObject {
    annotations: Option<()>,
    data_type: Option<RichTextType>,
    equation: Option<()>,
    mention: Option<()>,
    plain_text: Option<String>,
    href: Option<String>,
    text: TextObject,
}

#[derive(Debug, Clone)]
enum RichTextType {
    Text,
}

#[derive(Debug, Clone)]
struct TextObject {
    content: String,
    link: Option<String>,
}

#[derive(Debug, Clone)]
struct SelectObject {
    id: Option<String>,
    color: Option<String>,
    name: String,
}

// ============================================================================
// Conversion Trait
// ============================================================================

pub trait IntoNotionOption {
    fn into_notion_option(self, prop_type: &str) -> Option<PropertyValue>;
}

impl IntoNotionOption for String {
    fn into_notion_option(self, prop_type: &str) -> Option<PropertyValue> {
        match prop_type {
            "title" => Some(PropertyValue::Title(vec![
                RichTextObject {
                    annotations: None,
                    data_type: Some(RichTextType::Text),
                    equation: None,
                    mention: None,
                    plain_text: None,
                    href: None,
                    text: TextObject {
                        content: self,
                        link: None,
                    }
                }
            ])),
            "url" => Some(PropertyValue::Url(self)),
            _ => panic!("Unsupported type '{}' for String field", prop_type),
        }
    }
}

impl<T: ToString> IntoNotionOption for Vec<T> {
    fn into_notion_option(self, prop_type: &str) -> Option<PropertyValue> {
        match prop_type {
            "multi_select" | "MultiSelect" => Some(PropertyValue::MultiSelect(
                self.into_iter().map(|item| SelectObject {
                    id: None,
                    color: None,
                    name: item.to_string(),
                }).collect()
            )),
            _ => panic!("Unsupported type '{}' for Vec field", prop_type),
        }
    }
}

impl<T: IntoNotionOption> IntoNotionOption for Option<T> {
    fn into_notion_option(self, prop_type: &str) -> Option<PropertyValue> {
        self.and_then(|v| v.into_notion_option(prop_type))
    }
}

// ============================================================================
// Macro for Struct Definition and Conversion
// ============================================================================

macro_rules! notion_properties {
    (
        $(#[$struct_meta:meta])*
        struct $struct_name:ident {
            $(
                $(#[$field_meta:meta])*
                #[notion_property(type = $type:tt, name = $name:expr)]
                $vis:vis $field:ident: $ty:ty,
            )*
        }
    ) => {
        $(#[$struct_meta])*
        pub struct $struct_name {
            $($(#[$field_meta])* $vis $field: $ty,)*
        }

        impl $struct_name {
            pub fn into_properties(self) -> HashMap<String, PropertyValue> {
                let mut map = HashMap::new();
                $(
                    if let Some(value) = crate::IntoNotionOption::into_notion_option(self.$field, $type) {
                        map.insert($name.to_string(), value);
                    }
                )*
                map
            }
        }
    };
}

// ============================================================================
// Example Usage
// ============================================================================

notion_properties! {
    #[derive(Debug, Clone, Serialize, Deserialize)]
    struct MyUnit {
        #[notion_property(type = "title", name = "Name")]
        pub name: String,

        #[notion_property(type = "url", name = "Icon url")]
        pub icon_url: Option<String>,

        #[notion_property(type = "MultiSelect", name = "Roles")]
        pub categories: Option<Vec<Value>>,
    }
}

fn main() {
    // Example 1: All fields populated
    let unit = MyUnit {
        name: "My Notion Page".to_string(),
        icon_url: Some("https://example.com/icon.png".to_string()),
        categories: Some(vec![
            serde_json::json!("Admin"),
            serde_json::json!("Editor"),
        ]),
    };

    println!("=== Example 1: All fields ===");
    let properties = unit.into_properties();
    for (key, value) in &properties {
        println!("{}: {:?}", key, value);
    }

    // Example 2: Optional fields are None
    let unit2 = MyUnit {
        name: "Minimal Page".to_string(),
        icon_url: None,
        categories: None,
    };

    println!("\n=== Example 2: Optional fields empty ===");
    let properties2 = unit2.into_properties();
    for (key, value) in &properties2 {
        println!("{}: {:?}", key, value);
    }

    // Demonstrate it matches the expected HashMap type
    let _: HashMap<String, PropertyValue> = properties;
    println!("\nConversion successful! HashMap<String, PropertyValue> created.");
}
"
}
