use tracing::{debug, error, info, trace, warn};
use tracing_subscriber::filter;
use tracing_subscriber::layer::SubscriberExt;
use tracing_subscriber::reload;
use tracing_subscriber::util::SubscriberInitExt;
use tracing_subscriber::Registry;

// Type alias for the complex handle type to make it readable
// This represents a fmt::Layer wrapped with a LevelFilter, which is what we reload
type FilteredFmtLayer = tracing_subscriber::filter::Filtered<
    tracing_subscriber::fmt::Layer<Registry>,
    filter::LevelFilter,
    Registry,
>;

// Global handles to modify filters at runtime
// We use Option because we need to initialize them after creating the layers
static STDOUT_HANDLE: Mutex<Option<reload::Handle<FilteredFmtLayer, Registry>>> =
    Mutex::new(None);
static FILE_HANDLE: Mutex<Option<reload::Handle<FilteredFmtLayer, Registry>>> = Mutex::new(None);

fn main() {
