        .compact()
        .with_ansi(true)
        .with_writer(std::io::stdout);
    let stdout_filtered = stdout_layer.with_filter(filter::LevelFilter::INFO);
    let (stdout_reload_layer, stdout_handle) = reload::Layer::new(stdout_filtered);

    // Create file layer with initial INFO filter
    let file_layer = tracing_subscriber::fmt::layer()
        .with_ansi(false)
        .with_writer(Arc::new(file));
    let file_filtered = file_layer.with_filter(filter::LevelFilter::INFO);
    let (file_reload_layer, file_handle) = reload::Layer::new(file_filtered);

    // Store handles in global statics so we can modify them later
    *STDOUT_HANDLE.lock().unwrap() = Some(stdout_handle);
    *FILE_HANDLE.lock().unwrap() = Some(file_handle);

    // Initialize the subscriber with both reloadable layers
    tracing_subscriber::registry()
        .with(stdout_reload_layer)
        .with(file_reload_layer)
        .init();

