/// Processes a nested vector in parallel while preserving structure using flatten/reshape.
/// 
/// Strategy:
/// 1. Save the lengths of each inner vector to reconstruct the structure later
/// 2. Flatten into a single vector for efficient parallel processing (better load balancing)
/// 3. Apply function in parallel using rayon
/// 4. Reconstruct the nested structure using the saved lengths
fn parallel_flatten_process<F, T>(nested: Vec<Vec<usize>>, f: F) -> Vec<Vec<T>>
where
    F: Fn(usize) -> T + Sync + Send,
    T: Send,
{
    // Save the lengths of inner vectors
    let lengths: Vec<usize> = nested.iter().map(|v| v.len()).collect();

    // Flatten: Vec<Vec<usize>> -> Vec<usize>
    let flat: Vec<usize> = nested.into_iter().flatten().collect();

    // Process in parallel: Vec<usize> -> Vec<T>
    let processed: Vec<T> = flat.into_par_iter()
        .map(f)
        .collect();

    // Reshape back using the saved lengths
    // Using .take() moves elements without cloning
    let mut result = Vec::with_capacity(lengths.len());
    let mut processed = processed.into_iter();

    for len in lengths {
        let chunk: Vec<T> = processed.by_ref().take(len).collect();
        result.push(chunk);
    }

    result
}

/// Alternative: Nested parallel iteration (simpler, good when outer vec has many elements)
fn parallel_nested_process<F, T>(nested: Vec<Vec<usize>>, f: F) -> Vec<Vec<T>>
where
    F: Fn(usize) -> T + Sync + Send,
    T: Send,
{
    nested.into_par_iter()
        .map(|inner| {
            inner.into_par_iter().map(&f).collect()
        })
        .collect()
}

fn main() {
    // Example data with uneven sizes (the challenging case)
    let data: Vec<Vec<usize>> = vec![
        vec![1, 2, 3],
        vec![4, 5],
        vec![6, 7, 8, 9, 10],
        vec![],           // empty inner vec
        vec![11],         // single element
        vec![12, 13, 14, 15, 16, 17, 18],
    ];

    println!("Original: {:?}", data);
    println!("Original structure lengths: {:?}", data.iter().map(|v| v.len()).collect::<Vec<_>>());

    // Example: Convert usize to String with some "work"
    let result = parallel_flatten_process(data.clone(), |x| {
        // Simulate CPU work
        std::thread::sleep(std::time::Duration::from_micros(100));
        format!("processed_{}", x)
    });

    println!("\nResult (flatten approach): {:?}", result);
    println!("Result structure lengths: {:?}", result.iter().map(|v| v.len()).collect::<Vec<_>>());

    // Verify structure is preserved
    let orig_lens: Vec<usize> = data.iter().map(|v| v.len()).collect();
    let res_lens: Vec<usize> = result.iter().map(|v| v.len()).collect();
    assert_eq!(orig_lens, res_lens, "Structure preservation failed!");

    // Alternative approach demonstration
    let result2 = parallel_nested_process(data.clone(), |x| x * 2);
    println!("\nResult (nested approach): {:?}", result2);

    println!("\n✓ Success! Nested structure preserved in both approaches.");
}"
