//! 
//! Platform: thumbv6m-none-eabi (e.g., RP2040 Cortex-M0+)
//! 
//! Explanation of Ordering:
//! - Inside critical_section::with, we use Ordering::Relaxed (or regular non-atomic ops)
//! - The critical_section itself provides the necessary memory barriers:
//!   * Acquire semantics on entry (ensures we see the latest value from other cores/threads)
//!   * Release semantics on exit (ensures our store is visible to other cores/threads)
//! - Therefore, Relaxed is correct and sufficient inside the critical section

use std::cell::UnsafeCell;
use std::sync::atomic::Ordering;

/// AtomicUsize implemented using critical-section for thumbv6m targets
/// 
/// This replaces atomic-polyfill::AtomicUsize when moving to critical-section based atomics.
pub struct CriticalSectionAtomicUsize {
    value: UnsafeCell<usize>,
}

// Safety: UnsafeCell is not Sync by default, but we implement Sync here because
// all access is protected by critical_section, ensuring thread-safety on multi-core
// systems like RP2040.
unsafe impl Sync for CriticalSectionAtomicUsize {}

impl CriticalSectionAtomicUsize {
    pub const fn new(val: usize) -> Self {
        Self {
            value: UnsafeCell::new(val),
        }
    }

    /// Atomically adds to the current value, returning the previous value.
    /// 
    /// # Arguments
    /// * `val` - The value to add
    /// * `_ordering` - The ordering (ignored internally because critical-section provides 
    ///                 the necessary guarantees, but kept for API compatibility)
    /// 
    /// # Ordering Notes
    /// We ignore the ordering parameter inside because critical_section::with provides:
    /// 1. Mutual exclusion (no other thread can access during the operation)
    /// 2. Memory barriers on entry/exit
    /// 
    /// This matches the semantics of fetch_add with any ordering, though technically
    /// the critical-section provides SeqCst-level synchronization.
    pub fn fetch_add(&self, val: usize, _ordering: Ordering) -> usize {
        critical_section::with(|_| {
            // SAFETY: We are inside a critical section, so we have exclusive access
            // to the value. No other core or thread can access it simultaneously.
            let old_val = unsafe { *self.value.get() };

            // Use wrapping_add to match standard AtomicUsize behavior
            unsafe { *self.value.get() = old_val.wrapping_add(val) };

            old_val
        })
    }

    /// Load the current value
    pub fn load(&self, _ordering: Ordering) -> usize {
        critical_section::with(|_| unsafe { *self.value.get() })
    }

    /// Store a new value
    pub fn store(&self, val: usize, _ordering: Ordering) {
        critical_section::with(|_| unsafe { *self.value.get() = val });
    }
}

