    Cmd, ConditionalEventHandler, Config, Editor, Event, EventContext, EventHandler,
    KeyEvent, Modifiers, Movement, RepeatCount,
};
use rustyline::history::DefaultHistory;
use rustyline::keyboard::KeyCode;

struct MyEventHandler {
    insert: String,
}

impl MyEventHandler {
    fn new(insert: char) -> Self {
        Self {
            insert: insert.to_string(),
        }
    }
}

impl ConditionalEventHandler for MyEventHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext<'_>,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();
        let line = &line[..pos];

        // Find the last non-whitespace character
        if let Some(index) = line.rfind(|c: char| !c.is_whitespace()) {
            let segment = &line[index..];
            let char_count = segment.chars().count();

            // If char_count > 1, there is whitespace after the last non-whitespace char
            if char_count > 1 {
                let last_char = segment.chars().next()?;
                // Replace the last char + all whitespace with: last char + our insert
                // This effectively deletes the whitespace and inserts our char after the word,
                // leaving the cursor positioned after the inserted character
                let replacement = format!("{}{}", last_char, self.insert);
                return Some(Cmd::Replace(
                    Movement::BackwardChar(char_count),
                    Some(replacement),
                ));
            }
        }
        None
    }
}

fn bind_handler(editor: &mut Editor<(), DefaultHistory>, key: char) {
    let event = KeyEvent::new(KeyCode::Char(key), Modifiers::NONE);
    let handler = MyEventHandler::new(key);
    let handler = EventHandler::Conditional(Box::new(handler));
    editor.bind_sequence(event, handler);
}

fn main() -> rustyline::Result<()> {
