    "https://www.example.com",
    "http://localhost:3000",
    "http://127.0.0.1:3000",
];

/// Middleware that checks Origin header for WebSocket upgrade requests.
/// Apply this to routes that should be protected.
async fn websocket_origin_check(
    request: Request<Body>,
    next: Next,
) -> Response {
    // Check if this is a WebSocket upgrade request
    let is_websocket = request
        .headers()
        .get(header::UPGRADE)
        .and_then(|val| val.to_str().ok())
        .map(|val| val.to_ascii_lowercase() == "websocket")
        .unwrap_or(false);

    if is_websocket {
        // Check Origin header for WebSocket connections
        match request.headers().get(header::ORIGIN) {
            Some(origin) => {
                let origin_str = match origin.to_str() {
                    Ok(s) => s,
                    Err(_) => {
                        tracing::warn!("Invalid Origin header encoding");
                        return StatusCode::FORBIDDEN.into_response();
                    }
                };

                if ALLOWED_WS_ORIGINS.contains(&origin_str) {
                    tracing::debug!("WebSocket origin allowed: {}", origin_str);
                    next.run(request).await
                } else {
                    tracing::warn!(
                        "WebSocket connection blocked from unauthorized origin: {}",
                        origin_str
                    );
                    StatusCode::FORBIDDEN.into_response()
                }
            }
            None => {
                // Browsers always send Origin for WebSockets.
                // Missing Origin likely means non-browser client or malicious request.
                tracing::warn!("WebSocket connection blocked: missing Origin header");
                StatusCode::FORBIDDEN.into_response()
            }
        }
