/// Listens for OS signals and forwards them to the main thread.
/// Stops immediately when a message is received on the `ctrl` channel.
fn yield_signals(sender: mpsc::Sender<Message>, ctrl: Receiver<()>) {
    // Convert the blocking Signals iterator into a channel so we can select on it
    let (sig_tx, sig_rx) = unbounded();
    let signals = Signals::new(&[SIGINT, SIGTERM]).unwrap();

    // Spawn a helper thread to drain the blocking iterator
    thread::spawn(move || {
        for sig in signals {
            if sig_tx.send(sig).is_err() {
