            recv(ctrl) -> _ => {
                println!("[Signal thread] Stop command received, shutting down...");
                break;
            }
            // Check for signals
            recv(sig_rx) -> sig => {
                if let Ok(s) = sig {
                    let _ = sender.send(Message::Signal(s));
                }
            }
        }
    }
}

