fn yield_keys(sender: mpsc::Sender<Message>, ctrl: Receiver<()>) {
    // Convert blocking stdin to a channel
    let (key_tx, key_rx) = unbounded();
    let running = Arc::new(AtomicBool::new(true));
    let r = running.clone();

    // Spawn helper thread for blocking stdin reading
    thread::spawn(move || {
        // Raw mode is required for termion to capture individual keypresses
        let _stdout = stdout().into_raw_mode().unwrap();
        let stdin = stdin();

        for evt in stdin.keys() {
            if !r.load(Ordering::Relaxed) {
                break;
            }
            if key_tx.send(evt).is_err() {
                break;
            }
        }
    });

    loop {
        select! {
            recv(ctrl) -> _ => {
                println!("[Key thread] Stop command received, shutting down...");
                running.store(false, Ordering::Relaxed);
                break;
            }
            recv(key_rx) -> key => {
                if let Ok(Ok(k)) = key {
                    let _ = sender.send(Message::Key(k));
                }
            }
        }
    }
    // Note: The helper thread may briefly remain blocked on stdin until the next keypress,
    // but since we set the atomic flag to false, it will exit immediately after.
}

fn main() {
    let (main_tx, main_rx) = mpsc::channel();

    // Control channels to stop the worker threads
    let (sig_ctrl_tx, sig_ctrl_rx) = bounded(1);
    let (key_ctrl_tx, key_ctrl_rx) = bounded(1);

    // Spawn signal handler thread
    let main_tx_sig = main_tx.clone();
    let handle_sig = thread::spawn(move || {
        yield_signals(main_tx_sig, sig_ctrl_rx);
    });

    // Spawn keyboard handler thread
    let main_tx_key = main_tx.clone();
    let handle_key = thread::spawn(move || {
        yield_keys(main_tx_key, key_ctrl_rx);
    });

    println!("Event loop running. Press 'q' to quit, or send SIGINT (Ctrl+C).");

    // Main event loop
    for msg in main_rx {
        match msg {
            Message::Signal(sig) => {
                println!("[Main] Received signal: {} (stopping)", sig);
                break;
            }
            Message::Key(key) => {
                println!("[Main] Received key: {:?}", key);
                if key == Key::Char('q') {
                    println!("[Main] Quit key pressed, initiating shutdown...");
                    break;
                }
            }
        }
