    // Graceful shutdown: send stop messages to both threads
    println!("[Main] Sending stop commands to worker threads...");
    let _ = sig_ctrl_tx.send(());
    let _ = key_ctrl_tx.send(());

    // Wait for threads to finish
    handle_sig.join().expect("Signal thread panicked");
    handle_key.join().expect("Key thread panicked");

    println!("[Main] Clean shutdown complete.");
}
