// Custom Visitor for deserializing B
struct BVisitor;

impl<'de> Visitor<'de> for BVisitor {
    type Value = B;

    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
        formatter.write_str("enum B as a map like {\"Int\": 42} or {\"Text\": \"hello\"}")
