/// Returns the rotation needed to align Vec3::Z with the given local face normal.
/// This maps the gizmo's default orientation (lying in XY plane, facing +Z) 
/// to the correct face of the cube (+X, -X, +Y, -Y, +Z, -Z).
fn determine_face_rotation(local_normal: Vec3) -> Quat {
    let n = local_normal.normalize();

    // Determine dominant axis to identify which face we're hitting
    if n.x.abs() > n.y.abs() && n.x.abs() > n.z.abs() {
        // X-axis faces
        if n.x > 0.0 {
            // +X face: Rotate Z to point +X (90° around Y)
            Quat::from_rotation_y(std::f32::consts::FRAC_PI_2)
