/// Trait that defines partial matching semantics.
/// A filter matches an object if all fields present in the filter (Some values)
/// are equal to the corresponding fields in the object.
pub trait Filterable {
    fn matches(&self, filter: &Self) -> bool;
}

// === Primitive implementations ===
// For primitive types, matching is just equality.

impl Filterable for bool {
    fn matches(&self, filter: &Self) -> bool {
        self == filter
    }
}

impl Filterable for String {
    fn matches(&self, filter: &Self) -> bool {
        self == filter
    }
}

impl Filterable for i32 {
    fn matches(&self, filter: &Self) -> bool {
        self == filter
    }
}

// === Recursive Option implementation ===
// This is the key insight: None in the filter means "don't care",
// Some means "must match recursively".

impl<T: Filterable> Filterable for Option<T> {
    fn matches(&self, filter: &Self) -> bool {
        match filter {
            // Filter field is not set -> matches anything (partial filter)
            None => true,
            // Filter field is set -> must check against actual value
            Some(filter_val) => match self {
                // Filter has value but object doesn't -> no match
                None => false,
                // Both have values -> recursive check
                Some(self_val) => self_val.matches(filter_val),
            },
        }
    }
}

