    type Input<'src>: Input<'src, Token = Self::InputToken<'src>, Span = SimpleSpan>;
    type Output;

    fn parser<'src>() -> impl Parser<
        'src,
        Self::Input<'src>,
        Self::Output,
        extra::Err<Rich<'src, Self::InputToken<'src>, SimpleSpan>>,
    >;

    fn parse_this<'src>(input: Self::Input<'src>) -> Result<Self::Output, Vec<String>> {
        Self::parser().parse(input).into_result().map_err(|errors| {
            errors
                .into_iter()
                .map(|e| e.to_string())
                .collect::<Vec<_>>()
        })
    }
}

pub trait BaseSliceParser<'src>:
    BaseParser<Input<'src> = &'src [Self::InputToken<'src>]>
{
