    // This allows the slice borrow to match the lifetime of the local `input` variable
    // rather than the potentially longer 'src lifetime from the trait parameter.
    fn parse_this_owned<'a>(
        input: Vec<Self::InputToken<'a>>,
    ) -> Result<Self::Output, Vec<String>>
    where
        Self: BaseParser<Input<'a> = &'a [Self::InputToken<'a>]>,
    {
        Self::parse_this(input.as_slice())
    }
}

