    type InputToken<'src> = Token;
    type Input<'src> = &'src [Token];
    type Output = Vec<Token>;

    fn parser<'src>() -> impl Parser<'src, &'src [Token], Vec<Token>, extra::Err<Rich<'src, Token, SimpleSpan>>> {
        any().repeated().collect()
    }
}

