                if i + 1 < self.selection_iterators.len() {
                    self.current_index_option[i + 1] = self.current_iterators[i + 1].next();
                }
            } else {
                break;
            }
        }

        let current_index: Vec<usize> = self.current_index_option
            .iter()
            .map(|x| x.unwrap())
            .collect();

        let flat_idx = self.ndindex_to_flat(&current_index);

