use tracing::{info, info_span, Instrument, Span};
use tracing_opentelemetry::OpenTelemetrySpanExt;
use opentelemetry::global;

/// Context that travels with the request through all stages.
/// The key is storing the parent Span so it can be "rehydrated" (re-entered)
/// when async callbacks fire on potentially different threads/tasks.
#[derive(Clone)]
struct RequestContext {
    /// The root request span. This is Send + Sync and can safely be stored
    /// and moved across async boundaries.
    parent_span: Span,
}

impl RequestContext {
    fn new() -> Self {
        let parent_span = info_span!("Request/Parent Span");
        Self { parent_span }
    }

    /// Helper to create a child span explicitly linked to the stored parent.
    /// Use this when you don't need to enter the parent, just link children to it.
    fn child_span(&self, name: &'static str) -> Span {
        info_span!(parent: self.parent_span.clone(), name)
    }
}

/// Simulates Pingora's first stage (e.g., request_filter)
async fn stage_1(ctx: RequestContext) {
    // Method 1: Rehydrate using .instrument()
    // This attaches the parent span to the async block, making it the "current" span
    // for everything inside, including the new Stage 1 span.
    let work = async {
        let stage_span = info_span!("Stage 1 Span");
        let _enter = stage_span.enter();

        info!("Processing stage 1 logic");
        tokio::time::sleep(Duration::from_millis(100)).await;
        info!("Stage 1 complete");
    }
    .instrument(ctx.parent_span.clone());

    work.await;
}

/// Simulates Pingora's second stage (e.g., upstream_peer)
/// This might be called later, on a different task/thread.
async fn stage_2(ctx: RequestContext) {
    // Method 2: Explicit parenting without entering
    // Create child span directly referencing the stored parent.
    // This avoids the need to enter the parent span first.
    let stage_span = ctx.child_span("Stage 2 Span");
    let _enter = stage_span.enter();

    info!("Processing stage 2 logic");
    tokio::time::sleep(Duration::from_millis(100)).await;
    info!("Stage 2 complete");
}

/// Simulates the upstream request
async fn upstream_request(ctx: RequestContext) {
    // Method 3: Using in_scope for synchronous-style rehydration
    // Useful for quick sync operations or setting up context before the async block.
    ctx.parent_span.in_scope(|| {
        info!("Preparing upstream connection in parent context");
    });

    // Then instrument the async work
    let work = async {
        let upstream_span = info_span!("Upstream Span");
        let _enter = upstream_span.enter();

        info!("Sending request to upstream");
        tokio::time::sleep(Duration::from_millis(100)).await;
        info!("Upstream response received");
    }
    .instrument(ctx.parent_span.clone());

    work.await;
}

#[tokio::main]
async fn main() {
    // Setup OpenTelemetry with stdout exporter so you can see the trace structure
    let exporter = opentelemetry_stdout::SpanExporter::default();
    let provider = opentelemetry_sdk::trace::TracerProvider::builder()
        .with_simple_exporter(exporter)
        .build();

    let tracer = provider.tracer("pingora-proxy");
    global::set_tracer_provider(provider);

    // Setup subscriber with both console output (fmt) and OTLP (structured)
    tracing_subscriber::registry()
        .with(
            tracing_subscriber::fmt::layer()
                .with_target(false)
                .with_thread_ids(true),
        )
        .with(tracing_opentelemetry::layer().with_tracer(tracer))
        .init();

    // Simulate the request lifecycle
    let ctx = RequestContext::new();

    // Run the entire request flow instrumented with the parent span.
    // This ensures the parent is active throughout, even across await points
    // and thread boundaries (via tokio::spawn).
    let request_flow = async {
        info!("Request started");

        // Stage 1 runs with parent context
        stage_1(ctx.clone()).await;

        // Simulate gap between stages (maybe some internal processing)
        tokio::time::sleep(Duration::from_millis(50)).await;

        // Stage 2 might run on a different task (simulating work-stealing/thread change)
        let ctx2 = ctx.clone();
        let handle = tokio::spawn(async move {
            stage_2(ctx2).await;
        });
        handle.await.unwrap();

        // Another gap
        tokio::time::sleep(Duration::from_millis(50)).await;

        // Upstream request
        upstream_request(ctx).await;

        info!("Request completed");
    }
    .instrument(ctx.parent_span.clone());

    request_flow.await;

    // Allow exporter to flush
    tokio::time::sleep(Duration::from_millis(500)).await;
    global::shutdown_tracer_provider();
}
"
