#![cfg_attr(not(debug_assertions), windows_subsystem = "windows")]

use std::sync::{
    mpsc::{channel, Sender},
    Arc, Mutex,
};
use std::thread;

use expectrl::spawn;
use nix::poll::{poll, PollFd, PollFlags};
use std::os::unix::io::AsRawFd;
use tauri::{AppHandle, Manager, State};

/// Handle to a running agent. Only holds a channel sender; the actual Session
/// lives in a background thread to avoid blocking mutex issues.
pub struct Agent {
    tx: Sender<String>,
}

impl Agent {
    /// Spawns the PTY in a background thread. The thread owns the Session and
    /// uses poll() to wait for output without blocking the ability to receive
    /// write requests via the channel.
    pub fn spawn(app: AppHandle, program: &str) -> Result<Self, String> {
        let mut session = spawn(program).map_err(|e| format!("spawn failed: {}", e))?;

        // Obtain raw FD for polling (Unix only)
        let fd = session.as_raw_fd();
        let (tx, rx) = channel::<String>();

        thread::spawn(move || {
            let mut pollfd = PollFd::new(fd, PollFlags::POLLIN);
            let mut buf = [0u8; 1024];

            loop {
                // 1. Drain any pending write requests from the frontend (non-blocking)
                match rx.try_recv() {
                    Ok(data) => {
                        if let Err(e) = session.send(&data) {
                            eprintln!("PTY write error: {}", e);
                            let _ = app.emit("agent-output", format!("[write error: {}]\r\n", e));
                            break;
                        }
                    }
                    Err(std::sync::mpsc::TryRecvError::Empty) => {}
                    Err(std::sync::mpsc::TryRecvError::Disconnected) => {
                        // Main thread dropped the Agent; exit cleanly
                        break;
                    }
                }

                // 2. Poll for readability with a short timeout (10ms).
                // This prevents blocking forever if the process is idle,
                // allowing us to check for new write requests frequently.
                match poll(&mut [pollfd], 10) {
                    Ok(0) => {
                        // Timeout: no data from PTY, loop back to check rx
                        continue;
                    }
                    Ok(_) => {
                        // Data is available to read without blocking
                        match session.read(&mut buf) {
                            Ok(0) => {
                                // EOF
                                let _ = app.emit("agent-output", "[process terminated]\r\n");
                                break;
                            }
                            Ok(n) => {
                                let text = String::from_utf8_lossy(&buf[..n]);
                                if let Err(e) = app.emit("agent-output", text.to_string()) {
                                    eprintln!("Emit error: {}", e);
                                }
                            }
                            Err(e) => {
                                let _ = app.emit("agent-output", format!("[read error: {}]\r\n", e));
                                break;
                            }
                        }
                    }
                    Err(e) => {
                        let _ = app.emit("agent-output", format!("[poll error: {}]\r\n", e));
                        break;
                    }
                }
            }
            let _ = app.emit("agent-output", "[agent thread exited]\r\n");
        });

        Ok(Self { tx })
    }

    /// Queues data to be sent to the PTY. Returns immediately (non-blocking).
    pub fn send(&self, data: &str) -> Result<(), String> {
        self.tx
            .send(data.to_string())
            .map_err(|e| format!("channel closed: {}", e))
    }
}

// ------------------------------------------------------------------
// Tauri Integration
// ------------------------------------------------------------------

pub struct AppState {
    agent: Arc<Mutex<Option<Agent>>>,
}

impl AppState {
    pub fn new() -> Self {
        Self {
            agent: Arc::new(Mutex::new(None)),
        }
    }
}

#[tauri::command]
fn start_agent(
    program: String,
    state: State<AppState>,
    app: AppHandle,
) -> Result<(), String> {
    let mut guard = state.agent.lock().map_err(|e| e.to_string())?;
    if guard.is_some() {
        return Err("Agent already running".into());
    }
    let agent = Agent::spawn(app, &program)?;
    *guard = Some(agent);
    Ok(())
}

#[tauri::command]
fn send_to_agent(message: String, state: State<AppState>) -> Result<(), String> {
    let guard = state.agent.lock().map_err(|e| e.to_string())?;
    match guard.as_ref() {
        Some(agent) => agent.send(&message),
        None => Err("No agent running".into()),
    }
}

#[tauri::command]
fn stop_agent(state: State<AppState>) -> Result<(), String> {
    let mut guard = state.agent.lock().map_err(|e| e.to_string())?;
    // Dropping the Agent drops the Sender, causing the thread to exit
    *guard = None;
    Ok(())
}

fn main() {
    tauri::Builder::default()
        .manage(AppState::new())
        .invoke_handler(tauri::generate_handler![
            start_agent,
            send_to_agent,
            stop_agent
        ])
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}
