            FrameworkError::Error400(e) => write!(f, "400: {}", e),
        }
    }
}

impl Error for FrameworkError {}

/// Helper function that constructs a log record with manually specified metadata.
/// This allows us to override the module path to match the calling code.
pub fn log_and_transform<T, E: Error + 'static>(
    result: Result<T, E>,
    level: log::Level,
    module_path: &'static str,
    file: &'static str,
    line: u32,
) -> Result<T, FrameworkError> {
    match result {
        Ok(v) => Ok(v),
        Err(e) => {
            // Manually construct the log record so we can set the module_path to the caller's module
            log::logger().log(
                &log::Record::builder()
                    .level(level)
                    .target(module_path)
                    .module_path(Some(module_path))
                    .file(Some(file))
                    .line(Some(line))
                    .args(format_args!("Error: {:?}", e))
                    .build(),
            );
            Err(FrameworkError::Error400(Box::new(e)))
        }
    }
}

/// Macro that captures the calling context (module_path, file, line) and invokes 
/// the helper function with that metadata. This ensures the log shows the module
/// of the calling code, not the module where the helper is defined.
#[macro_export]
macro_rules! log_and_explain_400 {
    ($expr:expr) => {
        $crate::log_and_transform(
            $expr,
            log::Level::Warn,
            module_path!(),
            file!(),
            line!(),
        )
    };
}

pub mod my_application_code {
