        // Import the macro
        use crate::log_and_explain_400;

        fn failing_function() -> Result<u32, std::num::ParseIntError> {
            "abc".parse()
        }

        pub fn some_route() -> Result<u32, crate::FrameworkError> {
            // This log call correctly shows my_application_code::routes_example
            log::warn!("This log call is from the correct module");

            // Using the macro captures the caller's module path at compile time.
            // The syntax is slightly different (macro!() instead of .method()), but this is 
            // necessary to capture module_path!() at the call site.
            let long_chain = log_and_explain_400!(failing_function())? + 42;
            Ok(long_chain)
        }
    }
}

fn main() {
