use bevy::prelude::*;
use bevy::render::render_resource::{Extent3d, TextureDimension, TextureFormat};
use byteorder::{LittleEndian, WriteBytesExt};
use futures_lite::{AsyncRead, AsyncReadExt, AsyncSeek, AsyncSeekExt};
use std::collections::HashMap;
use std::io::{Cursor, SeekFrom, Write};
use std::path::{Path, PathBuf};
use std::sync::Mutex;

/// ---------------------------------------------------------------------------
/// 1. WAD3 Format Definitions
/// ---------------------------------------------------------------------------
const WAD3_MAGIC: &[u8; 4] = b"WAD3";
const MIPTEX_TYPE: u8 = 0x43; // GoldSrc texture type

/// A cached index of a WAD file's contents. This allows lazy loading:
/// we only parse the directory once, then seek to specific entries on demand.
struct WadIndex {
    entries: HashMap<String, (u32, u32)>, // name -> (offset, size_in_bytes)
}

impl WadIndex {
    async fn load<R: AsyncRead + AsyncSeek + Unpin>(mut reader: R) -> Result<Self, std::io::Error> {
        // Read header
        let mut magic = [0u8; 4];
        reader.read_exact(&mut magic).await?;
        if &magic != WAD3_MAGIC {
            return Err(std::io::Error::new(
                std::io::ErrorKind::InvalidData,
                "Not a valid WAD3 file",
            ));
        }

        let mut buf = [0u8; 4];
        reader.read_exact(&mut buf).await?;
        let num_lumps = u32::from_le_bytes(buf);

        reader.read_exact(&mut buf).await?;
        let dir_offset = u32::from_le_bytes(buf);

        // Seek to directory
        reader.seek(SeekFrom::Start(dir_offset as u64)).await?;

        let mut entries = HashMap::new();
        for _ in 0..num_lumps {
            // Each directory entry is 32 bytes
            let mut entry = [0u8; 32];
            reader.read_exact(&mut entry).await?;

            let offset = u32::from_le_bytes([entry[0], entry[1], entry[2], entry[3]]);
            let size = u32::from_le_bytes([entry[4], entry[5], entry[6], entry[7]]);
            // entry[8..12] = compressed size (unused here)
            // entry[12] = type, entry[13] = compression, entry[14..16] = pad

            let name = String::from_utf8_lossy(&entry[16..32])
                .trim_end_matches('\0')
                .to_string();

            if !name.is_empty() {
                entries.insert(name, (offset, size));
            }
        }

        Ok(Self { entries })
    }
}

/// ---------------------------------------------------------------------------
/// 2. Custom AssetReader for Lazy WAD Loading
/// ---------------------------------------------------------------------------
/// This reader intercepts paths like `maps/level.wad/BRICK` and extracts only
/// the specific texture entry from the archive, without loading the whole WAD.
pub struct WadAssetReader {
    root: PathBuf,
    // Cache WAD directories so we don't re-parse them for every texture
    cache: Mutex<HashMap<PathBuf, WadIndex>>,
}

impl WadAssetReader {
    pub fn new(root: PathBuf) -> Self {
        Self {
            root,
            cache: Mutex::new(HashMap::new()),
        }
    }
}

impl AssetReader for WadAssetReader {
    async fn read<'a>(&'a self, path: &'a Path) -> Result<Reader<'a>, AssetReaderError> {
        // Check if path contains a .wad component followed by sub-paths
        // Format: path/to/archive.wad/TEXTURE_NAME
        let components: Vec<_> = path.components().collect();

        for (i, comp) in components.iter().enumerate() {
            if let Some(name) = comp.as_os_str().to_str() {
                if name.ends_with(".wad") && i + 1 < components.len() {
                    // Found a WAD file reference
                    let wad_path: PathBuf = components[..=i].iter().collect();
                    let entry_name: String = components[i + 1..]
                        .iter()
                        .map(|c| c.as_os_str().to_string_lossy())
                        .collect::<Vec<_>>()
                        .join("/");

                    let full_wad_path = self.root.join(&wad_path);

                    // Get or load WAD index (directory)
                    let mut cache = self.cache.lock().unwrap();
                    let index = if let Some(idx) = cache.get(&full_wad_path) {
                        idx
                    } else {
                        let file = async_fs::File::open(&full_wad_path)
                            .await
                            .map_err(|e| AssetReaderError::Io(Box::new(e)))?;
                        let idx = WadIndex::load(file)
                            .await
                            .map_err(|e| AssetReaderError::Io(Box::new(e)))?;
                        cache.insert(full_wad_path.clone(), idx);
                        cache.get(&full_wad_path).unwrap()
                    };

                    let (offset, size) = index
                        .entries
                        .get(&entry_name)
                        .ok_or_else(|| AssetReaderError::NotFound(path.to_path_buf()))?;

                    // Seek and read only the specific entry
                    let mut file = async_fs::File::open(&full_wad_path)
                        .await
                        .map_err(|e| AssetReaderError::Io(Box::new(e)))?;

                    file.seek(SeekFrom::Start(*offset as u64))
                        .await
                        .map_err(|e| AssetReaderError::Io(Box::new(e)))?;

                    let mut data = vec![0u8; *size as usize];
                    file.read_exact(&mut data)
                        .await
                        .map_err(|e| AssetReaderError::Io(Box::new(e)))?;

                    // Return a cursor over the entry data
                    return Ok(Box::new(Cursor::new(data)));
                }
            }
        }

        // Not a WAD sub-path, delegate to regular file system
        let file = async_fs::File::open(self.root.join(path))
            .await
            .map_err(|e| match e.kind() {
                std::io::ErrorKind::NotFound => AssetReaderError::NotFound(path.to_path_buf()),
                _ => AssetReaderError::Io(Box::new(e)),
            })?;
        Ok(Box::new(file))
    }

    async fn read_meta<'a>(&'a self, path: &'a Path) -> Result<Reader<'a>, AssetReaderError> {
        // WAD entries don't have separate meta files
        Err(AssetReaderError::NotFound(path.to_path_buf()))
    }

    async fn is_directory<'a>(&'a self, _path: &'a Path) -> Result<bool, AssetReaderError> {
        Ok(false)
    }

    async fn read_directory<'a>(
        &'a self,
        path: &'a Path,
    ) -> Result<Box<dyn Iterator<Item = PathBuf> + Send>, AssetReaderError> {
        Err(AssetReaderError::NotFound(path.to_path_buf()))
    }
}

/// ---------------------------------------------------------------------------
/// 3. Asset Types and Loader
/// ---------------------------------------------------------------------------
#[derive(Asset, TypePath, Debug, Clone)]
struct WadTexture {
    indexed_pixels: Vec<u8>, // 8-bit palette indices
    width: u32,
    height: u32,
    palette: Vec<u8>, // RGB triplets (768 bytes for 256 colors)
}

#[derive(Default)]
struct WadTextureLoader;

impl AssetLoader for WadTextureLoader {
    type Asset = WadTexture;
    type Settings = ();
    type Error = std::io::Error;

    async fn load<'a>(
        &'a self,
        reader: &'a mut Reader<'_>,
        _settings: &'a (),
        _load_context: &'a mut LoadContext<'_>,
    ) -> Result<WadTexture, Self::Error> {
        // Read entire lump into memory
        let mut buf = Vec::new();
        reader.read_to_end(&mut buf).await?;
        let mut cursor = Cursor::new(&buf);

        // Parse MIPTEX header
        cursor.set_position(16); // Skip name (16 bytes)

        let width = read_u32_le(&mut cursor)?;
        let height = read_u32_le(&mut cursor)?;

        // Skip 4 mipmap offsets (16 bytes)
        cursor.set_position(16 + 4 + 4 + 16);

        // Read first (full-size) mipmap
        let mip_size = (width * height) as usize;
        let mut indexed_pixels = vec![0u8; mip_size];
        cursor.read_exact(&mut indexed_pixels)?;

        // Skip remaining mipmaps (half, quarter, eighth)
        let m2 = ((width / 2) * (height / 2)) as i64;
        let m3 = ((width / 4) * (height / 4)) as i64;
        let m4 = ((width / 8) * (height / 8)) as i64;
        cursor.seek(SeekFrom::Current(m2 + m3 + m4))?;

        // Read palette
        let pal_size = read_u16_le(&mut cursor)? as usize;
        let mut palette = vec![0u8; pal_size * 3];
        cursor.read_exact(&mut palette)?;

        Ok(WadTexture {
            indexed_pixels,
            width,
            height,
            palette,
        })
    }
}

fn read_u32_le(cursor: &mut Cursor<&Vec<u8>>) -> Result<u32, std::io::Error> {
    let mut buf = [0u8; 4];
    cursor.read_exact(&mut buf)?;
    Ok(u32::from_le_bytes(buf))
}

fn read_u16_le(cursor: &mut Cursor<&Vec<u8>>) -> Result<u16, std::io::Error> {
    let mut buf = [0u8; 2];
    cursor.read_exact(&mut buf)?;
    Ok(u16::from_le_bytes(buf))
