/// Creates a minimal WAD3 file with one test texture (64x64 checkerboard)
fn create_test_wad_file() {
    let wad_path = PathBuf::from("test.wad");
    if wad_path.exists() {
        return; // Don't recreate if already exists
    }

    let mut file = std::fs::File::create(&wad_path).unwrap();

    // Create a simple 64x64 texture with checkerboard pattern
    let width: u32 = 64;
    let height: u32 = 64;
    let mip0_size = (width * height) as usize;
    let mip1_size = ((width / 2) * (height / 2)) as usize;
    let mip2_size = ((width / 4) * (height / 4)) as usize;
    let mip3_size = ((width / 8) * (height / 8)) as usize;

    // Generate checkerboard pixels (palette indices 0 and 1)
    let mut mip0: Vec<u8> = Vec::with_capacity(mip0_size);
    for y in 0..height {
        for x in 0..width {
            let checker = ((x / 8) + (y / 8)) % 2;
            mip0.push(checker as u8);
        }
    }
    let mip1: Vec<u8> = mip0.iter().step_by(2).take(mip1_size).copied().collect();
    let mip2: Vec<u8> = mip0.iter().step_by(4).take(mip2_size).copied().collect();
    let mip3: Vec<u8> = mip0.iter().step_by(8).take(mip3_size).copied().collect();

    // Build MIPTEX lump
    let mut lump = Vec::new();

    // Name (16 bytes)
    let mut name = [0u8; 16];
    name[..12].copy_from_slice(b"TESTTEXTURE\0");
    lump.write_all(&name).unwrap();

    // Width, Height
    lump.write_u32::<LittleEndian>(width).unwrap();
    lump.write_u32::<LittleEndian>(height).unwrap();

    // Mipmap offsets (relative to start of texture header)
    let header_size = 16 + 4 + 4 + 16; // 40 bytes
    let offsets = [
        header_size,
        header_size + mip0_size as u32,
        header_size + mip0_size as u32 + mip1_size as u32,
        header_size + mip0_size as u32 + mip1_size as u32 + mip2_size as u32,
    ];
    for off in offsets {
        lump.write_u32::<LittleEndian>(off).unwrap();
    }

    // Mipmap data
    lump.write_all(&mip0).unwrap();
    lump.write_all(&mip1).unwrap();
    lump.write_all(&mip2).unwrap();
    lump.write_all(&mip3).unwrap();

    // Palette (256 colors)
    lump.write_u16::<LittleEndian>(256).unwrap(); // palette size
    // Color 0: Black, Color 1: White, rest: gradient
    for i in 0..256 {
        if i == 0 {
            lump.write_all(&[0, 0, 0]).unwrap(); // Black
        } else if i == 1 {
            lump.write_all(&[255, 255, 255]).unwrap(); // White
        } else {
            let v = i as u8;
            lump.write_all(&[v, v, v]).unwrap(); // Greyscale
        }
    }

    // Write WAD Header
    let dir_offset = 12 + lump.len() as u32; // header + lump
    file.write_all(WAD3_MAGIC).unwrap();
    file.write_u32::<LittleEndian>(1).unwrap(); // num lumps
    file.write_u32::<LittleEndian>(dir_offset).unwrap();

    // Write lump data
    file.write_all(&lump).unwrap();

    // Write directory entry
    file.write_u32::<LittleEndian>(12).unwrap(); // offset (after header)
    file.write_u32::<LittleEndian>(lump.len() as u32).unwrap(); // size
    file.write_u32::<LittleEndian>(lump.len() as u32).unwrap(); // compressed size
    file.write_u8(MIPTEX_TYPE).unwrap();
    file.write_u8(0).unwrap(); // compression
    file.write_u16::<LittleEndian>(0).unwrap(); // pad
    file.write_all(&name).unwrap();

    println!("Created test.wad with TESTTEXTURE (64x64 checkerboard)");
}

