    if *done {
        return;
    }

    if let Some(wad_tex) = wad_textures.get(&handle.0) {
        println!("Loaded WAD texture: {}x{}", wad_tex.width, wad_tex.height);

        // Convert indexed color to RGBA
        let mut rgba = Vec::with_capacity((wad_tex.width * wad_tex.height * 4) as usize);
        for &index in &wad_tex.indexed_pixels {
            let idx = index as usize * 3;
            let r = wad_tex.palette.get(idx).copied().unwrap_or(0);
            let g = wad_tex.palette.get(idx + 1).copied().unwrap_or(0);
            let b = wad_tex.palette.get(idx + 2).copied().unwrap_or(0);
            rgba.push(r);
            rgba.push(g);
            rgba.push(b);
            rgba.push(255); // Alpha
        }

        let image = Image::new(
            Extent3d {
                width: wad_tex.width,
                height: wad_tex.height,
                depth_or_array_layers: 1,
            },
            TextureDimension::D2,
            rgba,
            TextureFormat::Rgba8UnormSrgb,
            RenderAssetUsages::default(),
        );

        let image_handle = images.add(image);

        // Display the texture
        commands.spawn(SpriteBundle {
            texture: image_handle,
            sprite: Sprite {
                custom_size: Some(Vec2::new(256.0, 256.0)), // Scale up for visibility
                ..default()
            },
            ..default()
        });

        println!("Texture displayed! Note that only the requested texture was loaded from the WAD, not all 3200 potential textures.");
        *done = true;
    }
}
