  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::sync::Arc;
use std::task::{Context, Poll, Wake, Waker};

/// Result of trying to poll a future once without yielding
pub enum TryPollResult<T> {
    Ready(T),
    Pending,
}

/// A waker that does nothing when waked
struct NoopWaker;

impl Wake for NoopWaker {
    fn wake(self: Arc<Self>) {}
    fn wake_by_ref(self: &Arc<Self>) {}
}

fn create_noop_waker() -> Waker {
    Waker::from(Arc::new(NoopWaker))
}

/// Try to poll a future once. If it's ready, return the value.
/// If it's pending, return Pending without blocking.
/// 
/// Note: This requires the future to be `Unpin`. For `!Unpin` futures 
/// (like most Tokio IO futures), use `Box::pin()` to pin them first.
pub fn try_poll<F, T>(future: &mut F) -> TryPollResult<T>
where
    F: Future<Output = T> + Unpin,
{
    let waker = create_noop_waker();
    let mut context = Context::from_waker(&waker);

    match Pin::new(future).poll(&mut context) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

#[tokio::main]
async fn main() {
    println!("=== Testing try_poll ===\n");

    // Test 1: A future that is immediately ready
    println!("Test 1: Immediately ready future");
    let mut ready_fut = async { "hello world" };

    match try_poll(&mut ready_fut) {
        TryPollResult::Ready(val) => {
            println!("  -> Ready immediately with value: {}\n", val);
        }
        TryPollResult::Pending => {
            println!("  -> Pending (unexpected!)\n");
        }
    }

    // Test 2: A future that will be pending (Unpin version)
    println!("Test 2: Pending future (std::future::pending)");
    let mut pending_fut = std::future::pending::<i32>();

    match try_poll(&mut pending_fut) {
        TryPollResult::Ready(_) => {
            println!("  -> Ready immediately (unexpected!)\n");
        }
        TryPollResult::Pending => {
            println!("  -> Pending as expected, spawning in task...");
            // Since try_poll only borrowed, we still own pending_fut and can move it
            tokio::spawn(async move {
                // This would block forever, but demonstrates the pattern
                let _: i32 = pending_fut.await;
            });
            println!("  -> Spawned task\n");
        }
    }

    // Test 3: Demonstration with a real Tokio future (requires boxing for !Unpin types)
    println!("Test 3: Tokio sleep (Box::pin required for !Unpin types)");
    let mut sleep_fut = Box::pin(tokio::time::sleep(std::time::Duration::from_millis(100)));

    match try_poll(&mut sleep_fut) {
        TryPollResult::Ready(_) => {
            println!("  -> Ready immediately (unexpected!)\n");
        }
        TryPollResult::Pending => {
            println!("  -> Pending, spawning sleep in task...");
            tokio::spawn(async move {
                sleep_fut.await;
                println!("  -> Sleep completed in spawned task\n");
            });
        }
    }

    // Wait for the sleep to complete
    tokio::time::sleep(std::time::Duration::from_millis(200)).await;
    println!("Done!");
}"
}
