use rustyline::line_buffer::LineBuffer;
use rustyline::{Config, Editor, Event, KeyCode, KeyEvent};

fn main() -> rustyline::Result<()> {
    let config = Config::builder().build();
    let mut rl = Editor::<(), DefaultHistory>::with_config(config)?;

    // Use set_pre_handler to delete whitespace BEFORE the default key handling.
    // This allows the '.' or ',' to be inserted by the default handler after
    // we've removed the whitespace, ensuring the cursor ends up AFTER the char.
    rl.set_pre_handler(Some(Box::new(
        |line: &mut LineBuffer, event: &Event, _history: &dyn History| -> bool {
            // Check if the event is '.' or ','
            if let Event::Key(KeyEvent { code: KeyCode::Char(c @ ('.' | ',')), .. }) = event {
                let pos = line.pos();
                let text = line.as_str();

                // Count consecutive whitespace characters immediately before cursor
                let mut whitespace_count = 0;
                for ch in text[..pos].chars().rev() {
                    if ch.is_whitespace() {
                        whitespace_count += 1;
                    } else {
                        break;
                    }
                }

                if whitespace_count > 0 {
                    // Delete the whitespace range [pos - count, pos)
                    let start = pos - whitespace_count;
                    line.delete_range(start..pos);
                    // Cursor is now at 'start'. When we return true, the default
                    // handler will insert '.' at 'start', moving cursor to 'start + 1'.
                }
            }
            true // Return true to allow the event to be processed normally (insert the char)
        }
    )));

    println!("SQL-like REPL demo.");
    println!("Try typing 'SELECT book<TAB>' (which adds a space), then type '.' to see the auto-deletion.");
    println!("Type 'exit' to quit.\n");

    loop {
        match rl.readline("zql> ") {
            Ok(line) => {
                if line.trim().eq_ignore_ascii_case("exit") {
                    break;
                }
                println!("You entered: {:?}", line);
                let _ = rl.add_history_entry(&line);
            }
            Err(rustyline::error::ReadlineError::Interrupted) => {
                println!("CTRL-C");
                break;
            }
            Err(rustyline::error::ReadlineError::Eof) => {
                println!("CTRL-D");
                break;
            }
            Err(err) => {
                eprintln!("Error: {:?}", err);
                break;
            }
        }
    }

    Ok(())
}
