#[tokio::main]
async fn main() {
    // For this example, expects the DER file to be passed as first argument
    // or defaults to "scep_request.der"
    let filename = std::env::args().nth(1).unwrap_or_else(|| "scep_request.der".to_string());

    let body = fs::read(&filename).expect("Failed to read DER file");
    println!("Read {} bytes from {}", body.len(), filename);

    // Parse outer ContentInfo (SCEP PKIOperation is typically SignedData)
    let ci = ContentInfo::from_der(&body).expect("Failed to parse ContentInfo");
    println!("ContentInfo content type: {}", ci.content_type);

    // Attempt to decode SignedData
    // If this fails with INTEGER tag error at position ~129, it may be due to 
    // IMPLICIT tagging issues in the certificates field. Use the workaround below.
    let signed_data = match ci.content.decode_as::<SignedData>() {
        Ok(sd) => {
            println!("Successfully parsed SignedData");
            sd
        }
        Err(e) => {
            eprintln!("Standard SignedData parsing failed: {}", e);
            eprintln!("Attempting workaround for IMPLICIT tag issue...");
            parse_signed_data_workaround(ci.content.value())
                .expect("Workaround also failed")
        }
    };

    println!("SignedData version: {}", signed_data.version);
    println!("Digest algorithms count: {}", signed_data.digest_algorithms.len());

    // Access encapsulated content (contains EnvelopedData in SCEP)
    if let Some(econtent) = signed_data.encap_content_info.econtent {
        println!("eContentType: {}", signed_data.encap_content_info.econtent_type);
        println!("eContent length: {} bytes", econtent.value().len());

        // The eContent is typically an EnvelopedData structure
        // wrapped in a ContentInfo or directly as EnvelopedData
        match ContentInfo::from_der(econtent.value()) {
            Ok(inner_ci) => {
                println!("Inner ContentInfo type: {}", inner_ci.content_type);
                if inner_ci.content_type.to_string() == "1.2.840.113549.1.7.3" {
                    // pkcs7-envelopedData
                    let env_data: EnvelopedData = inner_ci.content.decode_as()
                        .expect("Failed to decode EnvelopedData");
                    println!("EnvelopedData version: {}", env_data.version);
                    println!("RecipientInfos count: {}", env_data.recipient_infos.len());
                }
            }
            Err(_) => {
                // Try parsing directly as EnvelopedData (without ContentInfo wrapper)
                match EnvelopedData::from_der(econtent.value()) {
                    Ok(ed) => {
                        println!("Parsed EnvelopedData directly (no ContentInfo wrapper)");
                        println!("Version: {}", ed.version);
                    }
                    Err(e) => eprintln!("Failed to parse eContent: {}", e)
                }
            }
        }
    }

    // Process signer infos
    println!("SignerInfos count: {}", signed_data.signer_infos.len());
    for (i, si) in signed_data.signer_infos.iter().enumerate() {
        println!("SignerInfo {}: version={}, digest_alg={}", 
                 i, si.version, si.digest_algorithm.oid);

        // Access signed attributes (SCEP uses transactionId, senderNonce, etc.)
        if let Some(signed_attrs) = &si.signed_attrs {
            println!("  Signed attributes count: {}", signed_attrs.len());
            for attr in signed_attrs.iter() {
                println!("    Attr OID: {}", attr.oid);
            }
        }
    }
