/// Workaround for parsing SignedData when strict DER decoding fails due to
/// IMPLICIT tagging issues in the certificates or crls fields.
/// Manually parses the SEQUENCE fields to extract the data we need.
fn parse_signed_data_workaround(content_bytes: &[u8]) -> Option<SignedData> {
    use der::{Sequence, Any, SliceReader};

    // Create a reader for the SignedData sequence
    let mut reader = SliceReader::new(content_bytes).ok()?;

    // Read as a generic sequence
    let seq = reader.decode::<der::SequenceRef<'_>>().ok()?;
    let mut fields = seq.decode::<_, Vec<Any>>().ok()?;

    // fields should be: version, digestAlgorithms, encapContentInfo, [certificates], [crls], signerInfos
    if fields.len() < 4 {
        return None;
    }

    // Reconstruct using the raw bytes
    // This is a simplified approach - in production you might want to
    // properly handle the optional fields
    let version = fields[0].decode_into::<u8>().ok()?;
    let digest_algorithms = fields[1].decode_into::<cms::cert::DigestAlgorithmIdentifiers>().ok()?;
    let encap_content_info = fields[2].decode_into::<cms::cert::EncapsulatedContentInfo>().ok()?;

    // Skip certificates (index 3) if it's context-specific [0] or parse if SET
    // Skip crls if present
    // signerInfos is last
    let signer_infos = fields.last()?.decode_into::<cms::signer_info::SignerInfos>().ok()?;

    Some(SignedData {
        version: version.into(),
        digest_algorithms,
        encap_content_info,
        certificates: None, // Skip problematic field
        crls: None,
        signer_infos,
    })
}
"
}
