    let is_target = full_path == "vexide::devices" || full_path.starts_with("vexide::devices::");

    if is_target {
        // Calculate the new path with 'devices' removed
        let new_path = if full_path == "vexide::devices" {
            "vexide".to_string()
        } else {
            full_path.replacen("vexide::devices", "vexide", 1)
        };

        if let Some(list) = subtrees {
            // Case: vexide::devices::{...} or vexide::devices::foo::{...}
            // Process children without prefix since they're relative to the new_path context
            let mut new_children = Vec::new();
            for child in list.use_trees() {
                new_children.extend(transform_use_tree(&child, None));
            }

            if full_path == "vexide::devices" {
                // Flatten: remove this level and return children directly
                return new_children;
            } else {
                // Rebuild with new path and processed children
                return vec![build_tree_string(&new_path, &new_children, has_star, rename.as_deref())];
            }
        } else {
            // Case: vexide::devices or vexide::devices::Foo or vexide::devices::*
            if full_path == "vexide::devices" {
                // Just importing the devices module - delete it since it's being flattened
                return vec![];
            } else {
                // Rewrite the path
                let fragment = if has_star {
                    format!("{}::*", new_path)
                } else if let Some(alias) = rename {
                    format!("{} as {}", new_path, alias)
                } else {
                    new_path
                };
                return vec![fragment];
            }
        }
    }

    // Not a target path - recurse normally with accumulated prefix
    if let Some(list) = subtrees {
        let mut new_children = Vec::new();
        for child in list.use_trees() {
            new_children.extend(transform_use_tree(&child, Some(full_path.clone())));
        }

        // Rebuild this node with original path and transformed children
        let tree_str = build_tree_string(
            &path_str.unwrap_or_default(),
            &new_children,
            has_star,
            rename.as_deref()
        );
        vec![tree_str]
    } else {
        // Leaf node, no change needed
        vec![tree.syntax().text().to_string()]
    }
}

fn build_tree_string(path: &str, children: &[String], star: bool, rename: Option<&str>) -> String {
    let main_part = if path.is_empty() {
        // Top-level group
        if children.is_empty() {
            "{}".to_string()
        } else {
            format!("{{{}}}", children.join(", "))
        }
    } else if star {
        format!("{}::*", path)
    } else if !children.is_empty() {
        format!("{}::{{{}}}", path, children.join(", "))
    } else {
        path.to_string()
    };

    if let Some(alias) = rename {
        format!("{} as {}", main_part, alias)
    } else {
        main_part
    }
}
