/// Middleware that checks the Origin header for WebSocket upgrade requests.
/// Non-WebSocket requests pass through without origin checks.
async fn check_websocket_origin(
    req: Request,
    next: Next,
) -> Result<Response, StatusCode> {
    // Check if this is a WebSocket upgrade request by looking for "upgrade: websocket" header
    let is_websocket = req
        .headers()
        .get("upgrade")
        .and_then(|v| v.to_str().ok())
        .map(|v| v.eq_ignore_ascii_case("websocket"))
        .unwrap_or(false);

    if is_websocket {
        match req.headers().get(ORIGIN) {
            Some(origin) => {
                let origin_str = origin.to_str().map_err(|_| {
                    eprintln!("Blocked WebSocket: invalid Origin header encoding");
                    StatusCode::FORBIDDEN
                })?;

                if !ALLOWED_ORIGINS.contains(&origin_str) {
                    eprintln!("Blocked WebSocket from unauthorized origin: {}", origin_str);
                    return Err(StatusCode::FORBIDDEN);
                }

                println!("Accepted WebSocket connection from origin: {}", origin_str);
            }
            None => {
                eprintln!("Blocked WebSocket: missing Origin header");
                return Err(StatusCode::FORBIDDEN);
            }
        }
    }

    // Continue to the next middleware/handler
    Ok(next.run(req).await)
}

/// WebSocket handler - only reached if origin check passes
async fn client_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
) -> impl IntoResponse {
    ws.on_upgrade(move |socket| handle_socket(socket, session_id))
}

async fn handle_socket(mut socket: WebSocket, session_id: String) {
    println!("WebSocket session {} connected", session_id);

    while let Some(Ok(msg)) = socket.recv().await {
        // Echo messages back
        if socket.send(msg).await.is_err() {
            break;
        }
    }

    println!("WebSocket session {} disconnected", session_id);
}

