/// This provides a nice syntax on stable Rust without requiring the user to write Box::pin.
/// 
/// Usage: `async_block!(ctx, { ctx.0 += 1; some_async_op().await; })`
#[macro_export]
macro_rules! async_block {
    ($ctx:ident, $body:expr) => {
        |$ctx| Box::pin(async move { $body }) as Pin<Box<dyn Future<Output = ()> + Send + '_>>
    };
}

/// Sends an async workload to the worker thread.
