/// The `block` argument should be created using the `async_block!` macro for ergonomic syntax.
/// It accepts any closure that implements the required higher-ranked trait bounds.
pub fn with_context_async(
    work_sender: &mut Sender<InnerAsyncEvent>,
    block: impl for<'a> FnOnce(&'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>> + Send + 'static,
) {
    let _ = work_sender.send(InnerAsyncEvent::DoWithContext {
        block: Box::new(block),
    });
}

