    // Spawn worker thread that owns the Context
    let handle = tokio::spawn(async move {
        let mut ctx = Context(0);

        while let Some(event) = rx.recv().await {
            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    // The block is called with the context, producing a future
                    let fut = block(&mut ctx);
                    fut.await;
                    println!("Context value after work: {}", ctx.0);
                }
            }
        }

        ctx
    });

    // Example 1: Simple async work
    let mut tx2 = tx.clone();
    with_context_async(&mut tx2, async_block!(ctx, {
