use futures::StreamExt;
use http_body_util::{BodyExt, Full, StreamBody};
use hyper::body::{Frame, Incoming};
use hyper::server::conn::http1;
use hyper::service::service_fn;
use hyper::{Request, Response, StatusCode};
use std::convert::Infallible;
use std::net::SocketAddr;
use std::path::Path;
use tokio::fs::File;
use tokio::net::TcpListener;
use tokio_util::io::ReaderStream;

// BoxBody lets us erase the specific body type to return a uniform Response type.
type BoxBody = http_body_util::combinators::BoxBody<Bytes, std::io::Error>;

async fn handle(_req: Request<Incoming>) -> Result<Response<BoxBody>, Infallible> {
    let path = Path::new("Cargo.toml");

    match File::open(path).await {
        Ok(file) => {
            // 1. Convert AsyncRead (File) -> Stream of io::Result<Bytes>
            let reader_stream = ReaderStream::new(file);

            // 2. Convert Stream of Bytes -> Stream of Frame<Bytes>
            //    StreamBody expects items to be Result<Frame<D>, E>
            let frame_stream = reader_stream.map(|result| result.map(Frame::data));

            // 3. Wrap in StreamBody and box it to erase the type
            let body = StreamBody::new(frame_stream).boxed();

            Ok(Response::builder()
                .status(StatusCode::OK)
                .header("Content-Type", "text/plain")
                .body(body)
                .unwrap())
        }
        Err(e) => {
            // For errors, create a simple text body.
            // Full uses Infallible as its error type, so we convert it to io::Error.
            let body = Full::new(Bytes::from(format!("File not found: {}", e)))
                .map_err(|e: std::convert::Infallible| match e {})
                .boxed();

            Ok(Response::builder()
                .status(StatusCode::NOT_FOUND)
                .body(body)
                .unwrap())
        }
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    let listener = TcpListener::bind(addr).await?;

    println!("Listening on http://{}", addr);
    println!("Serves 'Cargo.toml' as a streaming example.");
