                    for nested in &meta_list.nested {
                        if let NestedMeta::Meta(Meta::NameValue(nv)) = nested {
                            if nv.path.is_ident("type") {
                                if let Lit::Str(lit) = &nv.lit {
                                    prop_type = Some(lit.value());
                                }
                            } else if nv.path.is_ident("name") {
                                if let Lit::Str(lit) = &nv.lit {
                                    prop_name = Some(lit.value());
                                }
                            }
                        }
                    }
                }
            }
        }

        let prop_name = prop_name.unwrap_or_else(|| field_ident.to_string());
        let prop_type = prop_type.expect(&format!("Missing 'type' for field {}", field_ident));

        // Check if field is Option<T>
        let is_option = quote!(#field_ty).to_string().starts_with("Option");

        let insert_logic = match prop_type.as_str() {
