                    PropertyValue::Title(vec![RichTextObject {
                        annotations: None,
                        data_type: Some(RichTextType::Text),
                        equation: None,
                        mention: None,
                        plain_text: None,
                        href: None,
                        text: TextObject {
                            content: self.#field_ident.clone(),
                            link: None,
                        },
                    }])
                );
            },
            "url" => if is_option {
                quote! {
                    if let Some(val) = self.#field_ident.clone() {
                        map.insert(#prop_name.to_string(), PropertyValue::Url(val));
                    }
                }
            } else {
                quote! {
                    map.insert(#prop_name.to_string(), PropertyValue::Url(self.#field_ident.clone()));
                }
            },
            "MultiSelect" => quote! {
                if let Some(vals) = &self.#field_ident {
                    let selects: Vec<SelectObject> = vals.iter().map(|v| SelectObject {
                        id: None,
                        color: None,
                        name: v.to_string().trim_matches('"').to_string(),
                    }).collect();
                    map.insert(#prop_name.to_string(), PropertyValue::MultiSelect(selects));
                }
            },
            _ => panic!("Unknown notion_property type: {}", prop_type),
        };

        insert_logic
    });

    let expanded = quote! {
        impl IntoNotionProperties for #struct_name {
            fn into_notion_properties(self) -> ::std::collections::HashMap<String, PropertyValue> {
                let mut map = ::std::collections::HashMap::new();
                #(#field_inserts)*
                map
            }
        }
    };

    TokenStream::from(expanded)
}
*/"
