  "main.rs": "fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current = String::new();
    let mut in_quote = false;
    let mut in_token = false;

    for ch in input.chars() {
        match ch {
            '\'' => {
                // Toggle quote state
                in_quote = !in_quote;
                // Quotes mark the presence of a token (even if empty)
                in_token = true;
            }
            ' ' if !in_quote => {
                // Outside quotes, space delimits tokens
                if in_token {
                    tokens.push(std::mem::take(&mut current));
                    in_token = false;
                }
            }
            _ => {
                current.push(ch);
                in_token = true;
            }
        }
    }

    // Handle last token (handles case where string ends without trailing space)
    if in_token {
        tokens.push(current);
    }

    tokens
}

fn main() {
    let input = " one  ' two  'three    four";
    let tokens = tokenize(input);

    println!("Input: {:?}", input);
    println!("Found {} token(s):", tokens.len());
    for token in &tokens {
        println!("  <{}>", token);
    }

    // Verify expected behavior
    assert_eq!(tokens.len(), 3, "Expected exactly 3 tokens");
    assert_eq!(tokens[0], "one", "First token should be 'one'");
    assert_eq!(tokens[1], " two  three", "Second token should preserve internal spaces and concatenate with adjacent unquoted text");
    assert_eq!(tokens[2], "four", "Third token should be 'four'");

    println!("\n✓ All assertions passed!");
}"
}
