fn camera_controller(
    mut camera_query: Query<(&mut Transform, &mut CameraController), With<Camera>>,
    keyboard: Res<ButtonInput<KeyCode>>,
    mut mouse_motion: EventReader<bevy::input::mouse::MouseMotion>,
    time: Res<Time>,
) {
    let (mut transform, mut controller) = camera_query.single_mut();

    // Mouse look
    for motion in mouse_motion.read() {
        controller.yaw -= motion.delta.x * 0.003;
        controller.pitch -= motion.delta.y * 0.003;
        controller.pitch = controller.pitch.clamp(-89_f32.to_radians(), 89_f32.to_radians());
    }

    // Calculate forward/right vectors
    let forward = Vec3::new(
        controller.yaw.cos() * controller.pitch.cos(),
        controller.pitch.sin(),
        controller.yaw.sin() * controller.pitch.cos(),
    )
    .normalize();

    let right = forward.cross(Vec3::Y).normalize();

    // Keyboard movement
    let speed = 5.0 * time.delta_seconds();
    if keyboard.pressed(KeyCode::KeyW) {
        transform.translation += forward * speed;
    }
    if keyboard.pressed(KeyCode::KeyS) {
        transform.translation -= forward * speed;
    }
    if keyboard.pressed(KeyCode::KeyA) {
        transform.translation -= right * speed;
    }
    if keyboard.pressed(KeyCode::KeyD) {
        transform.translation += right * speed;
    }

    transform.look_to(forward, Vec3::Y);
}

fn update_gizmo(
    camera_query: Query<(&Camera, &GlobalTransform)>,
    block_query: Query<&GlobalTransform, With<Block>>,
    rapier_context: Res<RapierContext>,
    mut gizmos: Gizmos,
) {
    let (camera, camera_transform) = camera_query.single();

    // Cast ray from center of screen
    let ray = match camera.viewport_to_world(camera_transform, Vec2::new(0.5, 0.5)) {
        Some(r) => r,
        None => return,
    };

    // Raycast against physics world
    if let Some((entity, intersection)) = rapier_context.cast_ray(
        ray.origin,
        ray.direction,
        100.0,
        true,
        QueryFilter::default(),
    ) {
        // Check if we hit a block
        if let Ok(block_transform) = block_query.get(entity) {
            let block_rot = block_transform.rotation();
            let block_pos = block_transform.translation();
            let hit_normal = intersection.normal; // World space normal

            // Convert world normal to block's local space to identify which face
            let local_normal = block_rot.inverse() * hit_normal;

            // Round to nearest axis to handle floating point errors
            // This gives us one of: (±1,0,0), (0,±1,0), (0,0,±1)
            let local_normal_rounded = Vec3::new(
                local_normal.x.round(),
                local_normal.y.round(),
                local_normal.z.round(),
            ).normalize();

            // Create rotation that aligns the gizmo's Z-axis with the local face normal
            // This orients the gizmo to lie flat against the face in local space
            let local_face_rotation = Quat::from_rotation_arc(Vec3::Z, local_normal_rounded);

            // Combine rotations: 
            // First apply local_face_rotation (align to face), then block_rot (align to world)
            // Quat multiplication order: applying v' = q2 * (q1 * v) is (q2 * q1) * v
            let final_rotation = block_rot * local_face_rotation;

            // Calculate face center (block center + normal * half_extent)
            let face_center = block_pos + hit_normal * 0.5;

            // Draw the placement gizmo slightly offset to avoid z-fighting
            gizmos.rect(
                Isometry3d::new(
                    face_center + hit_normal * 0.02,
                    final_rotation,
                ),
                Vec2::new(1.0, 1.0), // Match cube face size
                Color::WHITE,
            );

            // Optional: Draw normal indicator
            gizmos.arrow(
                face_center,
                face_center + hit_normal * 0.3,
                Color::YELLOW,
            );
        }
    }
}
"
}
