    /// 3. Parallel: Uses rayon to parallelize the O(N^2) distance calculations.
    pub fn build_lists(&mut self) {
        let nelems = self.get_nelems();

        // Clear existing neighbor lists
        for elem in &mut self.elems {
            elem.nb.clear();
