/// Process every usize element in parallel while preserving nested structure.
/// Strategy: Remember sizes -> Flatten -> Parallel map -> Reconstruct
fn process_fully_parallel(nested: Vec<Vec<usize>>) -> Vec<Vec<String>> {
    // Store the length of each inner vector to reconstruct later
    let lengths: Vec<usize> = nested.iter().map(|v| v.len()).collect();

    // Flatten into a single vector (sequential, but O(n))
    let flat: Vec<usize> = nested.into_iter().flatten().collect();

    // Process all elements in parallel (example: convert usize to String)
    // Replace the map closure with your actual function
    let processed: Vec<String> = flat
        .into_par_iter()
        .map(|x| format!("processed_{}", x))
        .collect();

    // Reconstruct the nested structure using the stored lengths
    let mut result = Vec::with_capacity(lengths.len());
    let mut remaining = processed;

    for len in lengths {
        // Efficiently drain the first 'len' elements
        let inner: Vec<String> = remaining.drain(..len).collect();
        result.push(inner);
    }

    result
