  "main.rs": "use serde::{Deserialize, Deserializer, Serialize, Serializer};
use serde::de::{self, MapAccess, Visitor};
use serde::ser::{SerializeSeq, SerializeStruct};
use std::fmt;

#[derive(Debug, PartialEq)]
struct A {
    x: usize,
    b: Vec<B>,
}

#[derive(Debug, PartialEq)]
enum B {
    Text(String),
    Number(i32),
}

// ============== Custom Serializer for B ==============
impl Serialize for B {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        // Serialize B as a map with a single key indicating the variant
        match self {
            B::Text(s) => {
                let mut state = serializer.serialize_struct("B", 1)?;
                state.serialize_field("Text", s)?;
                state.end()
            }
            B::Number(n) => {
                let mut state = serializer.serialize_struct("B", 1)?;
                state.serialize_field("Number", n)?;
                state.end()
            }
        }
    }
}

// ============== Custom Deserializer for B ==============
impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct BVisitor;

        impl<'de> Visitor<'de> for BVisitor {
            type Value = B;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("enum B as a map with single key")
            }

            fn visit_map<V>(self, mut map: V) -> Result<B, V::Error>
            where
                V: MapAccess<'de>,
            {
                // Expecting {"Text": "value"} or {"Number": 42}
                if let Some(key) = map.next_key::<String>()? {
                    match key.as_str() {
                        "Text" => {
                            let value: String = map.next_value()?;
                            Ok(B::Text(value))
                        }
                        "Number" => {
                            let value: i32 = map.next_value()?;
                            Ok(B::Number(value))
                        }
                        _ => Err(de::Error::unknown_field(&key, &["Text", "Number"])),
                    }
                } else {
                    Err(de::Error::custom("empty map for enum B"))
                }
            }
        }

        deserializer.deserialize_map(BVisitor)
    }
}

// ============== Custom Serializer for A ==============
impl Serialize for A {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        let mut state = serializer.serialize_struct("A", 2)?;
        state.serialize_field("x", &self.x)?;
        state.serialize_field("b", &self.b)?;
        state.end()
    }
}

// ============== Custom Deserializer for A ==============
impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct AVisitor;

        impl<'de> Visitor<'de> for AVisitor {
            type Value = A;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("struct A")
            }

            fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut x: Option<usize> = None;
                let mut b: Option<Vec<B>> = None;

                // IMPORTANT: Use String instead of &str to avoid lifetime/runtime errors
                while let Some(key) = map.next_key::<String>()? {
                    match key.as_str() {
                        "x" => {
                            if x.is_some() {
                                return Err(de::Error::duplicate_field("x"));
                            }
                            x = Some(map.next_value()?);
                        }
                        "b" => {
                            if b.is_some() {
                                return Err(de::Error::duplicate_field("b"));
                            }
                            // ANSWER: Simply call next_value with Vec<B>
                            // This automatically uses the custom deserializer for B
                            b = Some(map.next_value::<Vec<B>>()?);
                        }
                        _ => {
                            // Skip unknown fields
                            let _: de::IgnoredAny = map.next_value()?;
                        }
                    }
                }

                let x = x.ok_or_else(|| de::Error::missing_field("x"))?;
                let b = b.ok_or_else(|| de::Error::missing_field("b"))?;

                Ok(A { x, b })
            }
        }

        deserializer.deserialize_struct("A", &["x", "b"], AVisitor)
    }
}

fn main() {
    // Create test data
    let a = A {
        x: 42,
        b: vec![
            B::Text("hello".to_string()),
            B::Number(123),
            B::Text("world".to_string()),
        ],
    };

    // Serialize to JSON
    let json = serde_json::to_string_pretty(&a).unwrap();
    println!("Serialized:");
    println!("{}", json);
    println!();

    // Deserialize back
    let deserialized: A = serde_json::from_str(&json).unwrap();
    println!("Deserialized: {:?}", deserialized);
    println!();

    // Verify roundtrip
    assert_eq!(a, deserialized);
    println!("✓ Roundtrip successful!");

    // Also test with raw JSON input
    let raw_json = r#"{"x": 100, "b": [{"Text": "nested"}, {"Number": 999}]}"#;
    let parsed: A = serde_json::from_str(raw_json).unwrap();
    println!("\nParsed from raw JSON: {:?}", parsed);
}
"
