fn deserialize_path_list<'de, D>(deserializer: D) -> Result<Vec<PathBuf>, D::Error>
where
    D: Deserializer<'de>,
{
    struct PathListVisitor;

    impl<'de> de::Visitor<'de> for PathListVisitor {
        type Value = Vec<PathBuf>;

        fn expecting(&self, formatter: &mut std::fmt::Formatter) -> std::fmt::Result {
            formatter.write_str("an array of paths or a $ref object like {\"$ref\": \"file.json#/pointer\"}")
        }

        fn visit_seq<A>(self, seq: A) -> Result<Self::Value, A::Error>
        where
            A: de::SeqAccess<'de>,
        {
            Vec::<PathBuf>::deserialize(de::value::SeqAccessDeserializer::new(seq))
        }

        fn visit_map<M>(self, map: M) -> Result<Self::Value, M::Error>
        where
            M: de::MapAccess<'de>,
        {
            let content = serde_json::Map::<String, serde_json::Value>::deserialize(
                de::value::MapAccessDeserializer::new(map)
            )?;

            match content.get("$ref") {
                Some(serde_json::Value::String(ref_str)) => {
                    resolve_reference(ref_str).map_err(de::Error::custom)
                }
                _ => Err(de::Error::custom("expected $ref field with string value")),
            }
        }
    }

    deserializer.deserialize_any(PathListVisitor)
}

fn resolve_reference(ref_str: &str) -> Result<Vec<PathBuf>, String> {
    // Split "./a.json#/p_list" into "./a.json" and "/p_list"
    let (file_path, pointer) = match ref_str.find('#') {
        Some(idx) => (&ref_str[..idx], &ref_str[idx..]),
        None => (ref_str, ""),
    };

    let content = fs::read_to_string(file_path)
        .map_err(|e| format!("Failed to read '{}': {}", file_path, e))?;

    let json: serde_json::Value = serde_json::from_str(&content)
        .map_err(|e| format!("Invalid JSON in '{}': {}", file_path, e))?;

    // Navigate JSON pointer (e.g., "/p_list" -> json["p_list"])
    let target = if pointer.is_empty() || pointer == "/" {
        json
    } else {
        let path = &pointer[1..]; // Remove leading '/'
        let mut current = &json;
        for segment in path.split('/') {
            current = current
                .get(segment)
                .ok_or_else(|| format!("Pointer '{}' not found in '{}'", pointer, file_path))?;
        }
        current.clone()
    };

    serde_json::from_value(target)
        .map_err(|e| format!("Type mismatch in referenced data: {}", e))
}

