/// Download all blobs for a specific prefix with controlled concurrency
/// Pipelines listing and downloading for optimal throughput
async fn download_prefix(
    container: Arc<ContainerClient>,
    prefix: String,
    concurrency: usize,
) -> Result<Vec<TradeData>> {
    let sem = Arc::new(Semaphore::new(concurrency));

    // Create a stream that continuously lists blobs while concurrently downloading
    // This avoids the "page stall" where you wait for all downloads in a page before listing the next
    let download_stream = container
        .clone()
        .list_blobs()
        .prefix(prefix)
        .into_stream()
        .map_ok(|page| {
            // Convert each page into a stream of individual blob items
            stream::iter(page.blobs.blobs().cloned().map(Ok::<_, AzureError>))
        })
        .try_flatten() // Flatten pages into a single continuous stream of blobs
        .try_filter_map(|blob| {
            // Only process .json files
            if blob.name.ends_with(".json") {
                futures::future::ready(Ok(Some(blob)))
            } else {
                futures::future::ready(Ok(None))
            }
        })
        .map_ok(|blob| {
            let container = Arc::clone(&container);
            let sem = Arc::clone(&sem);

            async move {
