  "main.rs": "//! Demonstration of replacing atomic-polyfill::AtomicUsize::fetch_add 
//! with critical_section on thumbv6m-none-eabi

use std::sync::atomic::Ordering;
use critical_section::Mutex;
use core::cell::Cell;

/// AtomicUsize implementation for thumbv6m using critical_section
/// 
/// On thumbv6m-none-eabi, core::sync::atomic::AtomicUsize is unavailable,
/// so we implement the functionality using Mutex<Cell<usize>>.
pub struct AtomicUsize {
    inner: Mutex<Cell<usize>>,
}

impl AtomicUsize {
    pub const fn new(val: usize) -> Self {
        Self {
            inner: Mutex::new(Cell::new(val)),
        }
    }

    /// Replacement for fetch_add using critical_section
    /// 
    /// CORRECT ORDERING: Ordering::Relaxed
    /// 
    /// Why Relaxed is correct:
    /// 1. The critical_section::with() provides mutual exclusion, ensuring atomicity
    ///    (no other thread/core can access the value during the operation)
    /// 
    /// 2. The critical section acts as a compiler barrier - the compiler cannot 
    ///    reorder memory accesses from outside the critical section to inside it,
    ///    or vice versa. This provides stronger guarantees than any atomic ordering.
    /// 
    /// 3. Since the original fetch_add used Relaxed, we maintain the same semantics.
    ///    Using SeqCst, Acquire, or Release would be unnecessary pessimization.
    /// 
    /// 4. Inside the critical section, there are no concurrent observers, so 
    ///    relaxed ordering is sufficient for the load and store operations.
    pub fn fetch_add(&self, val: usize, _ordering: Ordering) -> usize {
        critical_section::with(|cs| {
            // Even though Cell doesn't use Ordering, if this were an atomic type,
            // you would use Ordering::Relaxed here:
            let old_val = self.inner.borrow(cs).get();
            self.inner.borrow(cs).set(old_val.wrapping_add(val));
            old_val
        })
    }
}

fn main() {
    // Example: Simulating the original code pattern
    static CHANNEL_INDEX: AtomicUsize = AtomicUsize::new(0);

    // Original code was:
    // let index = self.channel_index.fetch_add(1, Ordering::Relaxed);
    let index = CHANNEL_INDEX.fetch_add(1, Ordering::Relaxed);

    println!("Got index: {}", index);
    println!("Next index would be: {}", CHANNEL_INDEX.fetch_add(1, Ordering::Relaxed));

    println!("\nKey point: Use Ordering::Relaxed because the critical_section");
    println!("provides all necessary synchronization. Stronger orderings are");
    println!("redundant and may hurt performance.");
}"
}
