/// Owns the broadcast sender. When this is dropped (or shutdown is called),
/// the channel closes and all BroadcastStreams will end.
pub struct EventBus {
    tx: Arc<Sender<Event>>,
}

impl EventBus {
    pub fn new(capacity: usize) -> (Self, EventSender, EventStreamFactory) {
        let (tx, _) = broadcast::channel(capacity);
        let tx = Arc::new(tx);

        let sender = EventSender {
            tx: Arc::downgrade(&tx),
        };

        let factory = EventStreamFactory {
            tx: Arc::downgrade(&tx),
        };

        (Self { tx }, sender, factory)
    }

    /// Explicitly drop the sender to close the channel
    pub fn shutdown(self) {
        drop(self.tx);
    }
}

/// Cheaply cloneable handle for sending events.
/// Uses Weak reference so that dropping the EventBus closes the channel
/// even if many EventSenders still exist.
#[derive(Clone, Debug)]
pub struct EventSender {
    tx: Weak<Sender<Event>>,
}

impl EventSender {
    pub fn send(&self, event: Event) -> Result<(), Event> {
