    /// returns an empty stream that resolves immediately.
    pub fn all_events(&self) -> impl Stream<Item = Result<Event, tokio_stream::wrappers::BroadcastStreamRecvError>> + Send + use<> {
        if let Some(tx) = self.tx.upgrade() {
            let rx = tx.subscribe();
            Either::Left(BroadcastStream::new(rx))
        } else {
            Either::Right(stream::iter(vec![]))
        }
    }
}

