        async move {
            let mut id = 1000;
            loop {
                id += 1;
                if sender.send(Event { 
                    id, 
                    data: format!("Producer-2 Event {}", id) 
                }).is_err() {
                    println!("Producer 2: Channel closed, stopping.");
                    break;
                }
                tokio::time::sleep(tokio::time::Duration::from_secs(2)).await;
            }
        }
    });

    // Simulate SSE consumer
    let consumer = tokio::spawn(async move {
        let mut stream = factory.all_events();
