        }
        println!("Consumer: Stream ended gracefully.");
    });

    println!("Service running. Press Ctrl+C to shutdown gracefully...");

    // Wait for interrupt
    signal::ctrl_c().await.expect("Failed to listen for ctrl+c");
    println!("\nShutdown signal received.");

    // Drop the bus to close the broadcast channel.
    // This causes all Weak references to become invalid.
    // The Sender is dropped, closing the channel.
    // All BroadcastStreams will end (return None on next poll).
    drop(bus);
