    let drag_state = use_context::<DragState>();

    // Local state for this specific point
    let position = use_signal(|| (props.initial_x, props.initial_y));
    let is_dragged = use_signal(|| false);
    let drag_offset = use_signal(|| (0.0, 0.0));

