/// Creates a demo archive file at assets/demo.archive
/// Format: [MAGIC:4][VERSION:4][ENTRY_COUNT:4][ENTRIES...][DATA...]
/// Entry: [NAME_LEN:4][NAME:bytes][OFFSET:8][SIZE:8]
fn create_demo_archive() {
    let assets_dir = env::current_dir().unwrap().join("assets");
    std::fs::create_dir_all(&assets_dir).ok();

    let archive_path = assets_dir.join("demo.archive");
    let mut file = File::create(&archive_path).expect("Failed to create archive");

    // Prepare dummy data (simulating 3 textures)
    let entries = vec![
        ("texture1.txt", b"This is texture 1 content from archive".to_vec()),
        ("texture2.txt", b"This is texture 2 content from archive".to_vec()),
        ("texture3_heavy.txt", vec![b'X'; 1024 * 1024]), // 1MB of data to prove lazy loading
    ];

    // Write header
    file.write_all(b"LAZY").unwrap(); // Magic
    file.write_all(&1u32.to_le_bytes()).unwrap(); // Version
    file.write_all(&(entries.len() as u32).to_le_bytes()).unwrap(); // Entry count

    // Calculate header size to know where data starts
    let header_size = 4 + 4 + 4 + entries.iter().map(|(n, _)| {
        4 + n.len() + 8 + 8 // name_len + name + offset + size
    }).sum::<usize>();

    // Write entry table
    let mut current_offset = header_size as u64;
    for (name, data) in &entries {
        let name_bytes = name.as_bytes();
        file.write_all(&(name_bytes.len() as u32).to_le_bytes()).unwrap();
        file.write_all(name_bytes).unwrap();
        file.write_all(&current_offset.to_le_bytes()).unwrap();
        file.write_all(&(data.len() as u64).to_le_bytes()).unwrap();
        current_offset += data.len() as u64;
    }

    // Write data
    for (_, data) in &entries {
        file.write_all(data).unwrap();
    }

    println!("Created demo archive at: {:?}", archive_path);
    println!("Contains: texture1.txt, texture2.txt, texture3_heavy.txt (1MB)");
}

// ============================================================================
