/// AssetReader that reads individual entries from our custom archive format.
/// This only loads the index (file table) into memory, not the actual asset data.
struct LazyArchiveReader {
    archive_path: PathBuf,
    /// Maps filename -> (offset_in_file, size)
    index: HashMap<String, (u64, u64)>,
}

impl LazyArchiveReader {
    fn new(archive_path: PathBuf) -> Self {
        // Load only the index, not the data
        let mut file = File::open(&archive_path).expect("Archive not found");
        let mut index = HashMap::new();

        // Read header
        let mut magic = [0u8; 4];
        file.read_exact(&mut magic).expect("Invalid archive");
        assert_eq!(&magic, b"LAZY", "Invalid magic");

        let mut buf = [0u8; 4];
        file.read_exact(&mut buf).unwrap();
        let _version = u32::from_le_bytes(buf);

        file.read_exact(&mut buf).unwrap();
        let count = u32::from_le_bytes(buf) as usize;

        // Read entry table
        for _ in 0..count {
            let mut name_len_buf = [0u8; 4];
            file.read_exact(&mut name_len_buf).unwrap();
            let name_len = u32::from_le_bytes(name_len_buf) as usize;

            let mut name_buf = vec![0u8; name_len];
            file.read_exact(&mut name_buf).unwrap();
            let name = String::from_utf8(name_buf).unwrap();

            let mut offset_buf = [0u8; 8];
            file.read_exact(&mut offset_buf).unwrap();
            let offset = u64::from_le_bytes(offset_buf);

            let mut size_buf = [0u8; 8];
            file.read_exact(&mut size_buf).unwrap();
            let size = u64::from_le_bytes(size_buf);

            index.insert(name, (offset, size));
        }

        println!("LazyArchiveReader initialized with {} entries", index.len());
        Self { archive_path, index }
    }
}

