        let mut buffer = vec![0u8; *size as usize];
        file.read_exact(&mut buffer).map_err(AssetReaderError::Io)?;

        println!("Lazy loaded '{}' ({} bytes) from archive", filename, size);

        // VecReader implements AsyncRead + AsyncSeek
        Ok(VecReader::new(buffer))
    }

