//! 
//! Uses platform-specific SIMD when available:
//! - x86_64 with AVX2: 256-bit vector permutation (1 load, 1 permute, 1 store)
//! - x86_64 with SSE2: Two 128-bit shuffles (2 loads, 2 shuffles, 2 stores)
//! - AArch64 with NEON: Vector reversal and swap
//! - Fallback: Unrolled u32 swaps (8 loads, 8 stores, fully pipelined)

const PIXELS_PER_SIDE: usize = 8;
const PIXELS_PER_LINE: usize = PIXELS_PER_SIDE;
const BYTES_PER_PIXEL: usize = 4;

/// Flip a single line of 8 4-byte pixels horizontally.
/// 
/// # Panics
/// Panics in debug mode if the slice length is not exactly 32 bytes.
#[inline]
pub fn flip_line(line_bytes: &mut [u8]) {
    debug_assert_eq!(
        line_bytes.len(),
        BYTES_PER_PIXEL * PIXELS_PER_LINE,
        "Line must be exactly 32 bytes (8 pixels × 4 bytes)"
    );

    // Platform-specific SIMD implementations
    #[cfg(all(target_arch = "x86_64", target_feature = "avx2"))]
    unsafe {
        return flip_line_avx2(line_bytes);
    }

    #[cfg(all(target_arch = "x86_64", target_feature = "sse2", not(target_feature = "avx2")))]
    unsafe {
        return flip_line_sse2(line_bytes);
    }

    #[cfg(all(target_arch = "aarch64", target_feature = "neon"))]
    unsafe {
        return flip_line_neon(line_bytes);
    }

    // Fast portable fallback using unaligned u32 operations
    // This is optimal for embedded systems without SIMD or when alignment is unknown
    unsafe {
        let ptr = line_bytes.as_mut_ptr() as *mut u32;

        // Load all 8 pixels into registers (allowing unaligned access)
        let p0 = ptr.add(0).read_unaligned();
        let p1 = ptr.add(1).read_unaligned();
        let p2 = ptr.add(2).read_unaligned();
        let p3 = ptr.add(3).read_unaligned();
        let p4 = ptr.add(4).read_unaligned();
        let p5 = ptr.add(5).read_unaligned();
        let p6 = ptr.add(6).read_unaligned();
        let p7 = ptr.add(7).read_unaligned();

        // Write back in reverse order
        ptr.add(0).write_unaligned(p7);
        ptr.add(1).write_unaligned(p6);
        ptr.add(2).write_unaligned(p5);
        ptr.add(3).write_unaligned(p4);
        ptr.add(4).write_unaligned(p3);
        ptr.add(5).write_unaligned(p2);
        ptr.add(6).write_unaligned(p1);
        ptr.add(7).write_unaligned(p0);
    }
