#[cfg(all(target_arch = "x86_64", target_feature = "avx2"))]
unsafe fn flip_line_avx2(line_bytes: &mut [u8]) {
    use std::arch::x86_64::*;

    // Load 32 bytes (8 pixels) into one 256-bit register
    let vec = _mm256_loadu_si256(line_bytes.as_ptr() as *const __m256i);

    // Permute to reverse order of 8 32-bit lanes
    // Indices: 7, 6, 5, 4, 3, 2, 1, 0
    let idx = _mm256_setr_epi32(7, 6, 5, 4, 3, 2, 1, 0);
    let reversed = _mm256_permutevar8x32_epi32(vec, idx);

    // Store back
    _mm256_storeu_si256(line_bytes.as_mut_ptr() as *mut __m256i, reversed);
}

#[cfg(all(target_arch = "x86_64", target_feature = "sse2"))]
unsafe fn flip_line_sse2(line_bytes: &mut [u8]) {
    use std::arch::x86_64::*;

    // Load two 16-byte halves
    let low = _mm_loadu_si128(line_bytes.as_ptr() as *const __m128i);
    let high = _mm_loadu_si128(line_bytes.as_ptr().add(16) as *const __m128i);

    // Shuffle to reverse 4 32-bit integers within each half
    // 0x1B = 00 01 10 11 (binary) = lanes 3, 2, 1, 0
    let low_rev = _mm_shuffle_epi32(low, 0x1B);
    let high_rev = _mm_shuffle_epi32(high, 0x1B);

    // Store swapped halves
    _mm_storeu_si128(line_bytes.as_mut_ptr() as *mut __m128i, high_rev);
    _mm_storeu_si128(line_bytes.as_mut_ptr().add(16) as *mut __m128i, low_rev);
}

#[cfg(all(target_arch = "aarch64", target_feature = "neon"))]
unsafe fn flip_line_neon(line_bytes: &mut [u8]) {
    use std::arch::aarch64::*;

    // Load two 16-byte halves (4 pixels each)
    let v0 = vld1q_u32(line_bytes.as_ptr() as *const u32);
    let v1 = vld1q_u32(line_bytes.as_ptr().add(16) as *const u32);

    // Reverse each 128-bit vector:
    // [A,B,C,D] -> combine([C,D], [A,B]) = [C,D,A,B] -> vrev64q = [D,C,B,A]
    let v0r = vrev64q_u32(vcombine_u32(vget_high_u32(v0), vget_low_u32(v0)));
    let v1r = vrev64q_u32(vcombine_u32(vget_high_u32(v1), vget_low_u32(v1)));

    // Store swapped (reversed v1 goes to front, reversed v0 goes to back)
    vst1q_u32(line_bytes.as_mut_ptr() as *mut u32, v1r);
    vst1q_u32(line_bytes.as_mut_ptr().add(16) as *mut u32, v0r);
