  "main.rs": "use async_trait::async_trait;
use std::sync::Arc;
use std::time::Duration;
use tracing::{info, info_span, Instrument, Span};

/// Context that travels with the request through all lifecycle stages.
/// This is the key structure that holds the parent span for rehydration.
#[derive(Clone)]
struct RequestContext {
    /// Store the parent span handle. This is Send + Sync and can be cloned
    /// into different async tasks or threads.
    parent_span: Span,
}

/// Simulates Pingora's proxy hooks trait where different stages
/// are called asynchronously and potentially on different threads.
#[async_trait]
trait ProxyHooks {
    async fn request_filter(&self, ctx: RequestContext);
    async fn upstream_peer(&self, ctx: RequestContext);
    async fn logging(&self, ctx: RequestContext);
}

struct MyProxy;

#[async_trait]
impl ProxyHooks for MyProxy {
    async fn request_filter(&self, ctx: RequestContext) {
        // Method 1: Rehydrate the parent span by entering it.
        // The _guard ensures the span is exited when dropped.
        // Note: In async functions, avoid holding guards across await points
        // if you need precise span timing, but for context propagation this is fine.
        let _parent_guard = ctx.parent_span.enter();

        // Now create the Stage 1 span. Because we entered the parent,
        // this span automatically becomes a child of the parent.
        let stage_span = info_span!("Stage 1");
        let _stage_guard = stage_span.enter();

        info!("Processing request filter");

        // Simulate async work
        tokio::time::sleep(Duration::from_millis(50)).await;

        // Guards drop here, exiting spans
    }

    async fn upstream_peer(&self, ctx: RequestContext) {
        // Method 2: Using Instrument trait (safer for async boundaries).
        // This explicitly sets the parent for the async block.
        let parent = ctx.parent_span.clone();
        let stage_span = info_span!(parent: parent, "Stage 2");

        async {
            info!("Selecting upstream peer");
            tokio::time::sleep(Duration::from_millis(50)).await;

            // Demonstrate that Span::current() correctly resolves to Stage 2
            let current = Span::current();
            info!(?current, "Current span inside Stage 2");
        }
