fn spawn_signal_handler(sender: Sender<Message>) -> (JoinHandle<()>, Arc<Waker>) {
    let (waker_tx, waker_rx) = std::sync::mpsc::channel();

    let handle = thread::spawn(move || {
        let mut poll = Poll::new().expect("Failed to create Poll");

