    // Method 2: Using column iteration (efficient, no temporary allocations)
    let mut centered_2 = matrix.clone();
    for (mut col, &mean) in centered_2.column_iter_mut().zip(column_means.iter()) {
        col.iter_mut().for_each(|x| *x -= mean);
