/// Agent handle that splits the PTY into independent read/write halves.
/// The reader thread owns the `Session` (blocking read).
/// The writer handle is a dup'd file descriptor protected by a Mutex.
pub struct Agent {
    writer: Arc<Mutex<std::fs::File>>,
    pid: u32,
