impl Agent {
    /// Spawns the command in a PTY and starts a background thread to forward
    /// output to the Tauri frontend via events.
    pub fn new(app: AppHandle, command: &str) -> Result<Self, String> {
        // 1. Spawn the PTY session (blocking I/O)
        let mut session: Session = expectrl::spawn(command)
            .map_err(|e| format!("Failed to spawn '{}': {}", command, e))?;

        // 2. Get the raw FD from the session's underlying PTY stream
        let raw_fd = session.get_stream().as_raw_fd();

        // 3. Duplicate the FD so we can write without contending with the reader's lock.
        // SAFETY: dup() is safe here because raw_fd is a valid open PTY master.
        let write_fd = unsafe { libc::dup(raw_fd) };
        if write_fd == -1 {
            return Err("Failed to dup PTY fd".into());
        }

        // 4. Create a File from the dup'd FD for the writer side.
        //    This File is Send + Sync and can be locked independently.
        let write_file = unsafe { std::fs::File::from_raw_fd(write_fd) };
        let writer = Arc::new(Mutex::new(write_file));

        // 5. Capture PID so we can terminate the process later if needed.
        let pid = session.process().pid() as u32;

        // 6. Spawn the reader thread. It takes ownership of `session`.
        //    It blocks on `read()` but does NOT hold any mutex that would block writes.
        thread::spawn(move || {
            let mut buf = [0u8; 1024];
            loop {
