                    Err(e) => {
                        let _ = app.emit("agent-output", format!("[read error: {}]\r\n", e));
                        break;
                    }
                }
            }
            // When this scope ends, `session` is dropped, closing the original FD.
        });

        Ok(Self { writer, pid })
    }

    /// Send bytes to the PTY. This acquires a lock only on the writer FD,
    /// allowing the reader thread to block on `read()` without interference.
    pub fn send(&self, data: &str) -> Result<(), String> {
        let mut guard = self.writer.lock().map_err(|_| "Writer mutex poisoned")?;
        guard
            .write_all(data.as_bytes())
            .map_err(|e| format!("Write failed: {}", e))?;
        guard
            .flush()
            .map_err(|e| format!("Flush failed: {}", e))?;
        Ok(())
    }

    /// Send a signal to terminate the process (optional cleanup).
    pub fn kill(&self) {
        unsafe {
            libc::kill(self.pid as i32, libc::SIGTERM);
        }
    }
