use std::pin::Pin;
use std::task::{Context, Poll, RawWaker, RawWakerVTable, Waker};

enum TryPollResult<T, F> {
    Ready(T),
    Pending(F),
}

/// Attempts to poll a future once with a no-op waker.
/// 
/// If the future completes immediately (Ready), returns the value.
/// If the future yields (Pending), returns the pinned future (boxed) 
/// so it can be spawned in a tokio task or polled again later.
fn try_poll<F, T>(future: F) -> TryPollResult<T, Pin<Box<F>>>
where
    F: Future<Output = T>,
{
    let mut pinned = Box::pin(future);
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);

    match pinned.as_mut().poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending(pinned),
    }
}

/// Creates a no-op waker suitable for one-shot polling.
/// This waker does nothing when woken, making it safe to discard
/// if the future is going to be spawned elsewhere.
fn noop_waker() -> Waker {
    const VTABLE: RawWakerVTable = RawWakerVTable::new(
        |_| noop_raw_waker(), // clone
        |_| {},               // wake
        |_| {},               // wake_by_ref
        |_| {},               // drop
    );

    fn noop_raw_waker() -> RawWaker {
        RawWaker::new(std::ptr::null(), &VTABLE)
    }

    unsafe { Waker::from_raw(noop_raw_waker()) }
}

// Example usage demonstrating the pattern
#[tokio::main]
async fn main() {
    println!("=== Test 1: Immediately ready future ===");
    let fut = async { 42 };

    match try_poll(fut) {
        TryPollResult::Ready(val) => {
            println!("Ready immediately: {}", val);
        }
        TryPollResult::Pending(fut) => {
            println!("Pending (unexpected for this future), spawning...");
            tokio::spawn(async move {
                println!("Spawned result: {}", fut.await);
            });
        }
    }

    println!("\n=== Test 2: Future that yields (pending) ===");
    let fut = async {
        tokio::task::yield_now().await;
        "completed after yield"
    };

    match try_poll(fut) {
        TryPollResult::Ready(val) => {
            println!("Ready immediately: {}", val);
        }
        TryPollResult::Pending(fut) => {
            println!("Pending, spawning in tokio task...");
            tokio::spawn(async move {
                println!("Spawned task result: {}", fut.await);
            });
        }
    }

    // Allow time for spawned tasks to complete
    tokio::time::sleep(std::time::Duration::from_millis(50)).await;
}
