{
  "Cargo.toml": "[package]
name = "enum_dispatch_solution"
version = "0.1.0"
edition = "2021"

# In a real project, you would have three separate crates:
# [dependencies]
# al = { path = "../al" }
# il = { path = "../il" }
",
  "main.rs": "//! Solution: Avoid `enum_dispatch` cross-crate limitation using a declarative macro.
//! 
//! Architecture:
//! - `al` (Abstract Layer): Defines `Rest` trait and a macro `define_rest_enum!` 
//!   that generates the enum + trait implementation.
//! - `il` (Implementation Layer): Defines `Foo` and `Boo`, implements `Rest`.
//! - `bl` (Business Layer): Uses the macro from `al` to create the enum locally,
//!   wiring together variants from `il`. This satisfies orphan rules because the
//!   `impl Rest for Enum` is generated in `bl` (same crate as the enum).

// ============================================================================
// Abstract Layer (al) - Would be its own crate
// ============================================================================
pub mod al {
    /// Trait with many methods (simulating 20 methods with 3 for brevity)
    pub trait Rest {
        fn method1(&self) -> String;
        fn method2(&self) -> i32;
        fn method3(&self) -> bool;
        // ... imagine 17 more methods here
    }

    /// This macro generates:
    /// 1. The enum definition with given variants
    /// 2. A manual `impl Rest for Enum` delegating all methods to variants
    /// 
    /// Since the macro is invoked in `bl`, the generated code lives in `bl`,
    /// avoiding the "trait and enum must be in same crate" limitation of
    /// enum_dispatch.
    #[macro_export]
    macro_rules! define_rest_enum {
        ($enum_name:ident, { $($variant:ident($type:ty)),+ $(,)? }) => {
            pub enum $enum_name {
                $($variant($type)),+
            }

            impl $crate::al::Rest for $enum_name {
                fn method1(&self) -> String {
                    match self {
                        $(Self::$variant(inner) => inner.method1()),+
                    }
                }

                fn method2(&self) -> i32 {
                    match self {
                        $(Self::$variant(inner) => inner.method2()),+
                    }
                }

                fn method3(&self) -> bool {
                    match self {
                        $(Self::$variant(inner) => inner.method3()),+
                    }
                }
                // ... delegate remaining 17 methods similarly
            }
        };
    }
}

// ============================================================================
// Implementation Layer (il) - Would be its own crate depending on `al`
// ============================================================================
pub mod il {
    use super::al::Rest;

    pub struct Foo {
        pub id: u32,
    }

    impl Rest for Foo {
        fn method1(&self) -> String { format!("Foo(id={})", self.id) }
        fn method2(&self) -> i32 { self.id as i32 * 10 }
        fn method3(&self) -> bool { self.id > 0 }
    }

    pub struct Boo {
        pub name: String,
    }

    impl Rest for Boo {
        fn method1(&self) -> String { format!("Boo(name={})", self.name) }
        fn method2(&self) -> i32 { self.name.len() as i32 }
        fn method3(&self) -> bool { self.name.is_empty() }
    }
}

// ============================================================================
// Business Layer (bl) - Would be its own crate depending on both `al` and `il`
// ============================================================================
fn main() {
    // Invoke the macro from `al` to generate `Item` enum locally.
    // This effectively achieves what enum_dispatch does, but works across crates.
    al::define_rest_enum!(Item, {
        Foo(il::Foo),
        Boo(il::Boo)
    });

    // Static dispatch: No Box<dyn Rest>, no vtable lookups
    let items: Vec<Item> = vec![
        Item::Foo(il::Foo { id: 42 }),
        Item::Boo(il::Boo { name: "StaticDispatch".to_string() }),
    ];

    println!("Demonstrating static dispatch across architectural layers:\n");

    for item in &items {
        // Direct method calls on the enum - monomorphized at compile time
        println!("{:<20} | method2: {:<3} | method3: {}", 
            item.method1(), 
            item.method2(), 
            item.method3()
        );
    }

    println!("\nSuccess! The enum and trait implementation were generated in `bl` via macro,");
    println!("avoiding the cyclic dependency while maintaining zero-cost abstraction.");
}
"
}
