fn extract_econtent_manual(content_any: &der::AnyRef) -> Result<Option<Vec<u8>>, Box<dyn std::error::Error>> {
    use der::{AnyRef, Reader, Tag, Tagged};

    let mut reader = SliceReader::new(content_any.as_bytes())?;

    // Read SEQUENCE header for SignedData
    let seq_tag = reader.context_specific::<AnyRef>(None, der::TagMode::Explicit)?;
    if seq_tag.tag() != Tag::Sequence {
