    let mut sd_reader = SliceReader::new(seq_tag.value())?;

    // Skip version (INTEGER)
    sd_reader.read::<der::AnyRef>()?;

    // Skip digestAlgorithms (SET)
    sd_reader.read::<der::AnyRef>()?;

    // Read encapContentInfo (SEQUENCE)
    let encap_tag = sd_reader.read::<der::AnyRef>()?;
    let mut encap_reader = SliceReader::new(encap_tag.value())?;

    // Read eContentType (OID)
    let _oid = encap_reader.read::<der::AnyRef>()?;

    // Read eContent [0] EXPLICIT OCTET STRING
    // Context-specific [0] constructed
    if let Ok(cs_tag) = encap_reader.context_specific::<AnyRef>(0u8.into(), der::TagMode::Explicit) {
