/// State holding allowed origins for WebSocket connections
#[derive(Clone)]
struct AllowedOrigins(Arc<Vec<String>>);

/// Middleware that checks the Origin header against allowed origins
/// Apply this to WebSocket routes to enforce origin validation (since CORS doesn't apply to WSS)
async fn check_origin(
    State(allowed): State<AllowedOrigins>,
    request: Request,
    next: Next,
) -> Result<Response, StatusCode> {
    // Require Origin header for WebSocket connections
    match request.headers().get(header::ORIGIN) {
        Some(origin) => {
            let origin_str = origin.to_str().unwrap_or_default();
            if allowed.0.iter().any(|allowed| allowed == origin_str) {
