            } else {
                eprintln!("Rejected WebSocket from origin: {}", origin_str);
                Err(StatusCode::FORBIDDEN)
            }
        }
        None => {
            // Reject if no origin header present (browsers always send Origin for WS)
            eprintln!("Rejected WebSocket: no origin header");
            Err(StatusCode::FORBIDDEN)
        }
    }
}

/// WebSocket handler - only reachable if origin check passes
async fn ws_handler(ws: WebSocketUpgrade) -> impl axum::response::IntoResponse {
    ws.on_upgrade(handle_socket)
}

async fn handle_socket(mut socket: WebSocket) {
    println!("WebSocket connection established");

    while let Some(Ok(msg)) = socket.next().await {
        if let axum::extract::ws::Message::Text(text) = msg {
            let reply = format!("Echo (validated origin): {}", text);
            if socket.send(axum::extract::ws::Message::Text(reply)).await.is_err() {
                break;
            }
        }
    }

