        .route("/ws", get(ws_handler))
        .route_layer(from_fn(check_origin))
        // Regular HTTP routes (CORS applies here)
        .route("/api", get(api_handler))
        // Global CORS layer for HTTP requests (doesn't affect WebSocket upgrades)
