use tokio::sync::broadcast::{self, Sender};
use tokio_stream::wrappers::BroadcastStream;
use tokio_stream::{Stream, StreamExt};

#[derive(Debug, Clone)]
struct Event {
    id: u64,
    data: String,
}

#[derive(Debug)]
enum RecvError {
    Lagged(u64),
    Closed,
}

/// Central controller that holds the sender in an Option inside an Arc<Mutex<>>.
/// When shutdown is called, it takes the Sender out and drops it, closing the channel.
pub struct EventChannel {
    inner: Arc<Mutex<Option<Sender<Event>>>>,
}

impl EventChannel {
    pub fn new(capacity: usize) -> (Self, EventSender, EventStreamFactory) {
        let (tx, _) = broadcast::channel(capacity);
        let inner = Arc::new(Mutex::new(Some(tx)));
        (
            Self { inner: inner.clone() },
            EventSender { inner: inner.clone() },
            EventStreamFactory { inner },
        )
    }

    /// Drops the internal sender, causing all receivers to see RecvError::Closed
    /// once the buffer is exhausted. This effectively shuts down all BroadcastStreams.
    pub fn shutdown(&self) {
        let mut lock = self.inner.lock().unwrap();
        if lock.take().is_some() {
            println!("[Shutdown] Sender dropped, channel closed");
        }
    }
}

/// Cloneable sender that shares the same Arc. When the central channel shuts down,
/// all clones will fail to send.
#[derive(Clone)]
pub struct EventSender {
    inner: Arc<Mutex<Option<Sender<Event>>>>,
}

impl EventSender {
    pub fn send(&self, event: Event) -> Result<(), Event> {
        let lock = self.inner.lock().unwrap();
        match lock.as_ref() {
            Some(tx) => tx.send(event).map_err(|e| e.0),
            None => {
                println!("[EventSender] Attempted to send on closed channel");
                Err(event)
            }
        }
    }
}

pub struct EventStreamFactory {
    inner: Arc<Mutex<Option<Sender<Event>>>>,
}

impl EventStreamFactory {
    pub fn create_stream(&self) -> impl Stream<Item = Result<Event, RecvError>> + Send + 'static {
        let rx = {
            let lock = self.inner.lock().unwrap();
            match lock.as_ref() {
                Some(tx) => tx.subscribe(),
                None => {
