/// Flattens the nested vector, processes elements in parallel, then restores structure
fn process_parallel_nested(nested: Vec<Vec<usize>>) -> Vec<Vec<String>> {
    // Step 1: Flatten and record original lengths in one pass
    let mut flat = Vec::with_capacity(nested.iter().map(|v| v.len()).sum());
    let lengths: Vec<usize> = nested
        .into_iter()
        .map(|inner| {
            let len = inner.len();
            flat.extend(inner); // Moves elements, no cloning
            len
        })
        .collect();

    // Step 2: Process all elements in parallel across all inner vectors
    let processed: Vec<String> = flat
        .into_par_iter()
        .map(|x| expensive_transformation(x))
        .collect();

    // Step 3: Reconstruct the nested structure using the recorded lengths
    let mut result = Vec::with_capacity(lengths.len());
    let mut iter = processed.into_iter();

    for len in lengths {
        result.push(iter.by_ref().take(len).collect());
    }

    result
}

/// Example expensive computation (convert usize to String representation)
fn expensive_transformation(x: usize) -> String {
    // Simulate CPU-intensive work
    let mut result = x * x;
    for _ in 0..100 {
        result = result.wrapping_add(x);
    }
    format!("value_{}_computed", result)
}

