#[allow(dead_code)]
fn process_nested_parallel(nested: Vec<Vec<usize>>) -> Vec<Vec<String>> {
    nested
        .into_par_iter()
        .map(|inner| {
            inner
                .into_par_iter()
                .map(|x| expensive_transformation(x))
                .collect()
        })
        .collect()
