/// Self-referential struct that owns the JSON string and holds borrowed references into it.
/// This allows passing deserialized borrowed data across tokio tasks without cloning.
#[self_referencing]
struct DataHolder {
    json_string: String,
    #[borrows(json_string)]
    #[covariant]
    parsed: MyData<'this>,
}

// Verify DataHolder is Send so it can cross tokio::spawn boundaries
const _: () = {
    fn assert_send<T: Send>() {}
    fn _check() { assert_send::<DataHolder>(); }
};

impl DataHolder {
    /// Parse JSON string into a self-referential struct.
    /// Note: Fails if JSON strings require unescaping (e.g., \" or \n),
    /// as &str cannot reference unescaped data without allocation.
    fn from_json(json: String) -> Result<Self, serde_json::Error> {
        Self::try_new(json, |s| serde_json::from_str(s))
    }

    /// Access the parsed data through a closure to satisfy borrow checker.
    fn with<F, R>(&self, f: F) -> R 
    where 
        F: FnOnce(&MyData<'_>) -> R 
    {
        self.with_parsed(|parsed| f(parsed))
    }
}

#[tokio::main]
async fn main() {
    // Channel to pass data across tasks
    let (tx, mut rx) = mpsc::channel::<Arc<DataHolder>>(10);

    // Spawn worker task that receives borrowed data
    let worker = tokio::spawn(async move {
        while let Some(holder) = rx.recv().await {
            holder.with(|data| {
                println!("Received: data='{}', more_data='{}'", data.data, data.more_data);
            });
