struct WhitespaceReplacer {
    insert: char,
}

impl WhitespaceReplacer {
    fn new(insert: char) -> Self {
        Self { insert }
    }
}

impl ConditionalEventHandler for WhitespaceReplacer {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();
        let line_before = &line[..pos];

        // Find the last non-whitespace character before cursor
        if let Some(last_non_ws) = line_before.rfind(|c: char| !c.is_whitespace()) {
            let ws_count = pos - (last_non_ws + 1);
            if ws_count > 0 {
                // Replace the whitespace with the desired character
                // Note: Cmd::Replace moves cursor to the beginning of replaced text,
                // positioning it BEFORE the inserted character. This is a limitation
                // of the current rustyline API (sequences/macros are not yet implemented).
                let movement = Movement::BackwardChar(ws_count as RepeatCount);
                return Some(Cmd::Replace(
                    movement,
                    Some(self.insert.to_string()),
                ));
            }
        }
        // No whitespace found, let default handler insert the character normally
        None
    }
}

fn bind_replacer(editor: &mut Editor<(), DefaultHistory>, key: char) {
    let event = KeyEvent::new(key, Modifiers::NONE);
    let handler = WhitespaceReplacer::new(key);
