/// Ray-cube intersection for a unit cube centered at origin with the given transform
/// Returns the world-space hit point and world-space normal
fn ray_cube_intersect(
    ray_origin: Vec3, 
    ray_dir: Vec3, 
    transform: &Transform
) -> Option<(Vec3, Vec3)> {
    // Transform ray to local space
    let inv_matrix = transform.compute_matrix().inverse();
    let local_origin = inv_matrix.transform_point3(ray_origin);
    let local_dir = inv_matrix.transform_vector3(ray_dir);

    let min = Vec3::splat(-0.5);
    let max = Vec3::splat(0.5);

    let mut t_min = -f32::INFINITY;
    let mut t_max = f32::INFINITY;
    let mut normal_axis = 0;
    let mut normal_sign = 1.0;

    for i in 0..3 {
        if local_dir[i].abs() < 1e-6 {
            // Ray is parallel to this axis
            if local_origin[i] < min[i] || local_origin[i] > max[i] {
                return None;
            }
        } else {
            let inv_dir = 1.0 / local_dir[i];
            let t1 = (min[i] - local_origin[i]) * inv_dir;
            let t2 = (max[i] - local_origin[i]) * inv_dir;

            let (t_near, t_far, near_sign) = if t1 < t2 {
                (t1, t2, -1.0)
            } else {
                (t2, t1, 1.0)
            };

            if t_near > t_min {
                t_min = t_near;
                normal_axis = i;
                normal_sign = near_sign;
            }
            if t_far < t_max {
                t_max = t_far;
            }

            if t_min > t_max {
                return None;
            }
        }
    }

    // Check if intersection is behind the ray origin
    if t_max < 0.0 || t_min < 0.0 {
        return None;
    }

    // Calculate local hit point
    let local_point = local_origin + local_dir * t_min;

    // Calculate local normal (points outward)
    let mut local_normal = Vec3::ZERO;
    local_normal[normal_axis] = normal_sign;

    // Transform back to world space
    let world_point = transform.transform_point(local_point);
    let world_normal = transform.transform_vector(local_normal).normalize();

    Some((world_point, world_normal))
}
"
}
