impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    /// Safe sequential implementation
    /// 
    /// Answers Q1 and Q2:
    /// - No unsafe pointers used
    /// - No copies of Vec<B> or B elements
    /// - Both elem_i and elem_j are modified (bidirectional neighbor lists)
    pub fn build_lists(&mut self) {
        let nelems = self.get_nelems();
        let cutoff = self.cutoff;
        let mut pairs = Vec::new();

        // First pass: collect pairs (i, j) where i < j and criterion is met
        // We only check j > i to avoid duplicate work (since criterion is symmetric)
        for i in 0..nelems {
            for j in (i + 1)..nelems {
                if self.elems[i].criterion(&self.elems[j]) < cutoff {
                    pairs.push((i, j));
                }
            }
        }

        // Second pass: update neighbor lists bidirectionally
        // This avoids the aliasing issues because we have no outstanding borrows
        for (i, j) in pairs {
            self.elems[i].nb.push(j);
            self.elems[j].nb.push(i);
        }
    }

