                .into_par_iter()
                .flat_map(|i| {
                    // Check all j > i to avoid duplicate pairs
                    (i + 1..nelems)
                        .filter_map(|j| {
                            if elems[i].criterion(&elems[j]) < cutoff {
                                Some((i, j))
                            } else {
