fn deserialize_path_list<'de, D>(deserializer: D) -> Result<Vec<PathBuf>, D::Error>
where
    D: Deserializer<'de>,
{
    struct PathListVisitor;

    impl<'de> Visitor<'de> for PathListVisitor {
        type Value = Vec<PathBuf>;

        fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
            formatter.write_str("a sequence of strings or an object with $ref")
        }

        fn visit_seq<S>(self, mut seq: S) -> Result<Self::Value, S::Error>
        where
            S: SeqAccess<'de>,
        {
            let mut paths = Vec::new();
            while let Some(path) = seq.next_element::<PathBuf>()? {
                paths.push(path);
            }
            Ok(paths)
        }

        fn visit_map<M>(self, mut map: M) -> Result<Self::Value, M::Error>
        where
            M: MapAccess<'de>,
        {
            let mut ref_val: Option<String> = None;

            while let Some(key) = map.next_key::<String>()? {
                if key == "$ref" {
                    ref_val = Some(map.next_value()?);
                } else {
                    let _: serde::de::IgnoredAny = map.next_value()?;
                }
            }

            match ref_val {
                Some(ref_str) => {
                    resolve_ref(&ref_str).map_err(de::Error::custom)
                }
                None => Err(de::Error::custom("expected $ref field in object"))
            }
        }
    }

    deserializer.deserialize_any(PathListVisitor)
}

fn resolve_ref(ref_str: &str) -> Result<Vec<PathBuf>, Box<dyn std::error::Error>> {
    let (file_path, pointer) = ref_str.split_once('#')
        .ok_or("Invalid $ref format, expected file#pointer")?;

    let content = fs::read_to_string(file_path)
        .map_err(|e| format!("Failed to read {}: {}", file_path, e))?;

    let json: serde_json::Value = serde_json::from_str(&content)
        .map_err(|e| format!("Failed to parse {}: {}", file_path, e))?;

    let mut current = &json;
    for segment in pointer.trim_start_matches('/').split('/') {
        if segment.is_empty() {
            continue;
        }
        current = current.get(segment)
            .ok_or_else(|| format!("JSON pointer '{}' not found in {}", pointer, file_path))?;
    }

    let paths: Vec<PathBuf> = serde_json::from_value(current.clone())
        .map_err(|e| format!("Failed to deserialize referenced data: {}", e))?;

    Ok(paths)
