// - For immutable refs: `&'1 T` can coerce to `&'a T` (covariance)
// - For mutable refs: `&'1 mut T` CANNOT coerce to `&'a mut T` (invariance)
// - This prevents aliasing: otherwise you could collect multiple &'a mut T 
//   and call next() again while holding the first reference
//
// THE SOLUTION:
// - Store `*mut T` (raw pointer) instead of `&'a mut Array<T>`
// - Use unsafe code to dereference with lifetime 'a
// - PhantomData ensures iterator doesn't outlive the data
#[derive(Debug)]
pub struct ArrayIteratorFromDynMut<'a, T> {
    ptr: *mut T,
    dims: Vec<usize>,
    selection_iterators: Vec<Box<dyn ArrayViewIterator>>,
    selection_dims: Vec<usize>,
    current_iterators: Vec<Box<dyn ArrayViewIterator>>,
    current_index_option: Vec<Option<usize>>,
    _marker: std::marker::PhantomData<&'a mut T>,
}

impl<'a, T> Iterator for ArrayIteratorFromDynMut<'a, T> {
    type Item = (Vec<usize>, &'a mut T);

    fn next(&mut self) -> Option<Self::Item> {
        if self.selection_iterators.is_empty() {
            return None;
        }

        self.current_index_option[0] = self.current_iterators[0].next();

        for i in 0..self.selection_iterators.len() {
            if self.current_index_option[i] == None {
                if i == self.selection_iterators.len() - 1 {
                    return None;
                }
                self.current_iterators[i] = self.selection_iterators[i].clone();
                self.current_index_option[i] = self.current_iterators[i].next();
                if i < self.selection_iterators.len() - 1 {
                    self.current_index_option[i + 1] = self.current_iterators[i + 1].next();
                }
            } else {
                break;
            }
        }

        let current_index: Vec<usize> = self.current_index_option.iter().map(|x| x.unwrap()).collect();

        // Calculate flat offset from n-dimensional index
        let mut offset = 0;
        let mut stride = 1;
        for i in (0..self.dims.len()).rev() {
            offset += current_index[i] * stride;
            stride *= self.dims[i];
        }

        // SAFETY: 
        // 1. ptr is valid (from Vec::as_mut_ptr) and not null
        // 2. offset is within bounds (calculated from valid indices)
        // 3. The iterator yields unique indices sequentially, so no aliasing occurs
        // 4. PhantomData ties the lifetime 'a to the Array's lifetime
        let current_value: &'a mut T = unsafe { &mut *self.ptr.add(offset) };

        Some((current_index, current_value))
    }
}

