  "main.rs": "/// Tokenizes a shell command string, respecting single quotes.
/// 
/// - Outside quotes: whitespace splits tokens
/// - Inside quotes: whitespace is preserved, quotes are removed
/// - Adjacent quoted and unquoted text is concatenated into a single token
fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current = String::new();
    let mut in_quotes = false;

    for ch in input.chars() {
        match ch {
            '\'' => {
                // Toggle quote state; don't add the quote character to the token
                in_quotes = !in_quotes;
            }
            c if c.is_whitespace() && !in_quotes => {
                // Whitespace outside quotes acts as a delimiter
                if !current.is_empty() {
                    tokens.push(std::mem::take(&mut current));
                }
            }
            c => {
                // Regular character (or whitespace inside quotes)
                current.push(c);
            }
        }
    }

    // Don't forget the last token if there is one
    if !current.is_empty() {
        tokens.push(current);
    }

    tokens
}

fn main() {
    // The example from the prompt
    let test_input = " one  ' two  'three    four";

    println!("Input: {:?}", test_input);
    println!("Tokens:");
    for token in tokenize(test_input) {
        println!("  <{}>", token);
    }

    // Additional test cases to demonstrate behavior
    println!("\n--- Additional tests ---");

    let cases = vec![
        "echo hello world",
        "echo 'hello world'",
        "echo hello'world'foo",
        "  spaces  'in quotes'   ",
        "'leading quote",
        "trailing quote'",
        "",
        "    ",
    ];

    for case in cases {
        println!("\nInput: {:?}", case);
        let tokens = tokenize(case);
        if tokens.is_empty() {
            println!("  (no tokens)");
        } else {
            for token in &tokens {
                println!("  <{}>", token);
            }
        }
    }
}"
}
