// Target function for demonstration: y = sqrt(x) + 1
// We'll evolve a tree that discovers this logic using our custom operator

fn main() {
    // Define custom operators using Op::new()
    // Arguments: name, arity (number of inputs), function pointer/closure

    // Custom unary operator: sqrt(x) + 1
    let sqrt_plus_one = Op::new("sqrt_plus_one", 1, |args: &[f64]| {
        args[0].sqrt() + 1.0
    });

    // Custom binary operator: average of two values
    let avg = Op::new("avg", 2, |args: &[f64]| {
        (args[0] + args[1]) / 2.0
    });

    // Custom unary operator: x^2 + x (polynomial term)
    let poly_term = Op::new("poly", 1, |args: &[f64]| {
        args[0].powi(2) + args[0]
    });

    // Set up the operator store with custom and built-in operators
    let store = vec![
        (
            NodeType::Vertex,
            vec![
                Op::add(),
                Op::sub(),
                Op::mul(),
                Op::div(),
                Op::pow(),
                sqrt_plus_one.clone(),  // Include our custom operators
                avg.clone(),
                poly_term.clone(),
            ],
        ),
        (
            NodeType::Leaf,
            vec![
                Op::var(0),            // Input variable x
                Op::const_(1.0),       // Constant 1.0
                Op::const_(2.0),       // Constant 2.0
                Op::const_(0.5),       // Constant 0.5
            ],
        ),
    ];

    // Define the problem: Symbolic regression to find sqrt(x) + 1
    let problem = RegressionProblem {
        target_func: |x| x.sqrt() + 1.0,
    };

    // Configure the GP engine
    let config = GeneticConfig::builder()
        .population_size(1000)
        .max_depth(4)
        .mutation_rate(0.15)
        .crossover_rate(0.85)
        .elitism(10)
        .tree_config(store)
        .build();

    // Create and run the genetic engine
    let engine = GeneticEngine::new(config)
        .problem(problem)
        .minimize();

    println!("Starting evolution with custom operators...");
    println!("Custom operators: sqrt_plus_one, avg, poly");

    let result = engine.run(50);

    println!("\nEvolution complete!");
    println!("Best fitness: {}", result.best_fitness);
    println!("Best tree (Lisp format): {:?}", result.best);

    // Validate the solution
    println!("\nValidation (comparing with target y = sqrt(x) + 1):");
    println!("{:<5} {:<12} {:<12} {:<12}", "x", "Target", "Predicted", "Error");
    println!("{}", "-".repeat(45));

    for i in 1..=10 {
        let x = i as f64;
        let target = x.sqrt() + 1.0;
        let predicted = result.best.eval(&[x]);
        let error = (predicted - target).abs();
        println!("{:<5.0} {:<12.6} {:<12.6} {:<12.6}", x, target, predicted, error);
    }
}

// Problem definition for symbolic regression
struct RegressionProblem {
    target_func: fn(f64) -> f64,
}

impl Problem<Tree<f64>> for RegressionProblem {
    fn fitness(&self, individual: &Tree<f64>, _generation: i32, _training: bool) -> f64 {
        let mut total_error = 0.0;
        let test_points: Vec<f64> = (1..=20).map(|x| x as f64).collect();

        for x in &test_points {
            let target = (self.target_func)(*x);
            let predicted = individual.eval(&[*x]);

            // Handle NaN or Infinity
            if predicted.is_finite() {
                total_error += (predicted - target).powi(2);
            } else {
                total_error += 1e10; // Penalize invalid values heavily
            }
        }

        // Return RMSE (lower is better)
        (total_error / test_points.len() as f64).sqrt()
    }
}"
