        }
    }

    pub struct Boo {
        version: f32,
    }

    impl Boo {
        pub fn new() -> Self {
            Self { version: 2.0 }
        }
    }

    impl Rest for Boo {
        fn get_name(&self) -> &str {
            "BooClient"
        }

        fn fetch_data(&self, endpoint: &str) -> String {
