  "main.rs": "use bevy::asset::io::PathStream;
use bevy::asset::{AssetReader, AssetReaderError, AssetSource, Reader};
use bevy::prelude::*;
use futures_lite::stream;
use std::collections::HashMap;
use std::fs::File;
use std::io::{self, Cursor, Read, Seek, SeekFrom, Write};
use std::path::{Path, PathBuf};
use std::sync::{Arc, Mutex};

/// Custom AssetReader that reads individual files from a WAD-like archive
/// without loading the entire archive into memory.
struct ArchiveAssetReader {
    /// Shared file handle to the archive (kept open for the lifetime of the app)
    file: Arc<Mutex<File>>,
    /// Directory index: filename -> (offset_in_file, size_in_bytes)
    /// This index is small (just metadata) compared to the full archive
    index: HashMap<String, (u64, u64)>,
}

impl AssetReader for ArchiveAssetReader {
    /// This is called by Bevy when an asset like "wad://red.png" is requested.
    /// It seeks to the specific offset and reads ONLY the bytes for that asset.
    async fn read<'a>(&'a self, path: &'a Path) -> Result<Reader<'a>, AssetReaderError> {
        let key = path.to_string_lossy().to_string();

        let (offset, size) = self.index.get(&key).ok_or_else(|| {
            AssetReaderError::NotFound(path.to_path_buf())
        })?;

        let mut file = self.file.lock().map_err(|e| {
            AssetReaderError::Io(Arc::new(io::Error::new(
                io::ErrorKind::Other,
                format!("Mutex poison: {}", e),
            )))
        })?;

        // Seek to the specific location in the archive
        file.seek(SeekFrom::Start(*offset))
            .map_err(|e| AssetReaderError::Io(Arc::new(e)))?;

        // Read only the required bytes (lazy loading)
        let mut buffer = vec![0u8; *size as usize];
        file.read_exact(&mut buffer)
            .map_err(|e| AssetReaderError::Io(Arc::new(e)))?;

        // Drop the lock explicitly before returning
        drop(file);

        // Return a cursor over the bytes, which implements AsyncRead + AsyncSeek
        Ok(Box::new(Cursor::new(buffer)))
    }

    async fn read_meta<'a>(&'a self, _path: &'a Path) -> Result<Reader<'a>, AssetReaderError> {
        // No meta support for this demo; return empty
        Ok(Box::new(Cursor::new(Vec::new())))
    }

    async fn read_directory<'a>(&'a self, _path: &'a Path) -> Result<Box<PathStream<'a>>, AssetReaderError> {
        // Return all filenames in the archive
        let paths: Vec<PathBuf> = self
            .index
            .keys()
            .map(|k| Path::new(k).to_path_buf())
            .collect();
        Ok(Box::new(stream::iter(paths)))
    }

    async fn is_directory<'a>(&'a self, _path: &'a Path) -> Result<bool, AssetReaderError> {
        // This archive format doesn't support directories, only flat files
        Ok(false)
    }
}

/// Creates a mock WAD3-like archive file containing two PNG images.
/// Format: [MAGIC: "WAD3"][COUNT: u32][ENTRIES: [(name: [u8;16], offset: u32, size: u32)]][DATA]
fn create_demo_archive(path: &Path) {
    use image::ImageEncoder;

    // Generate two simple 32x32 PNG images (red and blue)
    let red_pixels = vec![255u8, 0, 0, 255].repeat(32 * 32); // RGBA red
    let blue_pixels = vec![0u8, 0, 255, 255].repeat(32 * 32); // RGBA blue

    let mut red_png = Vec::new();
    let mut blue_png = Vec::new();

    image::codecs::png::PngEncoder::new(&mut red_png)
        .write_image(&red_pixels, 32, 32, image::ExtendedColorType::Rgba8)
        .unwrap();
    image::codecs::png::PngEncoder::new(&mut blue_png)
        .write_image(&blue_pixels, 32, 32, image::ExtendedColorType::Rgba8)
        .unwrap();

    let mut file = File::create(path).unwrap();
    let entries = vec![("red.png", red_png), ("blue.png", blue_png)];

    // Write header
    file.write_all(b"WAD3").unwrap();
    file.write_all(&(entries.len() as u32).to_le_bytes()).unwrap();

    // Calculate where data starts: header + directory
    let header_size = 4 + 4;
    let entry_size = 16 + 4 + 4; // name + offset + size
    let mut current_offset = (header_size + entries.len() * entry_size) as u64;

    // Write directory entries
    for (name, data) in &entries {
        let mut name_buf = [0u8; 16];
        for (i, b) in name.bytes().take(16).enumerate() {
            name_buf[i] = b;
        }
        file.write_all(&name_buf).unwrap();
        file.write_all(&(current_offset as u32).to_le_bytes()).unwrap();
        file.write_all(&(data.len() as u32).to_le_bytes()).unwrap();
        current_offset += data.len() as u64;
    }

    // Write actual data
    for (_, data) in &entries {
        file.write_all(data).unwrap();
    }

    println!(
        "Created demo archive at {:?} with {} files",
        path,
        entries.len()
    );
}

fn main() {
    // Create the archive in a temp location
    let archive_path = std::env::temp_dir().join("demo.wad");
    create_demo_archive(&archive_path);

    // We need to move the path into the closure for AssetSource::build
    let archive_path_for_source = Arc::new(archive_path);
    let archive_path_for_reader = archive_path_for_source.clone();

    App::new()
        .add_plugins(DefaultPlugins)
        // Register our custom asset source named "wad"
        // When we load "wad://red.png", Bevy will use this reader
        .register_asset_source(
            "wad",
            AssetSource::build(move |_settings| {
                // Open the archive and build the index (directory)
                // This only reads the directory table, not the entire file!
                let file = File::open(archive_path_for_reader.as_path()).expect("Failed to open archive");
                let mut reader = io::BufReader::new(file);

                // Read header
                let mut magic = [0u8; 4];
                reader.read_exact(&mut magic).expect("Invalid archive");
                assert_eq!(&magic, b"WAD3", "Invalid magic bytes");

                let mut count_buf = [0u8; 4];
                reader.read_exact(&mut count_buf).unwrap();
                let count = u32::from_le_bytes(count_buf) as usize;

                // Read directory entries into index
                let mut index = HashMap::new();
                for _ in 0..count {
                    let mut name_buf = [0u8; 16];
                    reader.read_exact(&mut name_buf).unwrap();
                    let name = String::from_utf8_lossy(&name_buf)
                        .trim_end_matches('\0')
                        .to_string();

                    let mut offset_buf = [0u8; 4];
                    reader.read_exact(&mut offset_buf).unwrap();
                    let offset = u32::from_le_bytes(offset_buf) as u64;

                    let mut size_buf = [0u8; 4];
                    reader.read_exact(&mut size_buf).unwrap();
                    let size = u32::from_le_bytes(size_buf) as u64;

                    index.insert(name, (offset, size));
                }

                let file_handle = Arc::new(Mutex::new(reader.into_inner()));

                Box::new(ArchiveAssetReader {
                    file: file_handle,
                    index,
                }) as Box<dyn AssetReader>
            }),
        )
        .add_systems(Startup, setup)
        .add_systems(Update, spawn_sprites_when_loaded)
        .run();
}

#[derive(Resource)]
struct LoadingAssets {
    red: Handle<Image>,
    blue: Handle<Image>,
}

fn setup(mut commands: Commands, asset_server: Res<AssetServer>) {
    // Load images from our custom archive source
    // Note: These are loaded LAZILY - the archive bytes are only read now,
    // and only for these specific files, not the whole archive
    let red_handle: Handle<Image> = asset_server.load("wad://red.png");
    let blue_handle: Handle<Image> = asset_server.load("wad://blue.png");

    commands.insert_resource(LoadingAssets {
        red: red_handle,
        blue: blue_handle,
    });

    commands.spawn(Camera2dBundle::default());
    println!("Loading assets from archive... (check that the entire file isn't loaded into RAM)");
}

fn spawn_sprites_when_loaded(
    mut commands: Commands,
    handles: Res<LoadingAssets>,
    asset_server: Res<AssetServer>,
    mut done: Local<bool>,
) {
    if *done {
        return;
    }

    // Check if both assets are loaded
    if asset_server.is_loaded_with_dependencies(&handles.red)
        && asset_server.is_loaded_with_dependencies(&handles.blue)
    {
        println!("Assets loaded! Spawning sprites...");

        // Spawn red sprite on the left
        commands.spawn(SpriteBundle {
            texture: handles.red.clone(),
            transform: Transform::from_xyz(-100.0, 0.0, 0.0).with_scale(Vec3::splat(4.0)),
            ..default()
        });

        // Spawn blue sprite on the right
        commands.spawn(SpriteBundle {
            texture: handles.blue.clone(),
            transform: Transform::from_xyz(100.0, 0.0, 0.0).with_scale(Vec3::splat(4.0)),
            ..default()
        });

        *done = true;
    }
}
"
}
