  "main.rs": "use std::sync::Arc;
use std::future::Future;
use tracing::{Span, Instrument};
use opentelemetry::Context as OtelContext;
use tracing_opentelemetry::OpenTelemetrySpanExt;

/// Context that survives across async callback boundaries.
/// Store this in Pingora's session context or similar.
struct RequestContext {
    /// The parent tracing span for the entire request
    pub span: Span,
    /// The OpenTelemetry context extracted from that span.
    /// This contains trace_id/span_id for OTel propagation.
    pub otel_ctx: OtelContext,
}

impl RequestContext {
    fn new(request_id: &str) -> Self {
        // Create the parent span that will encompass all stages
        let span = tracing::info_span!("request", request_id = %request_id);

        // Extract the OTel context from the tracing span.
        // This must be done while the span is active/entered or immediately after creation
        // if using the current thread's context.
        let otel_ctx = span.context();

        Self { span, otel_ctx }
    }

    /// Helper to execute an async block within the rehydrated context.
    /// This ensures both tracing and OTel contexts are properly restored.
    async fn run<F, Fut, R>(&self, stage_name: &'static str, f: F) -> R
    where
        F: FnOnce() -> Fut,
        Fut: Future<Output = R>,
    {
        // Clone necessary data for the async block
        let parent_span = self.span.clone();
        let otel_ctx = self.otel_ctx.clone();

        // Create a child span explicitly parented to our stored span
        let stage_span = tracing::info_span!(parent: parent_span.id(), stage_name);

        // Instrument the future with the span, and attach OTel context inside
        async move {
            // Reattach the OTel context so any OTel operations (like creating 
            // new spans or exporting) see the correct parent trace/span IDs.
            let _otel_guard = otel_ctx.attach();

            f().await
        }
        .instrument(stage_span)
        .await
    }
}

/// Simulates Pingora's Proxy trait with multiple async callbacks
#[async_trait::async_trait]
trait ProxyCallbacks {
    async fn stage1(&self, ctx: Arc<RequestContext>);
    async fn stage2(&self, ctx: Arc<RequestContext>);
    async fn upstream(&self, ctx: Arc<RequestContext>);
}

struct MyProxy;

#[async_trait::async_trait]
impl ProxyCallbacks for MyProxy {
    async fn stage1(&self, ctx: Arc<RequestContext>) {
        // Method 1: Using the helper function for clean encapsulation
        ctx.run("stage1", || async {
            tracing::info!("Processing stage 1");

            // Nested spans work correctly - they become children of stage1
            let details_span = tracing::info_span!("stage1_processing");
            let _enter = details_span.enter();
            tracing::info!("Stage 1 details");
            drop(_enter);

            tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
            tracing::info!("Stage 1 complete");
        }).await;
    }

    async fn stage2(&self, ctx: Arc<RequestContext>) {
        // Method 2: Manual rehydration with explicit span parenting
        let parent_span = ctx.span.clone();
        let otel_ctx = ctx.otel_ctx.clone();

        // Create child span using the stored parent's ID
        let stage_span = tracing::info_span!(parent: parent_span.id(), "stage2");

        async move {
            // Must attach OTel context inside the instrumented block
            let _guard = otel_ctx.attach();
            tracing::info!("Processing stage 2");
            tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
        }
        .instrument(stage_span)
        .await;
    }

    async fn upstream(&self, ctx: Arc<RequestContext>) {
        // Method 3: Enter span for synchronous setup, then instrument async work
        ctx.span.in_scope(|| {
            tracing::info!("Preparing upstream connection (sync setup)");
        });

        let parent_span = ctx.span.clone();
        let otel_ctx = ctx.otel_ctx.clone();
        let upstream_span = tracing::info_span!(parent: parent_span.id(), "upstream");

        async move {
            let _guard = otel_ctx.attach();
            tracing::info!("Sending request to upstream");
            tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
            tracing::info!("Received upstream response");
        }
        .instrument(upstream_span)
        .await;
    }
}

#[tokio::main]
async fn main() {
    // Initialize OpenTelemetry with stdout exporter for demonstration
    let tracer = opentelemetry_sdk::export::trace::stdout::new_pipeline()
        .install_simple();

    let telemetry = tracing_opentelemetry::layer().with_tracer(tracer);

    tracing_subscriber::registry()
        .with(telemetry)
        .with(tracing_subscriber::fmt::layer().with_target(false))
        .init();

    // Simulate a request lifecycle
    let ctx = Arc::new(RequestContext::new("req-abc-123"));
    let proxy = MyProxy;

    // Simulate Pingora's behavior: these callbacks may be called
    // at different times and potentially on different threads/tasks.
    let h1 = {
        let ctx = ctx.clone();
        tokio::spawn(async move { 
            proxy.stage1(ctx).await 
        })
    };

    let h2 = {
        let ctx = ctx.clone();
        tokio::spawn(async move { 
            // Simulate delay - in real Pingora this might be called later
            tokio::time::sleep(tokio::time::Duration::from_millis(50)).await;
            proxy.stage2(ctx).await 
        })
    };

    let h3 = {
        let ctx = ctx.clone();
        tokio::spawn(async move { 
            tokio::time::sleep(tokio::time::Duration::from_millis(150)).await;
            proxy.upstream(ctx).await 
        })
    };

    // Wait for all stages to complete
    let _ = tokio::join!(h1, h2, h3);

    // Ensure all spans are flushed
    opentelemetry::global::shutdown_tracer_provider();
}
