    /// In Tauri, this closure would emit events via `app.emit("agent-output", text)`.
    pub fn spawn<F>(command: &str, mut on_output: F) -> Result<Self, Box<dyn std::error::Error + Send + Sync>>
    where
        F: FnMut(String) + Send + 'static,
