                    }
                    Ok(_) => {
                        // Data is available, read it (non-blocking)
                        match session.read(&mut buf) {
                            Ok(0) => {
                                let _ = on_output("[Process terminated]\r\n".to_string());
                                break;
                            }
                            Ok(n) => {
