    async fn run(mut shutdown_rx: watch::Receiver<bool>) {
        let mut counter = 0;
        loop {
            tokio::select! {
                // Check for shutdown signal
                _ = shutdown_rx.changed() => {
                    if *shutdown_rx.borrow() {
                        log::info!("Queue handler: received shutdown signal, completing pending work...");
