/// Parse a LanceDB ISO string (which may or may not have fractional seconds)
/// and convert to Unix timestamp (seconds since epoch)
pub fn date_string_to_int(date_str: &str) -> Result<i64, chrono::ParseError> {
    // Parse as NaiveDateTime since LanceDB returns strings without timezone info
    // The %.f format specifier handles optional fractional seconds (milliseconds, microseconds, etc.)
    let naive = NaiveDateTime::parse_from_str(date_str, "%Y-%m-%dT%H:%M:%S%.f")?;

    // Convert to UTC DateTime
    let datetime: DateTime<Utc> = Utc.from_utc_datetime(&naive);

    // Return Unix timestamp in seconds
    Ok(datetime.timestamp())
}

/// Alternative: Get DateTime<Utc> object for more flexibility
pub fn parse_lancedb_date(date_str: &str) -> Result<DateTime<Utc>, chrono::ParseError> {
    let naive = NaiveDateTime::parse_from_str(date_str, "%Y-%m-%dT%H:%M:%S%.f")?;
    Ok(Utc.from_utc_datetime(&naive))
}

