name = "async-wrap"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["full"] }",
  "main.rs": "use std::future::Future;
use std::pin::Pin;
use tokio::sync::mpsc::Sender;

pub struct Context(i32);

pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<
            dyn for<'a> Fn(
                &'a mut Context
            ) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
            + Send,
        >,
    },
}

/// Wraps an async closure (FnOnce) into the boxed trait object format required by InnerAsyncEvent.
/// 
/// Usage:
/// ```ignore
/// with_context_async(&sender, |ctx| async move {
///     ctx.0 += 1;
/// }).await;
/// ```
pub async fn with_context_async<F, Fut>(
    work_sender: &Sender<InnerAsyncEvent>,
    block: F,
) where
    F: for<'a> FnOnce(&'a mut Context) -> Fut + Send + 'static,
    Fut: Future<Output = ()> + Send + 'a,
{
    // Wrap FnOnce in a Mutex<Option> to adapt it to the Fn trait required for the boxed trait object.
    // The block will be taken out and called exactly once.
    let block = std::sync::Mutex::new(Some(block));

    let boxed_block: Box<
        dyn for<'a> Fn(&'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>> + Send
    > = Box::new(move |ctx| {
        let f = block
            .lock()
            .unwrap()
            .take()
            .expect("with_context_async block was called more than once");
        Box::pin(f(ctx))
    });

    let _ = work_sender
        .send(InnerAsyncEvent::DoWithContext { block: boxed_block })
        .await;
}

#[tokio::main]
async fn main() {
    let (tx, mut rx) = tokio::sync::mpsc::channel(100);

    // Spawn a worker task that processes events
    let worker = tokio::spawn(async move {
        while let Some(event) = rx.recv().await {
            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    let mut ctx = Context(0);
                    // Execute the async block
                    block(&mut ctx).await;
                    println!("Context value after processing: {}", ctx.0);
                }
            }
        }
    });

    // Send async work using the nice wrapper
    // Note: We pass a closure that returns a future (async block)
    with_context_async(&tx, |ctx: &mut Context| async move {
        println!("Processing first async task...");
        ctx.0 += 42;
    }).await;

    with_context_async(&tx, |ctx: &mut Context| async move {
        println!("Processing second async task...");
        ctx.0 += 1;
    }).await;

    // Drop sender to close the channel
    drop(tx);

    // Wait for worker to finish
    worker.await.unwrap();
}"
}
```

