  F: for&lt;'a&gt; Fn(&amp;'a Request) -&gt; Fut + Send + Sync + 'static,
  for&lt;'a&gt; Fut: Future&lt;Output = Response&gt; + Send + 'a,
{
  fn from(f: F) -&gt; Self {
    Handler(Arc::new(move |req| Box::pin(f(req))))
  }
}

// Conversion for a `sync` handler: Fn(&amp;Request) -&gt; Response
impl&lt;F&gt; From&lt;F&gt; for Handler
where
  F: for&lt;'a&gt; Fn(&amp;'a Request) -&gt; Response + Send + Sync + 'static,
{
  fn from(f: F) -&gt; Self {
    Handler(Arc::new(move |req| Box::pin(async move { f(req) })))
  }
}

