  "main.rs": "use futures::future::BoxFuture;
use std::future::Future;
use std::sync::Arc;

pub struct Request;
pub struct Response;

// Internal storage type: a boxed future that borrows the request
type HandlerFn = dyn for<'a> Fn(&'a Request) -> BoxFuture<'a, Response> + Send + Sync;

pub struct Handler(Arc<HandlerFn>);

/// Wrapper type for async handlers.
/// This is required on stable Rust to avoid conflicting implementations
/// and HRTB issues with opaque `impl Future` types.
pub struct Async<F>(F);

impl<F> Async<F> {
    pub fn new(f: F) -> Self {
        Async(f)
    }
}

/// Trait to convert user functions into our internal Handler type.
pub trait IntoHandler {
    fn into_handler(self) -> Handler;
}

// Implementation for synchronous handlers: Fn(&Request) -> Response
impl<F> IntoHandler for F
where
    F: Fn(&Request) -> Response + Send + Sync + 'static,
{
    fn into_handler(self) -> Handler {
        Handler(Arc::new(move |req| {
            // Wrap the synchronous result in an async block
            Box::pin(async move { self(req) })
        }))
    }
}

// Implementation for asynchronous handlers: Fn(&Request) -> impl Future
// Note: We wrap the async function in `Async(...)` to avoid overlapping
// with the sync implementation and to satisfy lifetime constraints.
impl<F, Fut> IntoHandler for Async<F>
where
    F: Fn(&Request) -> Fut + Send + Sync + 'static,
    Fut: Future<Output = Response> + Send + 'static,
{
    fn into_handler(self) -> Handler {
        Handler(Arc::new(move |req| {
            // Pin the future returned by the async function
            Box::pin(self.0(req))
        }))
    }
}

pub struct Server;

impl Server {
    pub fn new() -> Self {
        Server
    }

    pub fn add_route<F>(&mut self, path: &str, f: F)
    where
        F: IntoHandler,
    {
        let _handler: Handler = f.into_handler();
        println!("Registered route: {}", path);
    }
}

// Example user handlers
fn sync_handler(_req: &Request) -> Response {
    println!("Sync handler called");
    Response
}

async fn async_handler(_req: &Request) -> Response {
    println!("Async handler called");
    Response
}

fn main() {
    let mut server = Server::new();

    // Synchronous handler works directly
    server.add_route("/sync", sync_handler);

    // Asynchronous handler requires the Async wrapper
    server.add_route("/async", Async::new(async_handler));

    // You can also use closures
    server.add_route("/sync-closure", |_: &Request| Response);
    server.add_route("/async-closure", Async::new(|_: &Request| async move { Response }));

    println!("Server setup complete!");
}
"
}
