{
  "Cargo.toml": "[package]
name = "manual_poll"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["full"] }",
  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll, RawWaker, RawWakerVTable, Waker};

/// Result of attempting to poll a future immediately
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Creates a no-op waker for use in synchronous polling contexts.
/// This waker does nothing when woken, which is fine for one-shot polling
/// where we don't intend to wait for wakeups.
fn noop_waker() -> Waker {
    const VTABLE: RawWakerVTable = RawWakerVTable::new(
        |_| noop_raw_waker(), // clone
        |_| {},               // wake
        |_| {},               // wake_by_ref
        |_| {},               // drop
    );

    fn noop_raw_waker() -> RawWaker {
        RawWaker::new(std::ptr::null(), &VTABLE)
    }

    unsafe { Waker::from_raw(noop_raw_waker()) }
}

/// Attempts to poll an `Unpin` future once immediately without awaiting.
/// 
/// Returns `Ready` if the future completes immediately, or `Pending` if it
/// would block. The future remains valid and can be polled again later.
fn try_poll<X>(future: &mut impl Future<Output = X> + Unpin) -> TryPollResult<X> {
    let waker = noop_waker();
    let mut context = Context::from_waker(&waker);

    match Pin::new(future).poll(&mut context) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

/// Attempts to poll a pinned future once immediately.
/// 
/// Use this for futures that are `!Unpin` (like most `async` blocks).
/// The future must be pinned before calling this function (e.g., using `Box::pin`
/// or the `pin!` macro).
fn try_poll_pinned<X>(future: Pin<&mut impl Future<Output = X>>) -> TryPollResult<X> {
    let waker = noop_waker();
    let mut context = Context::from_waker(&waker);

    match future.poll(&mut context) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

#[tokio::main]
async fn main() {
    println!("=== Testing immediate ready future ===");
    // Example 1: A future that is immediately ready (Unpin)
    let mut immediate = std::future::ready(42);
    match try_poll(&mut immediate) {
        TryPollResult::Ready(val) => println!("Future was ready immediately: {}", val),
        TryPollResult::Pending => println!("Future was pending (unexpected for ready())"),
    }

    println!("\n=== Testing yielding future ===");
    // Example 2: A future that yields control (needs to be spawned)
    // Since async blocks are !Unpin, we box them to pin them
    let mut yielding = Box::pin(async {
        tokio::task::yield_now().await;
        123
    });

    match try_poll_pinned(yielding.as_mut()) {
        TryPollResult::Ready(val) => println!("Future was ready immediately: {}", val),
        TryPollResult::Pending => {
            println!("Future was pending, spawning task...");
            tokio::spawn(async move {
                let result = yielding.await;
                println!("Spawned task completed with: {}", result);
            });
        }
    }

    // Give spawned task time to complete
    tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;

    println!("\n=== Testing sleeping future ===");
    // Example 3: A future that sleeps
    let mut sleeping = Box::pin(async {
        tokio::time::sleep(tokio::time::Duration::from_millis(1)).await;
        "completed"
    });

    match try_poll_pinned(sleeping.as_mut()) {
        TryPollResult::Ready(val) => println!("Sleeping future was ready: {}", val),
        TryPollResult::Pending => {
            println!("Sleeping future was pending, spawning...");
            tokio::spawn(async move {
                let result = sleeping.await;
                println!("Sleeping task completed with: {}", result);
            });
        }
    }

    // Wait for spawned tasks
    tokio::time::sleep(tokio::time::Duration::from_millis(50)).await;

    println!("\n=== All tests complete ===");
}"
}
