  "main.rs": "use ra_ap_syntax::{
    ast::{self, make, Path, Use, UseTree},
    AstNode, SourceFile, TextRange,
};

fn main() {
    let code = r#"use vexide::{devices::smart::*, prelude::*};
use vexide::devices::*;
use vexide::devices::smart::Motor;
use vexide::{devices, fs};
use vexide::devices;
use vexide::devices::{smart, adi};
use {vexide::{devices, fs}, core::borrow};
"#;

    println!("Original:\n{}", code);
    println!("\nTransformed:\n{}", rewrite_imports(code));
}

pub fn rewrite_imports(source: &str) -> String {
    let file = SourceFile::parse(source).tree();
    let mut replacements: Vec<(TextRange, String)> = Vec::new();

    for use_item in file.syntax().descendants().filter_map(Use::cast) {
        if let Some(new_use_item) = rewrite_use_item(&use_item) {
            if new_use_item.syntax().text() != use_item.syntax().text() {
                replacements.push((use_item.syntax().text_range(), new_use_item.to_string()));
            }
        }
    }

    // Apply replacements in reverse order to preserve text ranges
    let mut result = source.to_string();
    replacements.sort_by_key(|(range, _)| range.start());
    replacements.reverse();

    for (range, new_text) in replacements {
        let start: usize = range.start().into();
        let end: usize = range.end().into();
        result.replace_range(start..end, &new_text);
    }

    result
}

fn rewrite_use_item(use_item: &Use) -> Option<Use> {
    let use_tree = use_item.use_tree()?;
    let new_trees = rewrite_use_tree(&use_tree, None);

    if new_trees.is_empty() {
        return None;
    }

    if new_trees.len() == 1 {
        Some(make::use_(use_item.visibility(), new_trees.into_iter().next()?))
    } else {
        // Multiple trees at root level: wrap in a list
        let list = make::use_tree_list(new_trees);
        let tree = make::use_tree(None, Some(list), None);
        Some(make::use_(use_item.visibility(), tree))
    }
}

/// Recursively transforms use trees, returning the new trees to replace this one.
/// The `prefix` is the accumulated path from parent nodes (e.g., "vexide::devices").
fn rewrite_use_tree(tree: &UseTree, prefix: Option<&str>) -> Vec<UseTree> {
    let path = tree.path();
    let star = tree.star_token();
    let list = tree.use_tree_list();

    // Build the full path string up to this node
    let current_segment = path.as_ref().map(path_to_string).unwrap_or_default();
    let full_path = match prefix {
        Some(p) if !current_segment.is_empty() => format!("{}::{}", p, current_segment),
        _ => current_segment,
    };

    // Check if this path matches vexide::devices or vexide::devices::...
    let matches_target = full_path == "vexide::devices" || full_path.starts_with("vexide::devices::");

    if matches_target {
        // Rewrite path by removing 'devices' segment
        let new_full_path = if full_path == "vexide::devices" {
            "vexide".to_string()
        } else {
            full_path.replacen("vexide::devices", "vexide", 1)
        };

        // If the new path equals the parent prefix, this import is redundant (e.g., vexide inside vexide::{...})
        if Some(new_full_path.as_str()) == prefix {
            return vec![];
        }

        let new_path = make::path_from_str(&new_full_path);

        if let Some(list) = list {
            // Has children: transform them with the new path as prefix
            let mut new_children = Vec::new();
            for child in list.use_trees() {
                new_children.extend(rewrite_use_tree(&child, Some(&new_full_path)));
            }

            if new_children.is_empty() && new_path.is_none() {
                return vec![];
            }

            let new_list = make::use_tree_list(new_children);
            vec![make::use_tree(new_path, Some(new_list), None)]
        } else if star.is_some() {
            // Glob pattern
            vec![make::use_tree(new_path, None, star)]
        } else {
            // Simple path
            vec![make::use_tree(new_path, None, None)]
        }
    } else {
        // No match - recurse into children with updated prefix
        if let Some(list) = list {
            let new_prefix = if full_path.is_empty() {
                prefix.map(|s| s.to_string())
            } else {
                Some(full_path.clone())
            };

            let mut new_children = Vec::new();
            for child in list.use_trees() {
                new_children.extend(rewrite_use_tree(&child, new_prefix.as_deref()));
            }

            // Check if any children changed
            let changed = new_children.len() != list.use_trees().count()
                || new_children.iter().zip(list.use_trees()).any(|(a, b)| {
                    a.syntax().text() != b.syntax().text()
                });

            if changed {
                if new_children.is_empty() && path.is_some() {
                    // All children removed, keep just the path
                    return vec![make::use_tree(path, None, None)];
                }
                let new_list = make::use_tree_list(new_children);
                return vec![make::use_tree(path, Some(new_list), None)];
            }
        }
        // No changes
        vec![tree.clone()]
    }
}

fn path_to_string(path: &Path) -> String {
    path.segments()
        .filter_map(|seg| seg.name_ref().map(|name| name.text().to_string()))
        .collect::<Vec<_>>()
        .join("::")
}
"
