use std::io::Write;
use tokio::io::{AsyncBufReadExt, AsyncWriteExt, BufReader};
use tokio::process::Command;
use tokio::sync::mpsc;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Create async readline. The second return value is a Printer that handles
    // redrawing the prompt when you write to it.
    let (mut rl, mut printer) = Readline::new("> ".to_string())?;

    // Example: host a Python REPL as child process
    // You can replace this with any REPL program (node, bash, etc.)
    let mut child = Command::new("python3")
        .arg("-i")  // Interactive mode
        .arg("-q")  // Quiet (no version message)
        .stdin(std::process::Stdio::piped())
        .stdout(std::process::Stdio::piped())
        .stderr(std::process::Stdio::piped())
        .spawn()?;

    let mut child_stdin = child.stdin.take().unwrap();
    let child_stdout = child.stdout.take().unwrap();
    let child_stderr = child.stderr.take().unwrap();

    // Channel to receive output from child process threads
    let (tx, mut rx) = mpsc::unbounded_channel::<String>();

    // Spawn stdout reader task
    let tx_stdout = tx.clone();
    tokio::spawn(async move {
        let mut reader = BufReader::new(child_stdout).lines();
        while let Ok(Some(line)) = reader.next_line().await {
            let _ = tx_stdout.send(line);
        }
    });

    // Spawn stderr reader task
    let tx_stderr = tx.clone();
    tokio::spawn(async move {
        let mut reader = BufReader::new(child_stderr).lines();
        while let Ok(Some(line)) = reader.next_line().await {
            let _ = tx_stderr.send(format!("[stderr] {}", line));
        }
    });

    // Monitor child exit
    let tx_exit = tx.clone();
    tokio::spawn(async move {
        let status = child.wait().await;
        match status {
            Ok(code) => { let _ = tx_exit.send(format!("[Child exited with {}]", code)); }
            Err(e) => { let _ = tx_exit.send(format!("[Child error: {}]", e)); }
        }
    });

    loop {
        tokio::select! {
            // Wait for user input
            result = rl.readline() => {
                match result {
                    Ok(line) => {
                        // Add to history so up-arrow works
                        rl.add_history_entry(line.clone());

                        // Send line to child process
                        if child_stdin.write_all(line.as_bytes()).await.is_err() {
                            break;
                        }
                        if child_stdin.write_all(b"\n").await.is_err() {
                            break;
                        }
                        if child_stdin.flush().await.is_err() {
                            break;
                        }
                    }
                    Err(ReadlineError::Interrupted) => {
                        writeln!(printer, "^C")?;
                        break;
                    }
                    Err(ReadlineError::Eof) => {
                        writeln!(printer, "^D")?;
                        break;
                    }
                    Err(e) => {
                        writeln!(printer, "Error: {}", e)?;
                        break;
                    }
                }
            }

            // Print child output immediately while readline is active
            Some(line) = rx.recv() => {
                // Using writeln! on the printer ensures the prompt is cleared,
                // the line is printed, and the prompt with current buffer is redrawn
                writeln!(printer, "{}", line)?;
            }
        }
    }

    Ok(())
}
"
}
