use std::path::Path;

/// Converts a source file path to its likely module path.
/// This assumes the standard Rust project layout where file paths mirror module paths.
/// Example: `src/my_module/submodule.rs` -> `crate_name::my_module::submodule`
fn file_to_module(file: &str) -> String {
    // Get the crate name (with dashes replaced by underscores, as Rust does)
    let crate_name = env!("CARGO_PKG_NAME").replace("-", "_");
    let path = Path::new(file);
    let components: Vec<_> = path.components().collect();

    // Find the "src" directory in the path
    if let Some(src_pos) = components.iter().position(|c| {
        c.as_os_str().to_str() == Some("src")
    }) {
        let after_src = &components[src_pos + 1..];

        // If src is the last component (e.g., just `src/`), return crate name
        if after_src.is_empty() {
            return crate_name;
        }

        // Convert path components to module parts
        let parts: Vec<String> = after_src.iter()
            .map(|c| {
                c.as_os_str()
                    .to_string_lossy()
                    .trim_end_matches(".rs")
                    .to_string()
            })
            .filter(|s| !s.is_empty())
            .collect();

        // Handle src/main.rs and src/lib.rs as the crate root
        if parts.len() == 1 && (parts[0] == "main" || parts[0] == "lib") {
            return crate_name;
        }

        format!("{}::{}" , crate_name, parts.join("::"))
    } else {
        // Fallback: just use the file stem
        format!("{}::{}" , crate_name, 
            path.file_stem().and_then(|s| s.to_str()).unwrap_or("unknown"))
    }
}

/// Logs a message using the provided caller location for module metadata.
/// This allows auxiliary functions to emit logs that appear to come from their callers.
fn log_with_caller_location(level: log::Level, message: &str, loc: &Location) {
    // Derive the module path from the file location
    let module_path = file_to_module(loc.file());

    // Manually construct the log record with the "faked" module path
    let record = log::Record::builder()
        .args(format_args!("{}", message))
        .level(level)
        .target(&module_path)  // Used for filtering
        .module_path(Some(&module_path))  // Displayed in log output
        .file(Some(loc.file()))
        .line(Some(loc.line()))
        .build();

    log::logger().log(&record);
}

