// Helper type to allow returning different body types (file vs empty) from the same handler
type BoxBody = http_body_util::combinators::BoxBody<Bytes, io::Error>;

/// Streams a tokio::fs::File as a hyper response body without loading it into memory
async fn serve_file(path: &Path) -> hyper::Response<BoxBody> {
    // Open the file
    let file = File::open(path).await.unwrap();

    // 1. Convert AsyncRead (File) into a Stream of Result<Bytes, io::Error>
    let byte_stream = ReaderStream::new(file);

    // 2. Map each Bytes chunk into a Frame<Bytes> (what hyper's Body trait requires)
    let frame_stream = byte_stream.map(|result| {
        result.map(|bytes| Frame::data(bytes))
    });

    // 3. Convert the stream into a Body implementation
    let body = StreamBody::new(frame_stream);

    // 4. Box the body to erase the concrete type (optional, but useful for returning 
    //    different body types like Empty vs StreamBody from the same function)
    let boxed_body = body.map_err(|e| e).boxed();

    Response::builder()
        .status(200)
        .header("content-type", "application/octet-stream")
        .body(boxed_body)
        .unwrap()
}

async fn handle_request(req: Request<Incoming>) -> Result<Response<BoxBody>, io::Error> {
    // Simple routing: use the request path as the file path
    // WARNING: In production, sanitize the path to prevent directory traversal attacks!
    let path = req.uri().path().trim_start_matches('/');
    let path = if path.is_empty() { "Cargo.toml" } else { path };
    let path = Path::new(path);

    // Check if file exists, otherwise return 404
    match File::open(path).await {
        Ok(_) => Ok(serve_file(path).await),
        Err(_) => {
            let empty = http_body_util::Empty::new().boxed();
            Ok(Response::builder()
                .status(StatusCode::NOT_FOUND)
                .body(empty)
                .unwrap())
        }
    }
}

