fn ray_aabb_intersection(origin: Vec3, dir: Vec3) -> Option<(f32, Vec3)> {
    let min = Vec3::splat(-0.5);
    let max = Vec3::splat(0.5);

    let mut tmin = 0.0f32;
    let mut tmax = f32::INFINITY;
    let mut normal = Vec3::ZERO;

