                (-Vec3::from_array([if i == 0 { 1.0 } else { 0.0 }, if i == 1 { 1.0 } else { 0.0 }, if i == 2 { 1.0 } else { 0.0 }]),
                 Vec3::from_array([if i == 0 { 1.0 } else { 0.0 }, if i == 1 { 1.0 } else { 0.0 }, if i == 2 { 1.0 } else { 0.0 }]))
