            };

            if t1 > t2 {
                std::mem::swap(&mut t1, &mut t2);
                std::mem::swap(&mut n1, &mut n2);
            }

            if t1 > tmin {
                tmin = t1;
                normal = n1;
            }
            tmax = tmax.min(t2);

            if tmin > tmax {
                return None;
            }
        }
    }

    Some((tmin, normal))
