use std::fs;
use std::path::PathBuf;

/// Resolves a JSON pointer (RFC 6901) within a JSON value.
fn resolve_json_pointer<'a>(value: &'a serde_json::Value, pointer: &str) -> Option<&'a serde_json::Value> {
    if pointer.is_empty() {
        return Some(value);
    }

    let mut current = value;
    // JSON pointer always starts with '/' if not empty (e.g., "#/p_list" -> pointer is "/p_list")
    for part in pointer.trim_start_matches('/').split('/') {
        // Decode JSON pointer escape sequences: ~1 -> /, ~0 -> ~
        let part = part.replace("~1", "/").replace("~0", "~");

        if let Some(obj) = current.as_object() {
            current = obj.get(&part)?;
        } else if let Some(arr) = current.as_array() {
            let index = part.parse::<usize>().ok()?;
            current = arr.get(index)?;
        } else {
            return None;
        }
    }
    Some(current)
}

/// Custom deserializer that handles either a direct array of paths or a {"$ref": "file#pointer"} object.
fn resolve_ref<'de, D>(deserializer: D) -> Result<Vec<PathBuf>, D::Error>
where
    D: Deserializer<'de>,
{
    let value = serde_json::Value::deserialize(deserializer)?;

    // First, try to deserialize as a direct Vec<PathBuf>
    if let Ok(paths) = Vec::<PathBuf>::deserialize(&value) {
        return Ok(paths);
    }

    // If that fails, check if it's a reference object
    if let Some(obj) = value.as_object() {
        if let Some(ref_str) = obj.get("$ref").and_then(|v| v.as_str()) {
            // Parse the reference format: "file_path#json_pointer"
            let (file_path, pointer) = ref_str
                .split_once('#')
                .ok_or_else(|| D::Error::custom("Invalid $ref format: missing '#' separator"))?;

            // Read the referenced file
            let content = fs::read_to_string(file_path)
                .map_err(|e| D::Error::custom(format!("Failed to read file {}: {}", file_path, e)))?;

            let json: serde_json::Value = serde_json::from_str(&content)
                .map_err(|e| D::Error::custom(format!("Failed to parse JSON in {}: {}", file_path, e)))?;

            // Resolve the JSON pointer (e.g., "/p_list")
            let target = resolve_json_pointer(&json, pointer)
                .ok_or_else(|| D::Error::custom(format!("JSON pointer '{}' not found in {}", pointer, file_path)))?;

            // Deserialize the target value as Vec<PathBuf>
            let paths = Vec::<PathBuf>::deserialize(target)
                .map_err(|e| D::Error::custom(format!("Failed to deserialize referenced data: {}", e)))?;

            return Ok(paths);
        }
    }

    Err(D::Error::custom("Expected either an array of paths or an object with '$ref' key"))
}

#[derive(Deserialize, Debug)]
struct A {
    #[serde(deserialize_with = "resolve_ref")]
    path_list: Vec<PathBuf>,
