/// When the inner Sender is taken (set to None), all sends will silently fail
/// and new streams will immediately end.
#[derive(Clone)]
pub struct EventSender {
    inner: Arc<Mutex<Option<Sender<Event>>>>,
}

impl EventSender {
    pub fn send(&self, event: Event) {
        // Lock briefly to access the sender
        if let Ok(guard) = self.inner.lock() {
            if let Some(tx) = guard.as_ref() {
                let _ = tx.send(event);
            }
        }
