    let sender_prod = sender.clone();
    let producer = tokio::spawn(async move {
        let mut i = 0;
        loop {
            sender_prod.send(Event { data: format!("msg-{}", i) });
            i += 1;
            sleep(Duration::from_secs(1)).await;
        }
    });

    // Simulate multiple SSE consumers
    let mut handles = vec![];
    for client_id in 1..=2 {
        let factory = factory.clone();
        handles.push(tokio::spawn(async move {
            let mut stream = factory.all_events();
            println!("[Client {}] Connected", client_id);

            while let Some(result) = stream.next().await {
                match result {
                    Ok(event) => println!("[Client {}] Got: {}", client_id, event.data),
                    Err(e) => println!("[Client {}] Error: {:?}", client_id, e),
