/// Listens for OS signals in a non-blocking way.
/// Checks the `running` flag every 100ms to allow graceful shutdown
/// without waiting for the next signal.
fn yield_signals(sender: Sender<Message>, running: Arc<AtomicBool>) {
    let mut signals = Signals::new(&[SIGINT, SIGTERM]).unwrap();

    while running.load(Ordering::SeqCst) {
        // Process all pending signals (non-blocking)
        for signal in signals.pending() {
            if sender.send(Message::Signal(signal)).is_err() {
                return;
            }
        }
        // Small sleep to prevent busy-waiting while keeping latency low
        thread::sleep(Duration::from_millis(100));
    }
}

/// Listens for keyboard input using non-blocking I/O.
/// Checks the `running` flag every 50ms when no input is available.
fn yield_keys(sender: Sender<Message>, running: Arc<AtomicBool>) {
    // async_stdin() provides a non-blocking reader
    let stdin = termion::async_stdin();
    let mut events = stdin.events();

    while running.load(Ordering::SeqCst) {
        match events.next() {
            Some(Ok(Event::Key(termion::event::Key::Char(c)))) => {
                if sender.send(Message::Key(c)).is_err() {
                    break;
                }
            }
            Some(Ok(_)) => {} // Ignore mouse/resizes
            Some(Err(_)) => break,
            None => {
                // No input available (WouldBlock), sleep briefly
                thread::sleep(Duration::from_millis(50));
            }
        }
    }
}

fn main() {
    // Enable raw mode to capture keys immediately
    let mut stdout = io::stdout().into_raw_mode().unwrap();

    let (sender, receiver) = channel();
    let running = Arc::new(AtomicBool::new(true));

    // Spawn signal thread
    let r1 = Arc::clone(&running);
    let s1 = sender.clone();
    let signal_handle = thread::spawn(move || {
        yield_signals(s1, r1);
    });

    // Spawn key thread
    let r2 = Arc::clone(&running);
    let s2 = sender;
    let key_handle = thread::spawn(move || {
        yield_keys(s2, r2);
    });

    write!(stdout, "Event loop started. Press 'q' to quit, or Ctrl+C\r\n").unwrap();
    stdout.flush().unwrap();

    // Main event loop
    for msg in receiver {
        match msg {
            Message::Signal(sig) => {
                write!(stdout, "Signal received: {}\r\n", sig).unwrap();
                stdout.flush().unwrap();
                if sig == SIGINT || sig == SIGTERM {
                    break;
                }
            }
            Message::Key(c) => {
                write!(stdout, "Key received: {}\r\n", c).unwrap();
                stdout.flush().unwrap();
                if c == 'q' {
                    break;
                }
            }
        }
    }

    // Signal threads to stop by setting the flag
    write!(stdout, "Shutting down threads...\r\n").unwrap();
    stdout.flush().unwrap();
    running.store(false, Ordering::SeqCst);

    // Wait for threads to finish (they will exit within ~100ms due to polling)
    signal_handle.join().unwrap();
    key_handle.join().unwrap();

    write!(stdout, "Shutdown complete\r\n").unwrap();
