    let mut tokens = Vec::new();
    let mut current = String::new();

    // Split by single quote to alternate between quoted and unquoted sections
    for (i, part) in input.split(''').enumerate() {
        if i % 2 == 0 {
            // Even indices: outside quotes
            // Spaces separate tokens; non-spaces accumulate in current token
            for ch in part.chars() {
                if ch == ' ' {
                    if !current.is_empty() {
                        tokens.push(std::mem::take(&mut current));
                    }
                } else {
                    current.push(ch);
                }
            }
        } else {
            // Odd indices: inside single quotes
            // Append verbatim to current token (preserving spaces)
            current.push_str(part);
        }
    }

    // Push any remaining content
    if !current.is_empty() {
        tokens.push(current);
    }

    tokens
}

