fn use_draggable(initial_x: f64, initial_y: f64) -> (Signal<Point2D>, Signal<bool>, EventHandler<MouseEvent>) {
    let ctx = use_context::<DragContext>();
    let position = use_signal(|| Point2D { x: initial_x, y: initial_y });
    let is_dragging = use_signal(|| false);
    let drag_start_pos = use_signal(|| Point2D::default());
    let drag_start_mouse = use_signal(|| Point2D::default());

    // React to global mouse movement when dragging
    use_effect(move || {
        // Subscribe to these signals
        let global_dragging = ctx.is_dragging();
        let global_mouse = ctx.mouse_pos();

        if !is_dragging() {
            return;
        }

        // If global dragging stopped (mouse up outside element), stop local dragging
        if !global_dragging {
            is_dragging.set(false);
            return;
        }

        // Update position: start_pos + (current_mouse - start_mouse)
        let start = drag_start_pos();
        let mouse_start = drag_start_mouse();

        position.set(Point2D {
            x: start.x + (global_mouse.x - mouse_start.x),
            y: start.y + (global_mouse.y - mouse_start.y),
        });
    });

    let onmousedown = move |e: MouseEvent| {
        // Record initial states
        drag_start_pos.set(*position.read());
        drag_start_mouse.set(Point2D { 
            x: e.client_x() as f64, 
            y: e.client_y() as f64 
        });

        // Activate dragging
        is_dragging.set(true);
        ctx.is_dragging.set(true);

        // Prevent event from bubbling to avoid parent handlers
        e.stop_propagation();
    };

    (position, is_dragging, EventHandler::new(onmousedown))
