    /// Return the display name of the operation
    fn name(&self) -> String {
        match self {
            MyOp::SqrtPlusOne => "sqrt_plus_one".to_string(),
            MyOp::Add => "add".to_string(),
            MyOp::Sub => "sub".to_string(),
            MyOp::Mul => "mul".to_string(),
            MyOp::Var(i) => format!("x{}", i),
            MyOp::Const(c) => format!("{:.2}", c),
        }
    }

    /// Define how many arguments this operation takes
    fn arity(&self) -> Arity {
        match self {
            MyOp::SqrtPlusOne => Arity::Fixed(1),  // Takes 1 argument
            MyOp::Add | MyOp::Sub | MyOp::Mul => Arity::Fixed(2),  // Binary ops
            MyOp::Var(_) | MyOp::Const(_) => Arity::Fixed(0),  // Terminals
        }
    }

    /// Define the logic of the operation
    fn eval(&self, inputs: &[f32]) -> f32 {
        match self {
            MyOp::SqrtPlusOne => {
                if inputs.is_empty() { 0.0 } else { inputs[0].sqrt() + 1.0 }
