            },
            MyOp::Mul => {
                if inputs.len() < 2 { 0.0 } else { inputs[0] * inputs[1] }
            },
            MyOp::Const(c) => *c,
            MyOp::Var(_) => 0.0, // Variables are filled during tree evaluation
        }
    }

    /// Required: Identify if this is a variable terminal
    fn is_variable(&self) -> bool {
        matches!(self, MyOp::Var(_))
    }

    /// Required: Identify if this is a constant terminal
    fn is_constant(&self) -> bool {
        matches!(self, MyOp::Const(_))
    }

