        .map_err(|e| format!("Failed to spawn '{}': {}", command, e))?;

    // 2. CRITICAL: Clone the session to separate read and write ownership.
    // This allows the read thread to block on `read()` without preventing writes.
    let mut reader_session = session
        .try_clone()
        .map_err(|e| format!("Failed to clone session for reader: {}", e))?;

    // 3. Create a channel for sending data from Tauri commands to the writer thread
    let (tx, rx) = mpsc::channel::<String>();

    // 4. Spawn the READER thread
    // This thread exclusively owns `reader_session` and emits output to the frontend.
    let app_handle = app.clone();
    thread::spawn(move || {
        let mut buf = [0u8; 1024];
        loop {
            match reader_session.read(&mut buf) {
                Ok(0) => {
                    let _ = app_handle.emit("agent-output", "[process terminated]\r\n");
                    break;
                }
                Ok(n) => {
                    let chunk = String::from_utf8_lossy(&buf[..n]);
                    if app_handle.emit("agent-output", chunk.to_string()).is_err() {
                        break; // Frontend disconnected
                    }
                }
                Err(e) => {
                    let _ = app_handle.emit("agent-output", format!("[read error: {}]\r\n", e));
                    break;
                }
            }
        }
    });

    // 5. Spawn the WRITER thread
    // This thread exclusively owns the original `session` (for writing) and listens on the channel.
    thread::spawn(move || {
        let mut writer_session = session;
        while let Ok(data) = rx.recv() {
            // Write keystrokes/lines from the frontend to the PTY
            if writer_session.write_all(data.as_bytes()).is_err() {
                break;
            }
            // Flush immediately for interactive responsiveness (e.g., vim, codex menus)
            if writer_session.flush().is_err() {
                break;
            }
        }
        // Session is dropped here when the channel closes, terminating the PTY process
    });

    // Store the sender in Tauri state so `send_to_agent` can use it
    *tx_guard = Some(tx);
    Ok(())
}

