/// This is non-blocking; it simply posts to the channel consumed by the writer thread.
#[command]
fn send_to_agent(message: String, state: State<'_, AppState>) -> Result<(), String> {
    let tx_guard = state.agent_tx.lock().unwrap();
    if let Some(tx) = tx_guard.as_ref() {
        tx.send(message).map_err(|e| format!("Failed to send to agent: {}", e))
    } else {
        Err("No agent running. Call start_agent first.".into())
    }
}

