        // Generate frame data into pre-allocated buffer
        fill_frame(&mut pixels, width, height, time);

        // Create shared memory file descriptor
        let fd = create_memfd(&pixels);
        let path = format!("/proc/self/fd/{}", fd);
        let encoded_path = STANDARD.encode(&path);

        // Close previous frame's fd (gives Kitty time to read it)
        if let Some(old_fd) = prev_fd.take() {
            unsafe { close(old_fd); }
        }
        prev_fd = Some(fd);

        // Send graphics command
        if frame_count == 0 {
            // First frame: transmit and place
            // t=t : shared memory transmission medium
            // f=24 : RGB format (3 bytes per pixel)
            write!(
                handle,
                "\x1b_Ga=t,t=t,f=24,s={},v={},i=1;{}\x1b\\",
                width, height, encoded_path
            ).unwrap();

            // Place image at (0,0), don't move cursor
            write!(
                handle,
                "\x1b_Ga=p,i=1,x=0,y=0,C=1;{}\x1b\\",
                STANDARD.encode("")
            ).unwrap();
        } else {
            // Update existing image (i=1) - automatically updates display
            write!(
                handle,
                "\x1b_Ga=t,t=t,f=24,s={},v={},i=1;{}\x1b\\",
                width, height, encoded_path
            ).unwrap();
        }

        handle.flush().unwrap();

        // Frame rate control
        let elapsed = frame_start.elapsed();
        if elapsed < FRAME_TIME {
            std::thread::sleep(FRAME_TIME - elapsed);
        }

        time += 0.05;
        frame_count += 1;

        // Print FPS to stderr every 60 frames
        if frame_count % 60 == 0 {
            let total_elapsed = start_time.elapsed().as_secs_f64();
            let fps = frame_count as f64 / total_elapsed;
            eprintln!("FPS: {:.1}", fps);
        }
    }
}

fn create_memfd(data: &[u8]) -> i32 {
    let name = CString::new("kitty-anim").unwrap();
    let fd = unsafe { memfd_create(name.as_ptr(), 0) };
    if fd < 0 {
        panic!("memfd_create failed: {}", io::Error::last_os_error());
    }

    // Set size
    if unsafe { ftruncate(fd, data.len() as i64) } < 0 {
        panic!("ftruncate failed");
    }

    // Write data
    let mut file = unsafe { std::fs::File::from_raw_fd(fd) };
    file.write_all(data).expect("write to memfd failed");
    file.flush().expect("flush memfd failed");

    // Keep FD open after function returns (Kitty needs to read it)
    let raw_fd = file.as_raw_fd();
    forget(file);
    raw_fd
}

fn fill_frame(buf: &mut [u8], width: usize, height: usize, time: f32) {
    let pi = std::f32::consts::PI;

    for y in 0..height {
        let fy = y as f32 / height as f32;
        for x in 0..width {
            let fx = x as f32 / width as f32;
            let idx = (y * width + x) * 3;

            let r = ((fx * pi + time).sin() * 0.5 + 0.5) * 255.0;
            let g = ((fy * pi + time * 1.3).sin() * 0.5 + 0.5) * 255.0;
            let b = (((fx + fy) * pi + time * 0.7).sin() * 0.5 + 0.5) * 255.0;

            buf[idx] = r as u8;
            buf[idx + 1] = g as u8;
            buf[idx + 2] = b as u8;
        }
    }
}

fn get_terminal_size() -> (usize, usize) {
    let mut ws: Winsize = unsafe { std::mem::zeroed() };

    if unsafe { ioctl(STDOUT_FILENO, TIOCGWINSZ, &mut ws) } < 0 {
        return (0, 0);
    }

    // If pixel dimensions are 0 (e.g., in a terminal without pixel info),
    // estimate from cell size (assuming 8x16 pixels per cell as fallback)
    let xpix = if ws.ws_xpixel > 0 {
        ws.ws_xpixel as usize
    } else {
        (ws.ws_col as usize) * 8
    };

    let ypix = if ws.ws_ypixel > 0 {
        ws.ws_ypixel as usize
    } else {
        (ws.ws_row as usize) * 16
    };

    (xpix, ypix)
}
