#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2")]
unsafe fn flip_line_avx2(line_bytes: &mut [u8]) {
    use std::arch::x86_64::*;
    let ptr = line_bytes.as_mut_ptr() as *mut __m256i;
    let vec = _mm256_loadu_si256(ptr);
    // Permute to reverse order of 8 x 32-bit lanes: indices 7,6,5,4,3,2,1,0
    // _mm256_set_epi32 takes args from high to low, so 0 goes to index 0
    let idx = _mm256_set_epi32(0, 1, 2, 3, 4, 5, 6, 7);
    let reversed = _mm256_permutevar8x32_epi32(vec, idx);
    _mm256_storeu_si256(ptr, reversed);
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "sse2")]
unsafe fn flip_line_sse2(line_bytes: &mut [u8]) {
    use std::arch::x86_64::*;
    let ptr = line_bytes.as_mut_ptr();
    let ptr2 = ptr.add(16);

    let low = _mm_loadu_si128(ptr as *const __m128i);
    let high = _mm_loadu_si128(ptr2 as *const __m128i);

    // Shuffle 32-bit lanes: 0x1B = 00 01 10 11 binary -> [3,2,1,0]
    let low_rev = _mm_shuffle_epi32(low, 0x1B);
    let high_rev = _mm_shuffle_epi32(high, 0x1B);

    // Swap the reversed halves
    _mm_storeu_si128(ptr as *mut __m128i, high_rev);
    _mm_storeu_si128(ptr2 as *mut __m128i, low_rev);
}

#[cfg(target_arch = "aarch64")]
#[target_feature(enable = "neon")]
unsafe fn flip_line_neon(line_bytes: &mut [u8]) {
    use std::arch::aarch64::*;

    let ptr = line_bytes.as_mut_ptr();
    // Load 32 bytes as two 128-bit vectors
    let data = vld1q_u8_x2(ptr);

    // Create index vectors to reverse 8 pixels (32 bytes)
    // First 16 bytes of result get bytes 28-31, 24-27, 20-23, 16-19 (pixels 7,6,5,4)
    let idx_low = vld1q_u8([
        28, 29, 30, 31, 24, 25, 26, 27,
        20, 21, 22, 23, 16, 17, 18, 19
    ].as_ptr());

    // Last 16 bytes of result get bytes 12-15, 8-11, 4-7, 0-3 (pixels 3,2,1,0)
    let idx_high = vld1q_u8([
        12, 13, 14, 15, 8, 9, 10, 11,
        4, 5, 6, 7, 0, 1, 2, 3
    ].as_ptr());

    let new_low = vqtbl2q_u8(data, idx_low);
    let new_high = vqtbl2q_u8(data, idx_high);

    vst1q_u8(ptr, new_low);
    vst1q_u8(ptr.add(16), new_high);
}

