/// Context that travels with the request through Pingora's lifecycle phases.
/// Clone is derive'd so we can pass it to spawned tasks.
#[derive(Clone)]
struct RequestContext {
    /// Store the parent span here. This is the key to "rehydrating" the trace context
    /// when Pingora calls back into your trait methods on potentially different threads.
    request_span: Span,
}

/// Simulates a Pingora-style proxy handler where different stages are called
/// asynchronously and potentially on different threads.
struct ProxyHandler;

impl ProxyHandler {
    /// Simulates Pingora's request_filter phase
    async fn request_filter(&self, ctx: RequestContext) {
        // Rehydrate: Create a child span explicitly specifying the parent.
        // This works even if we're now on a different thread from where the parent was created.
        let stage_span = info_span!(parent: &ctx.request_span, "stage_request_filter");

        async move {
            info!("Executing request filter logic");
            sleep(Duration::from_millis(10)).await;
            info!("Request filter complete");
        }
        .instrument(stage_span)
        .await;
    }

    /// Simulates Pingora's upstream_peer selection phase
    async fn upstream_peer(&self, ctx: RequestContext) {
        let stage_span = info_span!(parent: &ctx.request_span, "stage_upstream_peer");

        async move {
            info!("Selecting upstream peer");
            sleep(Duration::from_millis(20)).await;
            info!("Upstream peer selected");
        }
        .instrument(stage_span)
        .await;
    }

    /// Simulates Pingora's upstream response handling
    async fn upstream_response(&self, ctx: RequestContext) {
        let stage_span = info_span!(parent: &ctx.request_span, "stage_upstream_response");

        async move {
            info!("Processing upstream response");
            sleep(Duration::from_millis(15)).await;
            info!("Response processed");
        }
        .instrument(stage_span)
        .await;
    }
}

#[tokio::main]
async fn main() {
    // Initialize OpenTelemetry stdout exporter to visualize the span hierarchy
    let exporter = opentelemetry_stdout::SpanExporter::default();
    let provider = opentelemetry_sdk::trace::TracerProvider::builder()
        .with_simple_exporter(exporter)
        .build();
    let tracer = provider.tracer("pingora-proxy");

    // Set up the subscriber with both OpenTelemetry and console output
    tracing_subscriber::registry()
        .with(tracing_opentelemetry::layer().with_tracer(tracer))
        .with(tracing_subscriber::fmt::layer().with_filter(EnvFilter::new("info")))
        .init();

    info!("Starting proxy request simulation");

    // Create the root/parent span for the entire request lifecycle
    let request_span = info_span!(
        "http_request",
        http.method = "GET",
        http.route = "/api/data",
        http.host = "example.com"
    );

    // Initialize the context with the parent span
    let ctx = RequestContext {
        request_span: request_span.clone(),
    };

    let handler = ProxyHandler;

    // Execute the full request lifecycle within the parent span
    async {
        // Phase 1: Request filter (immediate)
        handler.request_filter(ctx.clone()).await;

        // Simulate time passing and potential thread switching
        // In Pingora, these phases may be called by different worker threads
        sleep(Duration::from_millis(50)).await;

