impl<'a, T> Iterator for ArrayIteratorFromDyn<'a, T> {
    type Item = (Vec<usize>, &'a T);

    fn next(&mut self) -> Option<Self::Item> {
        // Advance the first dimension
        self.current_index_option[0] = self.current_iterators[0].next();

        let ndims = self.selection_iterators.len();
        // Handle carry-over (odometer logic)
        for i in 0..ndims {
            if self.current_index_option[i] == None {
                if i == ndims - 1 {
                    return None; // All dimensions exhausted
                }
                // Reset current dimension and advance next
                self.current_iterators[i] = dyn_clone::clone_box(&*self.selection_iterators[i]);
                self.current_index_option[i] = self.current_iterators[i].next();
                self.current_index_option[i + 1] = self.current_iterators[i + 1].next();
            } else {
                break;
            }
        }

        let current_index: Vec<usize> = self.current_index_option.iter()
            .map(|x| x.unwrap())
            .collect();

        // Calculate flat index using strides
        let flat_idx: usize = current_index.iter()
            .zip(&self.strides)
            .map(|(i, s)| i * s)
            .sum();

        let current_value: &T = &self.array.store[flat_idx];
        Some((current_index, current_value))
    }
}

// Mutable iterator - uses raw pointer to bypass borrow checker limitations
// This is the standard approach (used by Vec::iter_mut, slice::iter_mut, etc.)
pub struct ArrayIteratorFromDynMut<'a, T> {
    ptr: *mut T,                    // Raw pointer to data (needed because &mut self in next() conflicts with &'a mut T return)
    dims: Vec<usize>,               // Copy of dimensions
    strides: Vec<usize>,            // Pre-calculated strides
    selection_iterators: Vec<Box<dyn ArrayViewIterator>>,
    current_iterators: Vec<Box<dyn ArrayViewIterator>>,
    current_index_option: Vec<Option<usize>>,
    _marker: PhantomData<&'a mut T>, // Marks that we conceptually hold &'a mut Array<T>
}

impl<'a, T> Iterator for ArrayIteratorFromDynMut<'a, T> {
    type Item = (Vec<usize>, &'a mut T);

    fn next(&mut self) -> Option<Self::Item> {
        // Advance the first dimension
        self.current_index_option[0] = self.current_iterators[0].next();

        let ndims = self.selection_iterators.len();
        // Handle carry-over (odometer logic)
        for i in 0..ndims {
            if self.current_index_option[i] == None {
                if i == ndims - 1 {
                    return None; // All dimensions exhausted
                }
                // Reset current dimension and advance next
                self.current_iterators[i] = dyn_clone::clone_box(&*self.selection_iterators[i]);
                self.current_index_option[i] = self.current_iterators[i].next();
                self.current_index_option[i + 1] = self.current_iterators[i + 1].next();
            } else {
                break;
            }
        }

        let current_index: Vec<usize> = self.current_index_option.iter()
            .map(|x| x.unwrap())
            .collect();

        // Calculate flat index using strides
        let flat_idx: usize = current_index.iter()
            .zip(&self.strides)
            .map(|(i, s)| i * s)
            .sum();

        // SAFETY: 
        // 1. `ptr` is valid as long as the Array is not reallocated. We hold PhantomData<&'a mut T>
        //    which ensures the Array is mutably borrowed for the lifetime of this iterator.
        // 2. The iterator logic ensures each index is visited at most once (no aliasing).
        // 3. The pointer derived from store.as_mut_ptr() is properly aligned and valid for store.len() elements.
        let current_value: &'a mut T = unsafe { &mut *self.ptr.add(flat_idx) };
        Some((current_index, current_value))
    }
}

fn main() {
    // Example: 2x3 array
    let data: Vec<f64> = (0..6).map(|x| x as f64).collect();
    let mut arr = Array::new(data, vec![2, 3]);

    println!("Original array:");
    for i in 0..2 {
        for j in 0..3 {
            let idx = i * 3 + j;
            print!("{:.0} ", arr.store[idx]);
        }
        println!();
    }

    println!("\nImmutable iteration over view [0..2, 1..3]:");
    let view = arr.view(vec![0..2, 1..3]);
    for (idx, val) in view {
        println!("Index {:?}: Value {}", idx, val);
    }

    println!("\nMutable iteration over view [0..2, 1..3]:");
    {
        let view_mut = arr.view_mut(vec![0..2, 1..3]);
        for (idx, val) in view_mut {
            *val *= 10.0;
            println!("Index {:?}: Modified to {}", idx, val);
        }
    }

    println!("\nArray after mutation:");
    for i in 0..2 {
        for j in 0..3 {
            let idx = i * 3 + j;
            print!("{:.0} ", arr.store[idx]);
        }
        println!();
    }

    println!("\nFull array verification:");
    for (idx, val) in arr.view(vec![0..2, 0..3]) {
        println!("{:?}: {}", idx, val);
    }
}
"
}
