name = "enum_dispatch_solution"
version = "0.1.0"
edition = "2021"

[dependencies]",
  "main.rs": "//! Solution to the enum_dispatch dilemma across crate boundaries.
//! 
//! This demonstrates how to use a declarative macro defined in the abstract layer (al)
//! to generate the enum and its trait implementation in the business layer (bl),
//! avoiding the cycle and keeping crates separate.

// ============================================================================
// Abstract Layer (al)
// Defines the trait and the code-generation macro
// ============================================================================
pub mod al {
    /// The trait with many methods (simulating 20 methods with 3)
    pub trait Rest {
        fn method1(&self) -> i32;
        fn method2(&self) -> String;
        fn method3(&self) -> bool;
        // ... imagine 17 more methods
    }

    /// Macro to generate an enum that implements Rest via static dispatch.
    /// This is invoked from the business layer (bl) where concrete types are known.
    #[macro_export]
    macro_rules! impl_rest_enum {
        (
            $vis:vis enum $enum_name:ident {
                $($variant:ident($variant_ty:ty)),* $(,)?
            }
        ) => {
            $vis enum $enum_name {
                $($variant($variant_ty)),*
            }

            impl $crate::al::Rest for $enum_name {
                fn method1(&self) -> i32 {
                    match self {
                        $(Self::$variant(inner) => inner.method1()),*
                    }
                }

                fn method2(&self) -> String {
                    match self {
                        $(Self::$variant(inner) => inner.method2()),*
                    }
                }

                fn method3(&self) -> bool {
                    match self {
                        $(Self::$variant(inner) => inner.method3()),*
                    }
                }
            }

            // Optional: Implement From for each variant for ergonomics
            $(
                impl From<$variant_ty> for $enum_name {
                    fn from(val: $variant_ty) -> Self {
                        Self::$variant(val)
                    }
                }
            )*
        };
    }
}

// ============================================================================
// Implementation Layer (il)
// Depends on al. Provides concrete implementations.
// ============================================================================
pub mod il {
    use crate::al::Rest;

    pub struct Foo {
        pub value: i32,
    }

    impl Rest for Foo {
        fn method1(&self) -> i32 { self.value * 10 }
        fn method2(&self) -> String { format!("Foo: {}", self.value) }
        fn method3(&self) -> bool { self.value > 0 }
    }

    pub struct Boo {
        pub name: String,
    }

    impl Rest for Boo {
        fn method1(&self) -> i32 { self.name.len() as i32 }
        fn method2(&self) -> String { self.name.clone() }
        fn method3(&self) -> bool { !self.name.is_empty() }
    }
}

// ============================================================================
// Business Layer (bl)
// Depends on both al and il. Defines the dispatch enum using the macro from al.
// ============================================================================
pub mod bl {
    use crate::il::{Foo, Boo};

    // Generate the enum and Rest implementation here, where we know the types.
    // This works because the macro is expanded in this module, where both the
    // trait (from al) and the types (from il) are in scope.
    crate::impl_rest_enum! {
        pub enum Item {
            Foo(Foo),
            Boo(Boo),
        }
    }

    pub fn process_item(item: &Item) {
        println!("Processing item:");
        println!("  method1: {}", item.method1());
        println!("  method2: {}", item.method2());
        println!("  method3: {}", item.method3());
    }

    // Demonstrate that we get static dispatch (monomorphization)
    pub fn generic_processor<T: super::al::Rest>(item: &T) -> String {
        format!("Generic: {}", item.method2())
    }
}

// ============================================================================
// Application Entry Point
// ============================================================================
fn main() {
    use bl::Item;
    use il::{Foo, Boo};

    // Create instances using the auto-generated From implementations
    let foo: Item = Foo { value: 42 }.into();
    let boo: Item = Boo { name: "Hello World".to_string() }.into();

    // Use static dispatch through the enum
    bl::process_item(&foo);
    bl::process_item(&boo);

    // Verify we can use the enum in generic contexts (proving static dispatch)
    println!("{}", bl::generic_processor(&foo));
    println!("{}", bl::generic_processor(&boo));

    println!("\nSuccess! Static dispatch works across crate boundaries without cycles.");
}"
}
