use futures_lite::Stream;
use std::collections::HashMap;
use std::io::{Cursor, Read, Seek, SeekFrom};
use std::path::{Path, PathBuf};

// Custom asset type for demonstration
#[derive(Asset, TypePath, Debug, Clone)]
struct TextAsset(String);

// AssetLoader to process the bytes from our lazy reader
#[derive(Default)]
struct TextAssetLoader;

impl AssetLoader for TextAssetLoader {
    type Settings = ();
    type Error = std::io::Error;

    async fn load<'a>(
        &'a self,
        reader: &'a mut Reader<'_>,
        _settings: &'a Self::Settings,
        _load_context: &'a mut LoadContext<'_>,
    ) -> Result<TextAsset, Self::Error> {
        let mut bytes = Vec::new();
        reader.read_to_end(&mut bytes).await?;
        Ok(TextAsset(String::from_utf8_lossy(&bytes).to_string()))
    }

    fn extensions(&self) -> &[&str] {
        &["txt"]
    }
}

// Index entry: (offset_in_file, size_in_bytes)
type EntryInfo = (u64, u64);

#[derive(Clone)]
struct ArchiveIndex {
    entries: HashMap<String, EntryInfo>,
    archive_path: PathBuf,
}

// The lazy asset reader - only reads specific entries when requested
struct LazyArchiveReader {
    index: ArchiveIndex,
}

impl AssetReader for LazyArchiveReader {
    async fn read<'a>(&'a self, path: &'a Path) -> Result<impl Reader, AssetReaderError> {
        let key = path.to_string_lossy().to_string();

        let (offset, size) = self.index.entries.get(&key).copied().ok_or_else(|| {
            AssetReaderError::NotFound(path.to_path_buf())
        })?;

        // Open archive and seek to specific entry - lazy loading!
        // In production, use a file handle pool or async-fs to avoid blocking
        let mut file = std::fs::File::open(&self.index.archive_path)
            .map_err(AssetReaderError::Io)?;
        file.seek(SeekFrom::Start(offset))
            .map_err(AssetReaderError::Io)?;

        let mut buffer = vec![0u8; size as usize];
        file.read_exact(&mut buffer)
            .map_err(AssetReaderError::Io)?;

        Ok(Cursor::new(buffer))
    }

    async fn read_meta<'a>(&'a self, path: &'a Path) -> Result<impl Reader, AssetReaderError> {
        Err(AssetReaderError::NotFound(path.to_path_buf()))
    }

    async fn read_directory<'a>(&'a self, _path: &'a Path) -> Result<Box<PathStream>, AssetReaderError> {
        Ok(Box::new(futures_lite::stream::empty::<PathBuf>()))
    }

    async fn is_directory<'a>(&'a self, _path: &'a Path) -> Result<bool, AssetReaderError> {
        Ok(false)
    }
}

#[derive(Clone)]
struct LazyArchiveSource {
    index: ArchiveIndex,
}

impl AssetSource for LazyArchiveSource {
    fn create_reader(&self) -> Box<dyn AssetReader> {
        Box::new(LazyArchiveReader {
            index: self.index.clone(),
        })
    }

    fn watch_for_changes(&self) -> bool {
        false // Disable watching for archive files
    }
}

// Creates a mock archive file with 100 "textures"
fn create_demo_archive() -> (PathBuf, HashMap<String, EntryInfo>) {
    use std::io::Write;

    let path = std::env::temp_dir().join("demo_lazy_archive.bin");
    let mut file = std::fs::File::create(&path).expect("Failed to create archive");
    let mut entries = HashMap::new();
    let mut offset: u64 = 0;

    println!("Creating demo archive with 100 entries at:\n{:?}\n", path);

    for i in 0..100 {
        let name = format!("textures/texture_{:03}.txt", i);
        let content = format!("This is texture {} data (imagine this is a 64KB WAD texture)", i);
        let bytes = content.as_bytes();

        entries.insert(name, (offset, bytes.len() as u64));
        file.write_all(bytes).unwrap();
        offset += bytes.len() as u64;
    }

    (path, entries)
}

#[derive(Resource)]
struct LoadedHandles {
    handle1: Handle<TextAsset>,
    handle2: Handle<TextAsset>,
}

fn main() {
    let (archive_path, entries) = create_demo_archive();

    let archive_source = LazyArchiveSource {
        index: ArchiveIndex {
            entries,
            archive_path,
        },
    };

    App::new()
        .add_plugins(DefaultPlugins.set(AssetPlugin {
            sources: vec![
                ("wad".to_string(), Box::new(move |_assets_root| {
                    Box::new(archive_source.clone()) as Box<dyn AssetSource>
                })),
            ],
            ..default()
        }))
        .init_asset::<TextAsset>()
        .init_asset_loader::<TextAssetLoader>()
        .add_systems(Startup, setup)
        .add_systems(Update, check_loaded)
        .run();
}

fn setup(mut commands: Commands, asset_server: Res<AssetServer>) {
    // Show how to get the assets folder path
    let assets_root = asset_server.asset_root_path();
    println!("Assets folder path: {:?}\n", assets_root);

    println!("Loading only 2 specific textures from the archive...");
    println!("(The other 98 textures are NOT loaded into memory)\n");

    // Load only specific entries - lazy loading!
    // Format: "wad://<path_inside_archive>"
    let handle1: Handle<TextAsset> = asset_server.load("wad://textures/texture_005.txt");
    let handle2: Handle<TextAsset> = asset_server.load("wad://textures/texture_042.txt");

    commands.insert_resource(LoadedHandles { handle1, handle2 });
}

fn check_loaded(
    handles: Res<LoadedHandles>,
    assets: Res<Assets<TextAsset>>,
    asset_server: Res<AssetServer>,
) {
    if asset_server.is_loaded_with_dependencies(&handles.handle1) {
        if let Some(asset) = assets.get(&handles.handle1) {
            println!("Loaded texture_005: {}", asset.0);
        }
    }
    if asset_server.is_loaded_with_dependencies(&handles.handle2) {
        if let Some(asset) = assets.get(&handles.handle2) {
            println!("Loaded texture_042: {}", asset.0);
        }
    }
}
