/// Rewrite all imports in the syntax tree, flattening vexide::devices::* to vexide::*
pub fn rewrite_imports(root: SyntaxNode) -> SyntaxNode {
    // Collect all Use items first to avoid iterator invalidation during replacement
    let use_items: Vec<_> = root.descendants().filter_map(Use::cast).collect();

    let mut result = root;
    for use_item in use_items {
        if let Some(new_use) = transform_use_item(&use_item) {
            result = result.replace_child(use_item.syntax().clone(), new_use.syntax().clone());
        }
    }

    result
