fn transform_use_item(use_item: &Use) -> Option<Use> {
    let tree = use_item.use_tree()?;
    let new_tree = transform_use_tree(tree, None)?;
    Some(make::use_(new_tree))
}

/// Recursively transform a use tree.
/// 
/// `prefix` is the path from the root to this tree's parent (e.g., "vexide" for items inside `use vexide::{...}`)
/// Returns None if the tree should be removed (e.g., importing the removed `devices` module itself)
fn transform_use_tree(tree: UseTree, prefix: Option<&str>) -> Option<UseTree> {
    let path = tree.path()?;
    let path_str = path.syntax().text().to_string();

    // Construct the full effective path (e.g., "vexide::devices::smart")
    let effective_path = match prefix {
        Some(p) => format!("{}::{}", p, path_str),
        None => path_str.clone(),
    };

    // Check if this path starts with "vexide::devices"
    if effective_path.starts_with("vexide::devices") {
        // Calculate the new path with "devices" removed
        // vexide::devices::foo -> vexide::foo
        // vexide::devices -> vexide
        let new_effective = if effective_path == "vexide::devices" {
            "vexide".to_string()
        } else {
            effective_path.replacen("vexide::devices", "vexide", 1)
        };

        // Calculate the path relative to the parent (for nested imports)
        // If parent is "vexide" and new_effective is "vexide::foo", local path is "foo"
        let new_local = if let Some(p) = prefix {
            let prefix_with_colon = format!("{}::", p);
            if new_effective.starts_with(&prefix_with_colon) {
                new_effective[prefix_with_colon.len()..].to_string()
            } else if new_effective == p {
                // This was exactly the parent module (e.g., importing `devices` inside `vexide`)
                // Remove it since we're flattening
                return None;
            } else {
                new_effective.clone()
            }
        } else {
            new_effective.clone()
        };

        let new_path = make::path_from_str(&new_local);

        // Handle nested imports: vexide::devices::{foo, bar} -> vexide::{foo, bar}
        if let Some(list) = tree.use_tree_list() {
            let new_children: Vec<_> = list.use_trees()
                .filter_map(|t| transform_use_tree(t, Some(&new_effective)))
                .collect();

            if new_children.is_empty() {
                // All children were removed, return just the path
                Some(make::use_tree(new_path, None, false))
            } else {
                let new_list = make::use_tree_list(new_children);
                Some(make::use_tree(new_path, Some(new_list), false))
            }
        } else {
            // Handle glob imports: vexide::devices::* -> vexide::*
            let is_glob = tree.star_token().is_some();

            // If this was exactly `vexide::devices` without children, remove it
            // (or you could keep it as `vexide` depending on your needs)
            if effective_path == "vexide::devices" && !is_glob {
                return None;
            }

            Some(make::use_tree(new_path, None, is_glob))
        }
    } else {
        // Not our target path, but recursively check children with updated prefix
        let child_prefix = Some(effective_path.as_str());

        if let Some(list) = tree.use_tree_list() {
            let original_count = list.use_trees().count();
            let new_children: Vec<_> = list.use_trees()
                .filter_map(|t| transform_use_tree(t, child_prefix))
                .collect();

