use std::task::{Context, Poll, RawWaker, RawWakerVTable, Waker};
use std::time::Duration;

/// Result of trying to poll a future once
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Create a no-op waker for synchronous polling
fn noop_waker() -> Waker {
    fn noop_clone(_: *const ()) -> RawWaker {
        noop_raw_waker()
    }
    fn noop(_: *const ()) {}

    const VTABLE: RawWakerVTable = RawWakerVTable::new(noop_clone, noop, noop, noop);

    fn noop_raw_waker() -> RawWaker {
        RawWaker::new(std::ptr::null(), &VTABLE)
    }

    unsafe { Waker::from_raw(noop_raw_waker()) }
}

/// Try to poll a future once synchronously.
/// 
/// - If the future is ready, returns Ready with the value.
/// - If the future is pending, spawns it as a tokio task and returns Pending.
/// 
/// Note: This takes ownership of the future because spawning requires moving 
/// the future into the new task. If you need &mut, the future would need to be 
/// Unpin and 'static to spawn, but ownership is cleaner for this pattern.
fn try_poll<F, X>(future: F) -> TryPollResult<X>
where
    F: Future<Output = X> + Send + 'static,
    X: Send + 'static + std::fmt::Debug,
{
    // Pin the future on the heap so we can poll it
    let mut future = Box::pin(future);

    // Create a noop waker since we don't need to be woken up - we're polling synchronously
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);

    // Attempt to poll the future once
    match future.as_mut().poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => {
            // Future is not ready, spawn it as a task to await completion
            tokio::spawn(async move {
                let result = future.await;
                println!("  [Spawned task completed with: {:?}]", result);
                // Use the result here as needed
            });
            TryPollResult::Pending
        }
    }
}

/// Example non-async function called from async context
fn process_future<F, X>(future: F) -> String
where
    F: Future<Output = X> + Send + 'static,
    X: Send + 'static + std::fmt::Debug,
{
    match try_poll(future) {
        TryPollResult::Ready(val) => {
            format!("Ready immediately: {:?}", val)
        }
        TryPollResult::Pending => {
            "Pending - spawned background task".to_string()
        }
    }
}

#[tokio::main]
async fn main() {
    println!("Test 1: Immediately ready future");
    let ready_future = async { 42 };
    let result = process_future(ready_future);
    println!("Result: {}\n", result);

    println!("Test 2: Pending future (will sleep for 100ms)");
    let pending_future = async {
        tokio::time::sleep(Duration::from_millis(100)).await;
        "delayed value"
    };
    let result = process_future(pending_future);
    println!("Result: {}", result);

    // Wait for spawned tasks to complete
    tokio::time::sleep(Duration::from_millis(200)).await;
    println!("\nAll tasks completed");
}"
}
