        4.0, 5.0, 6.0,
        7.0, 8.0, 9.0,
        10.0, 11.0, 12.0,
    ];
    let matrix = DMatrix::from_row_slice(4, 3, &data);

    println!("Original matrix (4x3):");
    println!("{}", matrix);

    // Compute column means (averaging across rows)
    // row_mean() returns a RowVector (1 x k)
    let mean = matrix.row_mean();
    println!("\nColumn means: {}", mean);

    // Method 1: Using map_with_location (idiomatic, no temporary matrices)
    // For each element at (_row, col), subtract the mean of that column
    let centered = matrix.map_with_location(|_row, col, val| val - mean[col]);

    println!("\nCentered matrix (subtracting column means):");
    println!("{}", centered);

    // Verify: new column means should be approximately zero
    let new_means = centered.row_mean();
    println!("\nColumn means after centering: {}", new_means);

    // Method 2: Using matrix multiplication for explicit broadcasting
    // Create a column vector of ones (n x 1) and multiply by row means (1 x k)
    // Result is an (n x k) matrix where each row is the mean vector
    println!("\n--- Alternative Method using matrix multiplication ---");
    let ones = DMatrix::from_element(matrix.nrows(), 1, 1.0);
    let mean_matrix = ones * mean; // (4x1) * (1x3) = 4x3
    let centered_alt = matrix.clone() - mean_matrix;

    println!("Centered (alternative method):");
    println!("{}", centered_alt);

    let max_diff = (&centered - &centered_alt).abs().max();
    println!("\nMax difference between methods: {}", max_diff);
}"
}
