/// Derive macro implementing `Foo` by delegating to an inherent method.
/// 
/// This generates a helper module inside the method where the trait `Foo`
/// is not in scope, ensuring that `self.go()` resolves only to the inherent
/// method and fails to compile if it is missing (rather than recursing).
#[proc_macro_derive(Foo)]
pub fn derive_foo(input: TokenStream) -> TokenStream {
    let input = parse_macro_input!(input as DeriveInput);
    let name = &input.ident;

    // Split generics for impl block
    let (impl_generics, ty_generics, where_clause) = input.generics.split_for_impl();

    // Get original generics params for the helper function (preserves bounds like T: Clone)
    let generics_params = &input.generics.params;

    // Generate a unique module name to avoid collisions
    let helper_mod = syn::Ident::new(
        &format!("__foo_derive_{}", name).to_lowercase(),
        proc_macro2::Span::call_site(),
    );

    let expanded = quote! {
        impl #impl_generics Foo for #name #ty_generics #where_clause {
            fn go(&self) {
                // Internal module: trait Foo is NOT in scope here
                mod #helper_mod {
                    // Bring the concrete type into scope
                    use super::#name;

                    // Helper function mirrors the generics and bounds of the impl
                    #[inline(always)]
                    pub fn __go<#generics_params>(this: &#name #ty_generics) #where_clause {
                        // This resolves ONLY to the inherent method `fn go(&self)`
                        // If the inherent method is missing, this is a compile error.
                        this.go();
                    }
                }

                // Delegate to the helper
                #helper_mod::__go(self);
            }
        }
    };

    TokenStream::from(expanded)
}

// The trait definition (for reference - normally this would be in your main crate)
pub trait Foo {
    fn go(&self);
}
