/// rather than EncapsulatedContentInfo, and certificates are SET OF Certificate
/// rather than SET OF CertificateChoices.
#[derive(Clone, Debug, Sequence)]
pub struct Pkcs7SignedData {
    pub version: u8,
    pub digest_algorithms: SetOfVec<AlgorithmIdentifier>,
    /// Inner ContentInfo (PKCS#7 style - raw content, not wrapped in OCTET STRING)
    pub content_info: ContentInfo,
    /// [0] IMPLICIT SET OF Certificate
    #[rasn(tag(0), mode = "IMPLICIT")]
    pub certificates: Option<SetOfVec<Certificate>>,
    /// [1] IMPLICIT SET OF CRL (optional, parsed as raw Any to avoid complexity)
    #[rasn(tag(1), mode = "IMPLICIT")]
    pub crls: Option<Any>,
    /// SET OF SignerInfo
    pub signer_infos: SetOfVec<SignerInfo>,
}

/// Simple AlgorithmIdentifier for the digest algorithms set
#[derive(Clone, Debug, Sequence)]
pub struct AlgorithmIdentifier {
    pub algorithm: ObjectIdentifier,
    pub parameters: Option<Any>,
