            std::process::exit(1);
        }
    };

    // Step 2: Decode content as PKCS#7 SignedData
    // Note: We use .value() to get the raw bytes from the Any type
    let signed_data = match Pkcs7SignedData::from_der(outer_ci.content.value()) {
        Ok(sd) => {
            println!("Successfully decoded PKCS#7 SignedData");
            sd
        }
        Err(e) => {
