use serde::Deserialize;
use tokio::sync::mpsc;

/// The borrowed data structure with references into the original JSON string
#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

/// Self-referential struct that owns the String buffer and holds the deserialized
/// struct with references pointing into that buffer. This allows moving both the
/// data and the references across thread boundaries (Send) without cloning.
#[self_referencing]
struct DataBundle {
    /// The owned buffer containing the raw JSON text
    json_text: String,

    /// The deserialized struct borrowing from json_text.
    /// 'this is the lifetime of the borrow.
    #[borrows(json_text)]
    #[covariant]
    parsed: MyData<'this>,
}

// DataBundle is automatically Send because String is Send and MyData<'a> (which
// contains only &str references) is Send. This allows passing it across tokio tasks.

#[tokio::main]
async fn main() {
    // Channel to pass the bundle between tasks
    let (tx, mut rx) = mpsc::channel::<DataBundle>(32);

    // Spawn worker task that receives the bundle
    let handle = tokio::spawn(async move {
        while let Some(bundle) = rx.recv().await {
            // Access the parsed data through the bundle.
            // The closure ensures we can't outlive the borrowed references.
            bundle.with_parsed(|data| {
                println!("Worker task received:");
                println!("  data: {}", data.data);
                println!("  more_data: {}", data.more_data);
                println!("  (zero copy: references point into original String buffer)");
            });
        }
        println!("Worker task finished");
    });

    // Simulate receiving JSON from a TCP stream or network
    let json_input = r#"{"data": "hello from network", "more_data": "zero copy!"}"#.to_string();

    // Deserialize once into the self-referential struct.
    // This binds the lifetime of the parsed MyData to the json_text String.
    let bundle = DataBundle::try_new(json_input, |text| {
        serde_json::from_str(text)
    }).expect("JSON parsing failed (note: serde_json can only borrow strings without escape sequences)");

    // Send across task boundary without cloning the string data
    if let Err(e) = tx.send(bundle).await {
        eprintln!("Failed to send: {}", e);
    }

    // Clean up channel and wait for worker
    drop(tx);
    let _ = handle.await;
}
