use std::{
    future::Future,
    pin::Pin,
    sync::Arc,
    task::{Context, Poll},
};
use tokio::net::TcpListener;
use tower::{Layer, Service};

/// Tower Layer that validates Origin headers for WebSocket upgrade requests
#[derive(Clone)]
pub struct WebSocketOriginLayer {
    allowed_origin: Arc<String>,
}

impl WebSocketOriginLayer {
    pub fn new(allowed_origin: impl Into<String>) -> Self {
        Self {
            allowed_origin: Arc::new(allowed_origin.into()),
        }
    }
}

impl<S> Layer<S> for WebSocketOriginLayer {
    type Service = WebSocketOriginService<S>;

    fn layer(&self, inner: S) -> Self::Service {
        WebSocketOriginService {
            inner,
            allowed_origin: self.allowed_origin.clone(),
        }
    }
}

/// Tower Service that checks the Origin header on WebSocket handshakes
#[derive(Clone)]
pub struct WebSocketOriginService<S> {
    inner: S,
    allowed_origin: Arc<String>,
}

impl<S> Service<Request> for WebSocketOriginService<S>
where
    S: Service<Request, Response = Response> + Send + 'static,
    S::Future: Send + 'static,
{
    type Response = S::Response;
    type Error = S::Error;
    type Future = Pin<Box<dyn Future<Output = Result<Self::Response, Self::Error>> + Send>>;

    fn poll_ready(&mut self, cx: &mut Context<'_>) -> Poll<Result<(), Self::Error>> {
        self.inner.poll_ready(cx)
    }

    fn call(&mut self, req: Request) -> Self::Future {
        // Check if this is a WebSocket upgrade request
        let is_websocket = req
            .headers()
            .get(header::UPGRADE)
            .and_then(|v| v.to_str().ok())
            .map(|v| v.eq_ignore_ascii_case("websocket"))
            .unwrap_or(false);

        if is_websocket {
            let origin = req
                .headers()
                .get(header::ORIGIN)
                .and_then(|v| v.to_str().ok());

            // Reject if origin doesn't match (case-sensitive)
            if origin != Some(self.allowed_origin.as_str()) {
                let response = StatusCode::FORBIDDEN.into_response();
                return Box::pin(async move { Ok(response) });
            }
        }

        // Proceed to the inner service (handler)
        let future = self.inner.call(req);
        Box::pin(async move { future.await })
    }
}

// WebSocket handler - only reachable if origin check passes
async fn ws_handler(ws: WebSocketUpgrade) -> impl IntoResponse {
    ws.on_upgrade(handle_socket)
}

async fn handle_socket(mut socket: WebSocket) {
    while let Some(Ok(msg)) = socket.recv().await {
        if socket.send(msg).await.is_err() {
            break;
        }
    }
}

// Regular HTTP handler (not affected by WebSocket origin check)
async fn http_handler() -> &'static str {
    "Hello, HTTP!"
}

#[tokio::main]
async fn main() {
    let allowed_origin = "https://www.example.com";

    let app = Router::new()
        .route("/ws", get(ws_handler))
        .route("/http", get(http_handler))
        // Apply the origin check layer at the router level
        .layer(WebSocketOriginLayer::new(allowed_origin));

    let listener = TcpListener::bind("127.0.0.1:3000").await.unwrap();
    println!("Server running on http://{}", listener.local_addr().unwrap());
    println!("WebSocket endpoint: ws://127.0.0.1:3000/ws");
    println!("Allowed origin for WS: {}", allowed_origin);

    axum::serve(listener, app).await.unwrap();
}"
}
