                /// # Safety
                ///
                /// We use #[doc = ...] to interpolate the type string.
                #[doc = #safety_doc]
                pub const fn #method_name(&self) -> #typ {
                    #[allow(unsafe_code)]
                    unsafe {
                        *::core::ptr::from_ref(self)
                            .cast::<#typ>()
                    }
                }
            }
        }
        _ => unimplemented!("Only enums are supported"),
    };

    quote! {
        #[repr(#typ)]
        #input

        impl #impl_generics #name #ty_generics #where_clause {
            #body
        }
    }
}

struct Args {
    typ: Type,
    method_name: Option<Ident>,
}

impl Parse for Args {
    fn parse(input: ParseStream<'_>) -> syn::Result<Self> {
        let typ: Type = input.parse()?;

        if input.is_empty() {
            return Ok(Self {
                typ,
                method_name: None,
            });
        };

        let _: Comma = input.parse()?;
        let method_name = input.parse()?;

        if !input.is_empty() {
            return Err(input.error("Unexpected tokens after method name"));
        }

        Ok(Self {
            typ,
            method_name,
        })
    }
}

fn main() {
    // Example usage: equivalent to #[repr_discriminant(u8, id)]
    let args = quote!(u8, id);
    let input = quote! {
        enum Foo {
            Bar(String) = 0x02,
        }
    };

    let expanded = repr_discriminant(args, input);

    println!("// Expanded code:");
    println!("{}", expanded);

    // Verify the doc comment contains the actual type, not the literal '#typ'
    let expanded_str = expanded.to_string();
    if expanded_str.contains("repr(u8)") && !expanded_str.contains("repr(#typ)") {
        println!("\n// Success! The type was correctly interpolated into the docstring.");
    } else {
        println!("\n// Error: Type interpolation failed.");
    }
}"
}
