// Helper trait to handle the higher-ranked lifetime (for<'a>)
trait AsyncFnHelper<'a> {
    type Fut: Future<Output = ()> + 'a;
    fn call(&self, arg: &'a mut String) -> Self::Fut;
}

impl<'a, F, Fut> AsyncFnHelper<'a> for F
where
    F: Fn(&'a mut String) -> Fut,
    Fut: Future<Output = ()> + 'a,
{
    type Fut = Fut;
    fn call(&self, arg: &'a mut String) -> Self::Fut {
        (self)(arg)
    }
}

// Public trait using GATs (Generic Associated Types) to abstract over async functions
trait AsyncFn {
    type Fut<'a>: Future<Output = ()> + 'a
    where
        Self: 'a;
    fn call<'a>(&self, arg: &'a mut String) -> Self::Fut<'a>;
}

impl<T> AsyncFn for T
where
    T: for<'a> AsyncFnHelper<'a>,
{
    type Fut<'a> = <Self as AsyncFnHelper<'a>>::Fut where Self: 'a;
    fn call<'a>(&self, arg: &'a mut String) -> Self::Fut<'a> {
        <Self as AsyncFnHelper<'a>>::call(self, arg)
    }
}

async fn harness<T>(test: T)
where
    T: AsyncFn,
{
    let mut string = String::new();
    test.call(&mut string).await;
    println!("new string is:\n{string}");
}

#[tokio::main]
async fn main() {
    harness(simple_test).await;
}"
