fn yield_signals(sender: Sender<Message>, stop_recv: Receiver<()>) {
    // Internal channel to bridge the blocking signal iterator
    let (internal_send, internal_recv) = unbounded::<i32>();

    // Spawn helper thread that blocks on signals
    thread::spawn(move || {
        let mut signals = Signals::new(&[SIGINT, SIGTERM]).unwrap();
        for sig in signals.forever() {
