    // Main loop selects between keys and stop command
    loop {
        select! {
            recv(internal_recv) -> event => {
                if let Ok(Ok(Event::Key(key))) = event {
                    if sender.send(Message::Key(key)).is_err() {
                        break;
                    }
                }
            }
            recv(stop_recv) -> _ => {
                // Stop message received, exit immediately without waiting for next key
                break;
            }
        }
