    // Create stop channels for each worker thread
    let (stop_tx_signals, stop_rx_signals) = unbounded::<()>();
    let (stop_tx_keys, stop_rx_keys) = unbounded::<()>();

    // Spawn signal handler thread
    let tx_signals = tx.clone();
    let handle_signals = thread::spawn(move || {
        yield_signals(tx_signals, stop_rx_signals);
    });

    // Spawn key handler thread
    let tx_keys = tx.clone();
    let handle_keys = thread::spawn(move || {
        yield_keys(tx_keys, stop_rx_keys);
