/// This uses `tokio_util::io::ReaderStream` to convert the `AsyncRead` (File) into a `Stream`,
/// then maps each `Bytes` chunk into a `Frame::data` to create a streaming body.
async fn serve_file(_req: Request<Incoming>) -> Result<Response<BoxBody>, io::Error> {
    // For this example, we serve Cargo.toml from the project root
    let path = Path::new("Cargo.toml");

    // Open the file
    let file = File::open(path).await?;

    // Convert the AsyncRead (File) into a Stream of Bytes
    let reader_stream = ReaderStream::new(file);

    // Map the stream from io::Result<Bytes> to io::Result<Frame<Bytes>>
    // Frame::data is used to create DATA frames for the HTTP body
    let frame_stream = reader_stream.map(|result| {
        result.map(|bytes| Frame::data(bytes))
    });

    // Create a body from the stream of frames
    let body = StreamBody::new(frame_stream);

    // Box the body to erase the complex stream type and make it easier to return
    let boxed_body = body.boxed();

    Ok(Response::builder()
        .status(StatusCode::OK)
        .header("content-type", "text/plain")
        .body(boxed_body)
        .unwrap())
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    let addr = "127.0.0.1:8080";
    let listener = TcpListener::bind(addr).await?;
    println!("Listening on http://{}", addr);
    println!("This server streams Cargo.toml as an example file");
    println!("Try: curl http://{}", addr);

    loop {
        let (stream, _) = listener.accept().await?;
        let io = hyper_util::rt::TokioIo::new(stream);

        let service = hyper::service::service_fn(serve_file);

        tokio::spawn(async move {
            if let Err(err) = hyper::server::conn::http1::Builder::new()
                .serve_connection(io, service)
                .await
            {
                eprintln!("Error serving connection: {:?}", err);
            }
        });
    }
}
"
}
