use std::time::Duration;
use tokio::signal;
use tokio::sync::{broadcast, mpsc};
use tokio::task::JoinHandle;
use tokio::time::timeout;
use tokio_stream::wrappers::BroadcastStream;

#[derive(Debug, Clone)]
pub struct Event {
    pub id: u64,
    pub data: String,
}

/// The central hub that manages the broadcast channel lifecycle.
pub struct EventsHub {
    /// The main broadcast sender. When this and all clones are dropped,
    /// all BroadcastStreams will receive RecvError::Closed and terminate.
    broadcast_tx: broadcast::Sender<Event>,
    /// Channel to send events to the proxy task.
    mpsc_tx: mpsc::UnboundedSender<Event>,
    /// Handle to the proxy task that forwards mpsc messages to broadcast.
    proxy_handle: JoinHandle<()>,
}

impl EventsHub {
    pub fn new(capacity: usize) -> Self {
        let (broadcast_tx, _) = broadcast::channel(capacity);
        let (mpsc_tx, mut mpsc_rx) = mpsc::unbounded_channel::<Event>();

        // The proxy task holds one clone of the broadcast sender.
        // When this task exits, it drops its clone.
        let tx_for_proxy = broadcast_tx.clone();
        let proxy_handle = tokio::spawn(async move {
            while let Some(event) = mpsc_rx.recv().await {
                // Ignore errors when there are no receivers (lagged/closed)
                let _ = tx_for_proxy.send(event);
            }
            println!("[Hub] Proxy task exiting, dropping broadcast sender clone");
        });

        Self {
            broadcast_tx,
            mpsc_tx,
            proxy_handle,
        }
    }

    /// Create a new event sender. This can be cloned and sent to multiple tasks.
    /// It does NOT hold the broadcast sender, so dropping it is not required for shutdown.
    pub fn event_sender(&self) -> EventSender {
        EventSender {
            tx: self.mpsc_tx.clone(),
        }
    }

    /// Create a stream factory. NOTE: To fully shutdown, all instances of
    /// EventStreamFactory must be dropped (or call subscribe() and drop the factory).
    pub fn stream_factory(&self) -> EventStreamFactory {
        EventStreamFactory {
            tx: self.broadcast_tx.clone(),
        }
    }

    /// Gracefully shutdown the hub:
    /// 1. Close the mpsc channel (stops accepting new events).
    /// 2. Wait for the proxy task to exit (drops its broadcast sender clone).
    /// 3. Drop the main broadcast sender.
    /// After this, if all EventStreamFactories are also dropped, all BroadcastStreams will end.
    pub async fn shutdown(self) {
        println!("[Hub] Closing mpsc channel...");
        drop(self.mpsc_tx);

        // Wait for the proxy task to finish and drop its sender clone
        if timeout(Duration::from_secs(5), self.proxy_handle)
            .await
            .is_err()
        {
            println!("[Hub] Warning: Proxy task did not exit in time");
        }

        println!("[Hub] Dropping main broadcast sender...");
        // self.broadcast_tx is dropped here as self goes out of scope
    }
}

