impl EventStreamFactory {
    /// Subscribe to events. The returned BroadcastStream will end when all
    /// broadcast senders (including this factory) are dropped.
    pub fn subscribe(&self) -> BroadcastStream<Event> {
        BroadcastStream::new(self.tx.subscribe())
    }
}

#[tokio::main]
async fn main() {
    let hub = EventsHub::new(100);

    let sender = hub.event_sender();
    let factory = hub.stream_factory();

    // Producer task: generates events every 500ms
    let producer = tokio::spawn({
        let sender = sender.clone();
        async move {
            let mut id = 0;
            loop {
                id += 1;
                sender.send(Event {
                    id,
                    data: format!("Message {}", id),
                });
                tokio::time::sleep(Duration::from_millis(500)).await;
            }
        }
    });

    // Consumer task: reads from the broadcast stream
    let consumer = tokio::spawn({
        async move {
            let stream = factory.subscribe();
            // CRITICAL: Drop the factory so it doesn't hold the sender alive
            drop(factory);

            stream
                .for_each(|result| async move {
                    match result {
                        Ok(event) => println!("[Consumer] Received: {:?}", event),
                        Err(e) => println!("[Consumer] Stream error (shutdown): {:?}", e),
                    }
                })
                .await;
            println!("[Consumer] Stream ended, task exiting");
        }
    });

    println!("Service running. Press Ctrl+C to shutdown gracefully...");

    // Wait for interrupt
    if let Err(e) = signal::ctrl_c().await {
        eprintln!("Error waiting for signal: {:?}", e);
    }
    println!("\n[Main] Interrupt received, starting shutdown...");

    // Stop the producer
    producer.abort();
    let _ = producer.await;

    // Shutdown the hub (drops mpsc and broadcast senders)
    hub.shutdown().await;

    // Wait for the consumer to finish (it should detect the closed channel)
    match timeout(Duration::from_secs(5), consumer).await {
        Ok(Ok(())) => println!("[Main] Consumer finished gracefully"),
        Ok(Err(e)) => println!("[Main] Consumer panicked: {:?}", e),
        Err(_) => println!("[Main] Consumer did not finish in time"),
    }

    println!("[Main] Shutdown complete, exiting");
}"
