        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TextObject {
    pub content: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub link: Option<serde_json::Value>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SelectObject {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub id: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub color: Option<String>,
    pub name: String,
}

// ============================================================================
// Notion Properties Macro
// Converts structs to HashMap<String, PropertyValue> using declarative macros
// Note: In a production environment, you would extract this into a 
// procedural macro crate to support #[notion_property(...)] attributes
// ============================================================================

macro_rules! notion_properties {
    // Handler for Title type (required String)
    // Wraps the string in a RichTextObject vector as required by Notion API
    (@insert $map:ident, $self:ident, $field:ident, title, $name:expr) => {
        $map.insert(
            $name.to_string(),
            PropertyValue::Title(vec![
                RichTextObject {
                    text: TextObject {
                        content: $self.$field.clone(),
                        link: None,
                    },
                    ..Default::default()
                }
            ])
        );
    };

    // Handler for Url type (Option<String>)
    // Only inserts if the field is Some(...)
    (@insert $map:ident, $self:ident, $field:ident, url, $name:expr) => {
        if let Some(ref url) = $self.$field {
            $map.insert($name.to_string(), PropertyValue::Url(url.clone()));
        }
    };

    // Handler for MultiSelect type (Option<Vec<serde_json::Value>>)
    // Maps JSON values to SelectObject structures
    (@insert $map:ident, $self:ident, $field:ident, multi_select, $name:expr) => {
        if let Some(ref items) = $self.$field {
            let selects: Vec<SelectObject> = items
                .iter()
                .map(|f| SelectObject {
                    id: None,
                    color: None,
                    name: f.to_string().trim_matches('"').to_string(),
                })
                .collect();
            $map.insert($name.to_string(), PropertyValue::MultiSelect(selects));
        }
    };

    // Entry point: generates the Into<HashMap<String, PropertyValue>> implementation
    ($struct_name:ident {
        $(
            $field:ident: $ty:ty => ($notion_type:tt, $name:expr)
        ),* $(,)?
    }) => {
        impl From<$struct_name> for HashMap<String, PropertyValue> {
            fn from(val: $struct_name) -> Self {
                let mut map = HashMap::new();
                $(
                    notion_properties!(@insert map, val, $field, $notion_type, $name);
                )*
                map
            }
        }
    };
}

// ============================================================================
// Example Usage
// ============================================================================

#[derive(Debug, Clone)]
struct MyUnit {
    pub name: String,
    pub icon_url: Option<String>,
    pub categories: Option<Vec<serde_json::Value>>,
}

// Generate the conversion implementation
// Syntax: field_name: Type => (notion_type, "Notion Property Name")
notion_properties! {
    MyUnit {
        name: String => (title, "Name"),
        icon_url: Option<String> => (url, "Icon url"),
        categories: Option<Vec<serde_json::Value>> => (multi_select, "Roles"),
    }
}

fn main() {
    let unit = MyUnit {
        name: "My Awesome Unit".to_string(),
        icon_url: Some("https://example.com/icon.png".to_string()),
        categories: Some(vec![
            serde_json::json!("Role A"),
            serde_json::json!("Role B"),
