    let properties: HashMap<String, PropertyValue> = unit.clone().into();

    println!("Converted Notion Properties:");
    println!("{}", serde_json::to_string_pretty(&properties).unwrap());

    // Verify the conversion worked correctly
    println!("\nVerification:");
    if let Some(PropertyValue::Title(title_vec)) = properties.get("Name") {
        println!("Name: {}", title_vec.first().unwrap().text.content);
    }
    if let Some(PropertyValue::Url(url)) = properties.get("Icon url") {
        println!("Icon URL: {}", url);
    }
    if let Some(PropertyValue::MultiSelect(roles)) = properties.get("Roles") {
        println!("Roles: {:?}", roles.iter().map(|r| &r.name).collect::<Vec<_>>());
    }
}"
}
